import { Question } from '../types';

export const questions: Question[] = [
  // ====== PORTUGUÊS (100 questões) ======
  { id: 'pt-q01', subjectId: 'portugues', topic: 'Interpretação de Texto', text: 'No trecho: "A violência urbana tem sido um dos maiores desafios das grandes cidades brasileiras. Não basta aumentar o efetivo policial; é preciso investir em educação e oportunidades." A ideia principal é:', options: ['A violência está diminuindo no Brasil.', 'Só a polícia resolve o problema da violência.', 'O combate à violência requer ações além do policiamento.', 'As cidades brasileiras são muito violentas.', 'A educação não tem relação com a violência.'], correct: 2, explanation: 'O texto afirma que "não basta aumentar o efetivo policial" e que é preciso investir em educação e oportunidades. A ideia central é que o combate à violência requer medidas além do policiamento.' },
  { id: 'pt-q02', subjectId: 'portugues', topic: 'Interpretação de Texto', text: '"O autor apresenta argumentos favoráveis e contrários à redução da maioridade penal, mas conclui defendendo que a medida, isoladamente, não resolve o problema." O tipo textual predominante é:', options: ['Narração', 'Descrição', 'Dissertação-argumentação', 'Injunção', 'Exposição subjetiva'], correct: 2, explanation: 'O texto apresenta argumentos e uma conclusão, o que caracteriza a dissertação-argumentação, típica de textos que defendem um ponto de vista.' },
  { id: 'pt-q03', subjectId: 'portugues', topic: 'Coesão e Coerência', text: 'Em "Maria estudou muito. _________, foi aprovada no concurso." O conectivo que NÃO pode ser usado é:', options: ['Portanto', 'Logo', 'Porém', 'Assim', 'Por conseguinte'], correct: 2, explanation: '"Porém" introduz ideia de oposição/concessão. As demais opções (portanto, logo, assim, por conseguinte) introduzem conclusão, que é o sentido correto para o contexto.' },
  { id: 'pt-q04', subjectId: 'portugues', topic: 'Classes de Palavras', text: 'Em "O jovem soldado caminhava lentamente pela rua deserta", a classe gramatical da palavra "lentamente" é:', options: ['Adjetivo', 'Advérbio', 'Substantivo', 'Pronome', 'Preposição'], correct: 1, explanation: '"Lentamente" é advérbio de modo, pois modifica o verbo "caminhava", indicando como a ação foi realizada. Advérbios terminados em -mente são de modo.' },
  { id: 'pt-q05', subjectId: 'portugues', topic: 'Concordância Verbal e Nominal', text: 'Assinale a alternativa com erro de concordância verbal:', options: ['Faz anos que não o vejo.', 'Existem muitos candidatos inscritos.', 'Houveram muitas reclamações.', 'Há muitos candidatos na sala.', 'Deve haver problemas na inscrição.'], correct: 2, explanation: '"Houver" é impessoal e não vai para o plural. O correto é "Houve muitas reclamações". O verbo haver no sentido de existir é impessoal.' },
  { id: 'pt-q06', subjectId: 'portugues', topic: 'Regência Verbal e Nominal', text: 'Complete: "O candidato aspirava _______ vaga no concurso." A lacuna deve ser preenchida com:', options: ['a', 'à', 'àquela', 'a essa', 'àquelas'], correct: 1, explanation: 'Quando "aspirar" significa "desejar, almejar", exige a preposição "a". Com "vaga" (palavra feminina), ocorre crase: "aspirava à vaga".' },
  { id: 'pt-q07', subjectId: 'portugues', topic: 'Crase', text: 'Assinale a alternativa em que o uso da crase está INCORRETO:', options: ['Refiro-me àquela proposta.', 'Fui à Curitiba.', 'Ele chegou à conclusão certa.', 'Obedeça às normas.', 'Paguei à funcionária.'], correct: 1, explanation: 'Antes de nomes de cidades, NÃO se usa crase, a menos que venha modificado. O correto é "Fui a Curitiba".' },
  { id: 'pt-q08', subjectId: 'portugues', topic: 'Pontuação', text: 'Em "O soldado ferido que estava em estado grave foi socorrido de helicóptero", a oração "que estava em estado grave" é:', options: ['Explicativa — deve ser isolada por vírgulas.', 'Restritiva — não deve ser isolada por vírgulas.', 'Apositiva — deve estar entre vírgulas.', 'Coordenada — separada por ponto e vírgula.', 'Absoluta — termina com ponto.'], correct: 1, explanation: 'A oração "que estava em estado grave" restringe qual soldado (não qualquer soldado, mas o ferido em estado grave). Orações restritivas não são isoladas por vírgulas.' },
  { id: 'pt-q09', subjectId: 'portugues', topic: 'Figuras de Linguagem', text: 'Em "Ele esperou uma eternidade na fila", a figura de linguagem predominante é:', options: ['Metáfora', 'Hipérbole', 'Metonímia', 'Prosopopeia', 'Ironia'], correct: 1, explanation: 'Hipérbole é o exagero intencional. "Esperou uma eternidade" não significa eternidade literal, mas uma espera muito longa.' },
  { id: 'pt-q10', subjectId: 'portugues', topic: 'Ortografia e Acentuação', text: 'Assinale a palavra acentuada INCORRETAMENTE:', options: ['Item', 'Ítens', 'Cadáver', 'Útil', 'Caráter'], correct: 1, explanation: 'A forma correta é "itens", sem acento. "Cadáver", "útil" e "caráter" recebem acento por regras de acentuação das paroxítonas. "Item" também não recebe acento.' },
  { id: 'pt-q11', subjectId: 'portugues', topic: 'Concordância Verbal e Nominal', text: 'Assinale a alternativa INCORRETA quanto à concordância nominal:', options: ['As informações seguem anexas.', 'É necessária muita atenção.', 'Os candidatos estavam bastante cansados.', 'Bastante alunos faltaram.', 'A documentação está anexa.'], correct: 3, explanation: 'O correto é "bastantes alunos faltaram", pois "bastante", quando equivale a "muitos", é adjetivo e concorda com o substantivo. Nas demais alternativas, a concordância está adequada.' },
  { id: 'pt-q12', subjectId: 'portugues', topic: 'Interpretação de Texto', text: '"Embora a tecnologia tenha facilitado a vida das pessoas, muitos ainda resistem às mudanças e preferem métodos tradicionais." A relação de sentido estabelecida por "embora" é de:', options: ['Causa', 'Consequência', 'Concessão', 'Adição', 'Explicação'], correct: 2, explanation: '"Embora" é uma conjunção concessiva, que indica uma ideia contrária à principal, mas que não impede sua realização.' },
  { id: 'pt-q13', subjectId: 'portugues', topic: 'Coesão e Coerência', text: '"João comprou um carro novo. _________ já foi ao mercado abastecê-lo." Para manter a coesão, o pronome adequado é:', options: ['Ele', 'O qual', 'Lhe', 'Cujo', 'Que'], correct: 0, explanation: '"Ele" retoma "João", funcionando como elemento coesivo referencial. O pronome pessoal "ele" é usado como sujeito da segunda oração.' },
  { id: 'pt-q14', subjectId: 'portugues', topic: 'Classes de Palavras', text: 'Em "Precisamos DE mais informações SOBRE o caso", as palavras destacadas são, respectivamente:', options: ['Preposição e conjunção', 'Preposição e preposição', 'Conjunção e advérbio', 'Advérbio e preposição', 'Pronome e conjunção'], correct: 1, explanation: '"De" e "sobre" são preposições. "Precisar de" exige preposição "de". "Informações sobre" usa "sobre" como preposição indicando assunto.' },
  { id: 'pt-q15', subjectId: 'portugues', topic: 'Ortografia e Acentuação', text: 'Assinale a palavra escrita CORRETAMENTE:', options: ['Previlégio', 'Estupidez', 'Ecesão', 'Inxectável', 'Descenção'], correct: 1, explanation: '"Estupidez" está correta. As formas corretas seriam: privilégio, exceção, injetável, descensão (ou decência, conforme o sentido).' },
  { id: 'pt-q16', subjectId: 'portugues', topic: 'Regência Verbal e Nominal', text: 'Complete: "Ela é admirada _______ todos e está ciente _______ suas obrigações."', options: ['por — de', 'com — com', 'de — por', 'a — para', 'por — com'], correct: 0, explanation: '"Admirada por todos" (admira-se alguém por alguém). "Ciente de suas obrigações" (ser ciente de algo).' },
  { id: 'pt-q17', subjectId: 'portugues', topic: 'Figuras de Linguagem', text: '"O tempo voa." A figura presente é:', options: ['Metonímia', 'Hipérbole', 'Metáfora', 'Catacrese', 'Antítese'], correct: 2, explanation: 'Metáfora é a comparação implícita. "O tempo voa" compara o tempo a algo que voa (rápido), sem usar "como" ou "parece".' },
  { id: 'pt-q18', subjectId: 'portugues', topic: 'Concordância Verbal e Nominal', text: '"Mais de um candidato _______ ao local da prova com antecedência." Complete corretamente:', options: ['chegaram', 'chegavam', 'chegou', 'chegariam', 'chegarão'], correct: 2, explanation: 'Com a expressão "mais de um", o verbo fica, em regra, no singular: "Mais de um candidato chegou".' },
  { id: 'pt-q19', subjectId: 'portugues', topic: 'Pontuação', text: 'Em "Senhor presidente é uma honra estar aqui", a pontuação correta é:', options: ['Senhor presidente, é uma honra estar aqui.', 'Senhor, presidente, é uma honra estar aqui.', 'Senhor presidente é uma honra, estar aqui.', 'Senhor presidente: é uma honra estar aqui.', 'Senhor presidente; é uma honra estar aqui.'], correct: 0, explanation: '"Senhor presidente" é um vocativo (chamamento), que deve ser isolado por vírgula: "Senhor presidente, é uma honra estar aqui."' },
  { id: 'pt-q20', subjectId: 'portugues', topic: 'Interpretação de Texto', text: '"O texto diz que a implementação da política pública foi exitosa, mas ressalva que os resultados de longo prazo ainda são incertos." Isso significa que:', options: ['A política fracassou completamente.', 'A política teve sucesso inicial, mas o futuro é incerto.', 'A política não teve nenhum resultado.', 'Os resultados de longo prazo já são conhecidos.', 'A política foi exitosa em todas as áreas.'], correct: 1, explanation: 'O texto usa "mas" para contrastar duas informações: sucesso inicial ("exitosa") e incerteza futura ("resultados de longo prazo ainda são incertos").' },


  { id: 'pt-q21', subjectId: 'portugues', topic: 'Interpretação de Texto', text: 'Leia: "A prevenção da violência depende de políticas públicas integradas, capazes de unir segurança, educação e assistência social." A ideia central do trecho é:', options: ['A violência deve ser tratada apenas pela polícia.', 'A educação não interfere na segurança pública.', 'A prevenção da violência exige ações integradas.', 'A assistência social substitui o trabalho policial.', 'A segurança pública é tema exclusivamente municipal.'], correct: 2, explanation: 'O trecho afirma que a prevenção depende da integração entre segurança, educação e assistência social. Portanto, a ideia central é a necessidade de ações integradas.' },
  { id: 'pt-q22', subjectId: 'portugues', topic: 'Coesão e Coerência', text: 'Em "O candidato estudou com disciplina; por isso, obteve bom resultado", a expressão "por isso" estabelece relação de:', options: ['Oposição', 'Conclusão', 'Alternância', 'Concessão', 'Comparação'], correct: 1, explanation: '"Por isso" introduz uma consequência ou conclusão decorrente da ideia anterior.' },
  { id: 'pt-q23', subjectId: 'portugues', topic: 'Pontuação', text: 'Assinale a alternativa em que a vírgula isola corretamente o vocativo:', options: ['Vamos estudar, hoje, matemática.', 'Candidato, mantenha a calma.', 'O aluno, chegou cedo.', 'A prova, será objetiva.', 'Todos, os candidatos compareceram.'], correct: 1, explanation: 'Vocativo é o termo usado para chamar o interlocutor. Em "Candidato, mantenha a calma", "Candidato" é vocativo e deve ser isolado por vírgula.' },
  { id: 'pt-q24', subjectId: 'portugues', topic: 'Crase', text: 'Assinale a alternativa em que o uso da crase está correto:', options: ['Cheguei à tempo.', 'Voltei à pé.', 'Dirigi-me à sala de aula.', 'Assisti à filmes antigos.', 'Começou à chover.'], correct: 2, explanation: 'Ocorre crase em "à sala de aula", pois há a preposição "a" exigida pelo verbo e o artigo feminino "a" antes de "sala".' },
  { id: 'pt-q25', subjectId: 'portugues', topic: 'Concordância Verbal e Nominal', text: 'Assinale a alternativa correta:', options: ['Fazem dois anos que ele estuda.', 'Houveram muitos inscritos.', 'Existem bons candidatos.', 'Deve existir problemas.', 'Haviam muitas vagas abertas.'], correct: 2, explanation: '"Existem bons candidatos" está correta, pois o verbo existir concorda com o sujeito plural. O verbo haver, no sentido de existir, é impessoal e fica no singular.' },
  { id: 'pt-q26', subjectId: 'portugues', topic: 'Regência Verbal e Nominal', text: 'Assinale a alternativa correta quanto à regência:', options: ['O candidato obedeceu o edital.', 'O candidato assistiu o filme.', 'O candidato visava ao cargo público.', 'O candidato preferiu estudar do que sair.', 'O candidato chegou no quartel às oito horas.'], correct: 2, explanation: 'No sentido de desejar, "visar" exige preposição "a": "visava ao cargo público".' },
  { id: 'pt-q27', subjectId: 'portugues', topic: 'Classes de Palavras', text: 'Na frase "A preparação diária melhora muito o desempenho", a palavra "diária" é:', options: ['Substantivo', 'Adjetivo', 'Verbo', 'Conjunção', 'Preposição'], correct: 1, explanation: '"Diária" caracteriza o substantivo "preparação", portanto é adjetivo.' },
  { id: 'pt-q28', subjectId: 'portugues', topic: 'Ortografia e Acentuação', text: 'Assinale a alternativa em que todas as palavras estão escritas corretamente:', options: ['Exceção, disciplina, privilégio', 'Ecessão, disciplina, previlégio', 'Exceção, diciplina, privilégio', 'Excessão, disciplina, previlégio', 'Exceção, disciplina, previlégio'], correct: 0, explanation: 'As grafias corretas são: exceção, disciplina e privilégio.' },
  { id: 'pt-q29', subjectId: 'portugues', topic: 'Figuras de Linguagem', text: 'Em "A esperança acendeu uma luz no coração dos moradores", há predominância de:', options: ['Ironia', 'Metáfora', 'Pleonasmo vicioso', 'Eufemismo', 'Onomatopeia'], correct: 1, explanation: 'A expressão usa "luz" em sentido figurado para representar ânimo ou expectativa positiva, caracterizando metáfora.' },
  { id: 'pt-q30', subjectId: 'portugues', topic: 'Interpretação de Texto', text: 'Quando um texto apresenta dados, argumentos e conclusão para defender uma tese, sua finalidade predominante é:', options: ['Narrar acontecimentos fictícios', 'Descrever personagens', 'Convencer ou defender um ponto de vista', 'Dar instruções de uso', 'Expressar sons da natureza'], correct: 2, explanation: 'Textos argumentativos organizam dados e argumentos para sustentar uma tese e convencer o leitor.' },


  { id: 'pt-q31', subjectId: 'portugues', topic: 'Interpretação de Texto', text: 'Leia: "A presença policial nas ruas contribui para a sensação de segurança, mas não substitui políticas sociais de longo prazo." A ideia central do trecho é:', options: ['A presença policial é inútil.', 'Políticas sociais eliminam a necessidade de polícia.', 'Segurança pública envolve ação policial e políticas sociais.', 'A sensação de segurança não tem relação com policiamento.', 'Apenas políticas de longo prazo resolvem ocorrências imediatas.'], correct: 2, explanation: 'O trecho afirma que a presença policial contribui, mas não substitui políticas sociais. A ideia central é a necessidade de combinação de medidas.' },
  { id: 'pt-q32', subjectId: 'portugues', topic: 'Coesão e Coerência', text: 'Em "O treinamento foi intenso; entretanto, os candidatos permaneceram motivados", o conectivo "entretanto" indica:', options: ['Conclusão', 'Oposição', 'Causa', 'Explicação', 'Finalidade'], correct: 1, explanation: '"Entretanto" estabelece oposição/contraste entre a intensidade do treinamento e a motivação mantida.' },
  { id: 'pt-q33', subjectId: 'portugues', topic: 'Classes de Palavras', text: 'Na frase "Os candidatos chegaram cedo ao local da prova", a palavra "cedo" exerce função de:', options: ['Substantivo', 'Adjetivo', 'Advérbio', 'Preposição', 'Conjunção'], correct: 2, explanation: '"Cedo" modifica o verbo "chegaram", indicando circunstância de tempo. Portanto, é advérbio.' },
  { id: 'pt-q34', subjectId: 'portugues', topic: 'Concordância Verbal e Nominal', text: 'Assinale a alternativa correta quanto à concordância verbal:', options: ['Fazem muitos anos que estudo.', 'Houveram alterações no edital.', 'Existe muitas dúvidas.', 'Faz dois meses que treino.', 'Deve haverem candidatos atrasados.'], correct: 3, explanation: 'O verbo "fazer" indicando tempo decorrido é impessoal e fica no singular: "Faz dois meses".' },
  { id: 'pt-q35', subjectId: 'portugues', topic: 'Regência Verbal e Nominal', text: 'Assinale a alternativa correta segundo a norma-padrão:', options: ['Obedeceu o regulamento.', 'Assistiu ao treinamento.', 'Preferiu dormir do que estudar.', 'Chegou no quartel cedo.', 'Aspirava o cargo público.'], correct: 1, explanation: 'No sentido de presenciar/ver, "assistir" exige preposição "a": "assistiu ao treinamento".' },
  { id: 'pt-q36', subjectId: 'portugues', topic: 'Crase', text: 'Assinale a alternativa em que NÃO deve ocorrer crase:', options: ['Dirigiu-se à autoridade.', 'Entregou o documento à servidora.', 'Começou a estudar cedo.', 'Referiu-se à prova.', 'Foi à sala indicada.'], correct: 2, explanation: 'Não ocorre crase antes de verbo. Em "começou a estudar", o "a" é apenas preposição antes do verbo "estudar".' },
  { id: 'pt-q37', subjectId: 'portugues', topic: 'Pontuação', text: 'Assinale a frase em que a vírgula foi usada incorretamente:', options: ['Durante a manhã, os candidatos revisaram o conteúdo.', 'O professor, explicou a matéria com calma.', 'Candidato, leia o enunciado com atenção.', 'A prova, segundo o edital, será objetiva.', 'João, o mais dedicado da turma, chegou cedo.'], correct: 1, explanation: 'Não se separa sujeito e verbo por vírgula. O correto é: "O professor explicou a matéria com calma".' },
  { id: 'pt-q38', subjectId: 'portugues', topic: 'Figuras de Linguagem', text: 'Em "Ele é uma muralha diante das dificuldades", ocorre:', options: ['Comparação', 'Metáfora', 'Eufemismo', 'Ironia', 'Onomatopeia'], correct: 1, explanation: 'Há metáfora, pois a pessoa é associada a uma muralha, indicando força/resistência, sem uso de "como".' },
  { id: 'pt-q39', subjectId: 'portugues', topic: 'Ortografia e Acentuação', text: 'Assinale a alternativa em que todas as palavras estão corretas:', options: ['Excessão, análise, rúbrica', 'Exceção, análise, rubrica', 'Eceção, analise, rúbrica', 'Exceção, análize, rubrica', 'Excessão, análise, rubrica'], correct: 1, explanation: 'As formas corretas são: exceção, análise e rubrica. "Rubrica" é paroxítona sem acento.' },
  { id: 'pt-q40', subjectId: 'portugues', topic: 'Tipos Textuais', text: 'Um texto que apresenta instruções passo a passo para realizar um procedimento tem predominância:', options: ['Narrativa', 'Descritiva', 'Injuntiva', 'Dissertativa argumentativa', 'Poética'], correct: 2, explanation: 'Textos injuntivos orientam o leitor, apresentam comandos, instruções ou procedimentos.' },

  { id: 'pt-q41', subjectId: 'portugues', topic: 'Interpretação de Texto', text: 'Leia: "A disciplina não elimina a liberdade; ela organiza o caminho para que a liberdade não vire desordem." A ideia central do trecho é:', options: ['A disciplina é sempre oposta à liberdade', 'A liberdade deve existir sem qualquer regra', 'A disciplina pode orientar o uso responsável da liberdade', 'A desordem é necessária para a vida social', 'A liberdade não possui relação com comportamento'], correct: 2, explanation: 'O trecho afirma que a disciplina organiza o caminho da liberdade. Portanto, a ideia central é que disciplina e liberdade podem se complementar.' },
  { id: 'pt-q42', subjectId: 'portugues', topic: 'Interpretação de Texto', text: 'Em um texto, uma informação implícita é aquela que:', options: ['Aparece escrita exatamente no enunciado', 'Precisa ser inferida a partir das pistas do texto', 'Contradiz obrigatoriamente o título', 'Não pode ser compreendida pelo leitor', 'Está sempre destacada em letras maiúsculas'], correct: 1, explanation: 'Informação implícita não está dita diretamente. O leitor precisa inferir com base nas pistas do texto.' },
  { id: 'pt-q43', subjectId: 'portugues', topic: 'Coesão e Coerência', text: 'Em "O candidato estudou bastante; portanto, aumentou suas chances de aprovação", o conectivo "portanto" indica:', options: ['Oposição', 'Conclusão', 'Dúvida', 'Condição', 'Comparação'], correct: 1, explanation: '"Portanto" introduz uma conclusão decorrente da ideia anterior.' },
  { id: 'pt-q44', subjectId: 'portugues', topic: 'Coesão e Coerência', text: 'Assinale a frase que apresenta problema de coerência:', options: ['Choveu muito, por isso a rua ficou alagada.', 'Ele treinou todos os dias e melhorou seu desempenho.', 'O candidato estudou durante meses; por isso, esqueceu tudo no mesmo instante.', 'A viatura estava sem combustível, então precisou abastecer.', 'Ela leu o edital para conhecer as regras.'], correct: 2, explanation: 'A alternativa apresenta relação incoerente entre causa e consequência: estudar durante meses não leva, naturalmente, a esquecer tudo no mesmo instante.' },
  { id: 'pt-q45', subjectId: 'portugues', topic: 'Classes de Palavras', text: 'Na frase "A prova difícil exigiu muita atenção", a palavra "difícil" é:', options: ['Substantivo', 'Adjetivo', 'Advérbio', 'Conjunção', 'Preposição'], correct: 1, explanation: '"Difícil" caracteriza o substantivo "prova". Portanto, é adjetivo.' },
  { id: 'pt-q46', subjectId: 'portugues', topic: 'Classes de Palavras', text: 'Na frase "Os alunos estudaram ontem", a palavra "ontem" indica circunstância de tempo e é classificada como:', options: ['Pronome', 'Advérbio', 'Artigo', 'Numeral', 'Substantivo'], correct: 1, explanation: '"Ontem" modifica o verbo "estudaram", indicando tempo. É advérbio.' },
  { id: 'pt-q47', subjectId: 'portugues', topic: 'Concordância Verbal e Nominal', text: 'Assinale a alternativa correta quanto à concordância verbal:', options: ['Haviam muitos candidatos na sala.', 'Fazem três dias que estudo.', 'Existem muitas dúvidas sobre o edital.', 'Existe muitas dúvidas sobre o edital.', 'Fazem dois meses que treino.'], correct: 2, explanation: 'O verbo "existir" concorda com o sujeito. Como "muitas dúvidas" está no plural, o correto é: "Existem muitas dúvidas".' },
  { id: 'pt-q48', subjectId: 'portugues', topic: 'Concordância Verbal e Nominal', text: 'Assinale a alternativa correta:', options: ['As questões estava difíceis.', 'Os candidato chegaram cedo.', 'A prova e o gabarito foram publicados.', 'Houveram problemas no sistema.', 'Fazem anos que ele treina.'], correct: 2, explanation: 'Sujeito composto "A prova e o gabarito" exige verbo no plural: "foram publicados".' },
  { id: 'pt-q49', subjectId: 'portugues', topic: 'Regência Verbal e Nominal', text: 'Quanto à regência do verbo "aspirar" no sentido de desejar, assinale a alternativa correta:', options: ['Aspirou ao cargo público.', 'Aspirou o cargo público.', 'Aspirou no cargo público.', 'Aspirou pelo cargo público.', 'Aspirou com o cargo público.'], correct: 0, explanation: 'No sentido de desejar ou almejar, o verbo "aspirar" exige preposição "a": "aspirou ao cargo público".' },
  { id: 'pt-q50', subjectId: 'portugues', topic: 'Regência Verbal e Nominal', text: 'Na norma-padrão, o verbo "preferir" deve ser usado corretamente em:', options: ['Prefiro estudar do que sair.', 'Prefiro mais estudar que sair.', 'Prefiro estudar a sair.', 'Prefiro antes estudar do que sair.', 'Prefiro estudar do que ficar em casa.'], correct: 2, explanation: 'Na norma-padrão, a construção correta é "preferir uma coisa a outra": "Prefiro estudar a sair".' },
  { id: 'pt-q51', subjectId: 'portugues', topic: 'Crase', text: 'Assinale a alternativa em que o uso da crase está correto:', options: ['Começou à estudar cedo.', 'Entregou o documento à coordenadora.', 'Chegou à pé.', 'Referiu-se à todos os candidatos.', 'A prova será à distância no sentido genérico sem artigo.'], correct: 1, explanation: 'Ocorre crase em "à coordenadora" porque há preposição "a" mais artigo feminino "a".' },
  { id: 'pt-q52', subjectId: 'portugues', topic: 'Crase', text: 'Não ocorre crase em:', options: ['Referiu-se à lei.', 'Foi à escola.', 'Dirigiu-se à sala.', 'Começou a correr.', 'Entregou a ficha à servidora.'], correct: 3, explanation: 'Não ocorre crase antes de verbo. Em "começou a correr", o "a" é apenas preposição.' },
  { id: 'pt-q53', subjectId: 'portugues', topic: 'Pontuação', text: 'Assinale a alternativa em que a vírgula está corretamente empregada:', options: ['O candidato, chegou cedo.', 'Durante a prova, mantenha a calma.', 'A professora explicou, a matéria.', 'Os alunos estudaram, bastante.', 'A prova objetiva, será domingo.'], correct: 1, explanation: 'A vírgula após adjunto adverbial deslocado é adequada: "Durante a prova, mantenha a calma".' },
  { id: 'pt-q54', subjectId: 'portugues', topic: 'Pontuação', text: 'Em "Soldado, mantenha a postura", a vírgula foi usada para isolar:', options: ['Aposto', 'Vocativo', 'Objeto direto', 'Predicativo', 'Adjunto adnominal'], correct: 1, explanation: '"Soldado" é chamamento direto ao interlocutor. Portanto, é vocativo e deve ser isolado por vírgula.' },
  { id: 'pt-q55', subjectId: 'portugues', topic: 'Figuras de Linguagem', text: 'Em "O vento sussurrava entre as árvores", ocorre:', options: ['Hipérbole', 'Prosopopeia', 'Metonímia', 'Ironia', 'Pleonasmo'], correct: 1, explanation: 'Prosopopeia ou personificação ocorre quando se atribui ação humana a ser inanimado ou irracional. O vento "sussurrar" é personificação.' },
  { id: 'pt-q56', subjectId: 'portugues', topic: 'Figuras de Linguagem', text: 'Em "Li Machado de Assis durante as férias", ocorre:', options: ['Metonímia', 'Hipérbole', 'Eufemismo', 'Comparação', 'Antítese'], correct: 0, explanation: 'Há metonímia: usa-se o nome do autor no lugar da obra. A pessoa leu obras de Machado de Assis.' },
  { id: 'pt-q57', subjectId: 'portugues', topic: 'Ortografia e Acentuação', text: 'Assinale a alternativa em que todas as palavras estão corretamente grafadas:', options: ['Privilégio, exceção, disciplina', 'Previlegio, excessão, disciplina', 'Privilégio, eceção, diciplina', 'Previlegio, exceção, discíplina', 'Privilégio, excessão, diciplina'], correct: 0, explanation: 'As formas corretas são: privilégio, exceção e disciplina.' },
  { id: 'pt-q58', subjectId: 'portugues', topic: 'Ortografia e Acentuação', text: 'Assinale a alternativa correta quanto à acentuação:', options: ['Heroi, ideia, juri', 'Herói, ideia, júri', 'Heroí, idéia, juri', 'Heroi, idéia, júri', 'Herói, idéia, juri'], correct: 1, explanation: '"Herói" e "júri" são acentuadas. "Ideia" perdeu o acento pelo Acordo Ortográfico.' },
  { id: 'pt-q59', subjectId: 'portugues', topic: 'Tipos Textuais', text: 'Um texto que defende uma opinião com argumentos apresenta predominância:', options: ['Narrativa', 'Descritiva', 'Dissertativa argumentativa', 'Injuntiva', 'Expositiva sem opinião'], correct: 2, explanation: 'O texto dissertativo-argumentativo apresenta tese/opinião e argumentos para defendê-la.' },
  { id: 'pt-q60', subjectId: 'portugues', topic: 'Tipos Textuais', text: 'Um boletim de ocorrência que relata uma sequência de fatos possui predominância:', options: ['Narrativa', 'Descritiva', 'Injuntiva', 'Poética', 'Publicitária'], correct: 0, explanation: 'A narração apresenta sequência de fatos, geralmente com personagens, tempo e espaço.' },

  { id: 'pt-q61', subjectId: 'portugues', topic: 'Interpretação de Texto', text: 'Leia: "O bom servidor público não atua para aparecer, mas para fazer o serviço aparecer pelo resultado." O trecho valoriza principalmente:', options: ['Vaidade pessoal', 'Eficiência e compromisso com o resultado', 'Desinteresse pelo serviço público', 'Competição entre servidores', 'Ausência de responsabilidade'], correct: 1, explanation: 'O trecho valoriza o resultado do serviço e o compromisso do servidor, não a autopromoção.' },
  { id: 'pt-q62', subjectId: 'portugues', topic: 'Interpretação de Texto', text: 'Em uma questão de interpretação, a alternativa que extrapola o texto é aquela que:', options: ['Repete uma informação explícita', 'Resume corretamente a ideia central', 'Acrescenta uma conclusão não sustentada pelo texto', 'Identifica o tema principal', 'Reconhece uma informação implícita com base em pistas'], correct: 2, explanation: 'Extrapolar é ir além do que o texto permite concluir. A alternativa pode até parecer lógica, mas não tem apoio suficiente no texto.' },
  { id: 'pt-q63', subjectId: 'portugues', topic: 'Coesão e Coerência', text: 'Em "Embora estivesse cansado, o candidato continuou estudando", a palavra "embora" indica:', options: ['Causa', 'Concessão', 'Conclusão', 'Finalidade', 'Adição'], correct: 1, explanation: '"Embora" introduz ideia de concessão: mesmo cansado, ele continuou estudando.' },
  { id: 'pt-q64', subjectId: 'portugues', topic: 'Coesão e Coerência', text: 'Assinale a alternativa em que o conectivo estabelece ideia de causa:', options: ['Estudou muito, portanto foi bem.', 'Não saiu porque estava chovendo.', 'Treinou, mas não descansou.', 'Leu o edital e fez anotações.', 'Embora cansado, revisou a matéria.'], correct: 1, explanation: '"Porque" indica causa: o motivo de não sair foi a chuva.' },
  { id: 'pt-q65', subjectId: 'portugues', topic: 'Classes de Palavras', text: 'Na frase "Aquele candidato revisou todo o conteúdo", a palavra "aquele" é:', options: ['Artigo', 'Pronome demonstrativo', 'Advérbio', 'Conjunção', 'Preposição'], correct: 1, explanation: '"Aquele" indica posição/distanciamento em relação ao substantivo "candidato"; é pronome demonstrativo.' },
  { id: 'pt-q66', subjectId: 'portugues', topic: 'Classes de Palavras', text: 'Na frase "Estudar exige paciência", a palavra "estudar" funciona como:', options: ['Substantivo', 'Advérbio de tempo', 'Preposição', 'Conjunção adversativa', 'Adjetivo'], correct: 0, explanation: 'O verbo no infinitivo pode ter valor substantivo. Em "Estudar exige paciência", "estudar" é o sujeito da oração.' },
  { id: 'pt-q67', subjectId: 'portugues', topic: 'Concordância Verbal e Nominal', text: 'Assinale a alternativa correta quanto à concordância nominal:', options: ['É proibida a entrada de candidatos atrasados.', 'É proibido a entrada de candidatos atrasados.', 'São proibido entradas atrasadas.', 'Foi proibido as entradas atrasadas.', 'Entrada atrasada são proibidas.'], correct: 0, explanation: 'Com artigo antes do substantivo feminino, o adjetivo concorda com ele: "É proibida a entrada". Sem artigo, seria comum a forma invariável: "É proibido entrada".' },
  { id: 'pt-q68', subjectId: 'portugues', topic: 'Concordância Verbal e Nominal', text: 'Assinale a alternativa em que a concordância nominal está correta:', options: ['As provas seguem anexos.', 'Seguem anexas as declarações.', 'É necessário muita atenção.', 'As candidata estavam preparados.', 'Meio cansadas, os soldados chegaram.'], correct: 1, explanation: '"Anexas" concorda com "declarações", que está no feminino plural.' },
  { id: 'pt-q69', subjectId: 'portugues', topic: 'Regência Verbal e Nominal', text: 'No sentido de desejar ou almejar, assinale a alternativa correta:', options: ['Visou o cargo público.', 'Visou ao cargo público.', 'Visou no cargo público.', 'Visou pelo cargo público.', 'Visou com o cargo público.'], correct: 1, explanation: 'No sentido de desejar ou almejar, o verbo "visar" exige preposição "a": "visou ao cargo público".' },
  { id: 'pt-q70', subjectId: 'portugues', topic: 'Regência Verbal e Nominal', text: 'Quanto à regência do verbo "lembrar-se", assinale a alternativa correta:', options: ['Ele se lembrou do horário da prova.', 'Ele se lembrou o horário da prova.', 'Ele lembrou-se o horário da prova.', 'Ele foi lembrado do horário pela prova.', 'Ele se lembrou com o horário da prova.'], correct: 0, explanation: 'O verbo pronominal "lembrar-se" rege preposição "de": quem se lembra, lembra-se de algo. Portanto, o correto é: "Ele se lembrou do horário da prova".' },
  { id: 'pt-q71', subjectId: 'portugues', topic: 'Crase', text: 'Assinale a alternativa em que o uso da crase está correto:', options: ['Ficou frente à frente com o avaliador.', 'Estudou de segunda à sexta.', 'Foi àquela sala indicada no edital.', 'Começou à revisar o conteúdo.', 'Entregou o recurso à prazo.'], correct: 2, explanation: 'Ocorre crase em "àquela" quando há preposição "a" somada ao pronome demonstrativo "aquela".' },
  { id: 'pt-q72', subjectId: 'portugues', topic: 'Crase', text: 'Na expressão "ensino a distância", usada de forma genérica, o uso da crase é:', options: ['Obrigatório', 'Sempre facultativo', 'Não indicado nesse uso genérico', 'Obrigatório antes de verbo', 'Obrigatório antes de palavra masculina'], correct: 2, explanation: 'Em uso genérico, "a distância" costuma aparecer sem crase. Com determinação, pode haver crase: "à distância de dois metros".' },
  { id: 'pt-q73', subjectId: 'portugues', topic: 'Pontuação', text: 'Assinale a frase em que o aposto está corretamente isolado por vírgulas:', options: ['A Vunesp banca organizadora aplicará a prova.', 'A Vunesp, banca organizadora, aplicará a prova.', 'A, Vunesp banca organizadora, aplicará a prova.', 'A Vunesp banca, organizadora aplicará, a prova.', 'A Vunesp aplicará, a prova banca organizadora.'], correct: 1, explanation: '"Banca organizadora" explica "A Vunesp" e funciona como aposto explicativo, por isso fica isolado por vírgulas.' },
  { id: 'pt-q74', subjectId: 'portugues', topic: 'Pontuação', text: 'Assinale a alternativa em que NÃO se deve separar sujeito e verbo por vírgula:', options: ['Os candidatos atentos, leram o edital.', 'Durante a manhã, os candidatos estudaram.', 'O edital, segundo a banca, foi publicado.', 'Soldado, mantenha a calma.', 'João, aluno dedicado, revisou a matéria.'], correct: 0, explanation: 'Não se separa sujeito e verbo por vírgula. O correto é: "Os candidatos atentos leram o edital".' },
  { id: 'pt-q75', subjectId: 'portugues', topic: 'Figuras de Linguagem', text: 'Em "A aprovação é uma escada construída degrau por degrau", há:', options: ['Metáfora', 'Onomatopeia', 'Ironia', 'Eufemismo', 'Pleonasmo vicioso'], correct: 0, explanation: 'Há metáfora, pois a aprovação é associada a uma escada, sem uso de "como".' },
  { id: 'pt-q76', subjectId: 'portugues', topic: 'Figuras de Linguagem', text: 'Em "Ele faltou com a verdade", ocorre principalmente:', options: ['Eufemismo', 'Hipérbole', 'Metonímia', 'Prosopopeia', 'Comparação'], correct: 0, explanation: 'Eufemismo suaviza uma ideia desagradável. "Faltou com a verdade" suaviza "mentiu".' },
  { id: 'pt-q77', subjectId: 'portugues', topic: 'Ortografia e Acentuação', text: 'Assinale a alternativa em que todas as palavras estão corretas:', options: ['Beneficente, consciência, exceção', 'Beneficiente, conciência, exceção', 'Beneficente, consciência, excessão', 'Beneficiente, consciência, eceção', 'Beneficente, conciência, excessão'], correct: 0, explanation: 'As formas corretas são: beneficente, consciência e exceção.' },
  { id: 'pt-q78', subjectId: 'portugues', topic: 'Ortografia e Acentuação', text: 'Assinale a alternativa correta:', options: ['Pôde indica passado; pode indica presente.', 'Pode e pôde sempre têm o mesmo tempo verbal.', 'Ideia deve ser escrita idéia pela regra atual.', 'Jiboia deve ser escrita jibóia pela regra atual.', 'Assembleia mantém acento obrigatório.'], correct: 0, explanation: '"Pôde" é passado do verbo poder; "pode" é presente. Ideia, jiboia e assembleia perderam o acento pelo Acordo Ortográfico.' },
  { id: 'pt-q79', subjectId: 'portugues', topic: 'Tipos Textuais', text: 'Um texto que explica um assunto de forma objetiva, sem defender necessariamente uma opinião, é predominantemente:', options: ['Narrativo', 'Descritivo', 'Expositivo', 'Injuntivo', 'Poético'], correct: 2, explanation: 'O texto expositivo tem finalidade de explicar ou informar sobre determinado assunto.' },
  { id: 'pt-q80', subjectId: 'portugues', topic: 'Tipos Textuais', text: 'Um manual de procedimentos para atendimento de ocorrência possui predominância:', options: ['Injuntiva', 'Narrativa literária', 'Poética', 'Descritiva subjetiva', 'Argumentativa informal'], correct: 0, explanation: 'Textos injuntivos orientam ações, dão instruções, ordens, comandos ou procedimentos.' },

  { id: 'pt-q81', subjectId: 'portugues', topic: 'Interpretação de Texto', text: 'Leia: "Nem toda resposta rápida é uma boa resposta; às vezes, pensar evita uma falha maior." A ideia central do trecho é:', options: ['A rapidez sempre garante acerto.', 'Pensar antes de agir pode evitar erros.', 'Toda demora é sinal de incompetência.', 'Responder rápido elimina qualquer risco.', 'A reflexão é inútil em decisões importantes.'], correct: 1, explanation: 'O trecho afirma que pensar pode evitar falhas. A ideia central é a valorização da reflexão antes da ação.' },
  { id: 'pt-q82', subjectId: 'portugues', topic: 'Interpretação de Texto', text: 'Quando uma alternativa apenas repete palavras do texto, mas muda o sentido original, ela representa uma armadilha de:', options: ['Cópia fiel do conteúdo', 'Falsa equivalência interpretativa', 'Pontuação obrigatória', 'Concordância nominal', 'Ortografia oficial'], correct: 1, explanation: 'A banca pode usar palavras do texto em alternativa que distorce o sentido. Isso é uma falsa equivalência interpretativa.' },
  { id: 'pt-q83', subjectId: 'portugues', topic: 'Coesão e Coerência', text: 'Em "O aluno revisou o conteúdo, além disso resolveu questões", a expressão "além disso" indica:', options: ['Adição', 'Oposição', 'Conclusão', 'Causa', 'Condição'], correct: 0, explanation: '"Além disso" acrescenta uma informação à anterior. Portanto, indica adição.' },
  { id: 'pt-q84', subjectId: 'portugues', topic: 'Coesão e Coerência', text: 'Assinale a alternativa em que há relação de oposição:', options: ['Estudou muito e fez anotações.', 'Estudou muito, mas errou por falta de atenção.', 'Estudou porque queria melhorar.', 'Estudou para ser aprovado.', 'Estudou, portanto evoluiu.'], correct: 1, explanation: 'A conjunção "mas" estabelece oposição entre estudar muito e errar por falta de atenção.' },
  { id: 'pt-q85', subjectId: 'portugues', topic: 'Classes de Palavras', text: 'Na frase "Todos compareceram ao treinamento", a palavra "todos" é:', options: ['Pronome indefinido', 'Artigo definido', 'Preposição', 'Conjunção conclusiva', 'Advérbio de modo'], correct: 0, explanation: '"Todos" indica totalidade de forma indefinida em relação ao grupo; é pronome indefinido.' },
  { id: 'pt-q86', subjectId: 'portugues', topic: 'Classes de Palavras', text: 'Na frase "O candidato e o instrutor conversaram", a palavra "e" é:', options: ['Conjunção aditiva', 'Preposição essencial', 'Advérbio de intensidade', 'Pronome relativo', 'Substantivo comum'], correct: 0, explanation: '"E" liga termos somando ideias. É conjunção coordenativa aditiva.' },
  { id: 'pt-q87', subjectId: 'portugues', topic: 'Concordância Verbal e Nominal', text: 'Assinale a alternativa correta quanto à concordância verbal:', options: ['Houve muitos recursos contra a prova.', 'Houveram muitos recursos contra a prova.', 'Fazem dois anos que ele treina.', 'Existe muitas regras no edital.', 'Aconteceu várias mudanças.'], correct: 0, explanation: 'O verbo "haver", no sentido de existir, é impessoal e fica no singular: "Houve muitos recursos".' },
  { id: 'pt-q88', subjectId: 'portugues', topic: 'Concordância Verbal e Nominal', text: 'Assinale a alternativa correta quanto à concordância nominal:', options: ['As instruções estavam claras.', 'As instrução estavam claras.', 'Os candidatos estavam atenta.', 'A prova estava difíceis.', 'Os documento foram entregue.'], correct: 0, explanation: '"Instruções" está no feminino plural; por isso, "claras" também fica no feminino plural.' },
  { id: 'pt-q89', subjectId: 'portugues', topic: 'Regência Verbal e Nominal', text: 'No sentido de presenciar, assinale a alternativa correta:', options: ['Assistiu ao treinamento.', 'Assistiu o treinamento.', 'Assistiu no treinamento.', 'Assistiu pelo treinamento.', 'Assistiu com o treinamento.'], correct: 0, explanation: 'No sentido de ver ou presenciar, o verbo "assistir" exige preposição "a": "assistiu ao treinamento".' },
  { id: 'pt-q90', subjectId: 'portugues', topic: 'Regência Verbal e Nominal', text: 'Quanto à regência do verbo "obedecer", assinale a alternativa correta:', options: ['O candidato obedeceu ao edital.', 'O candidato obedeceu o edital.', 'O candidato obedeceu no edital.', 'O candidato obedeceu pelo edital.', 'O candidato obedeceu com o edital.'], correct: 0, explanation: 'O verbo "obedecer" exige preposição "a": quem obedece, obedece a algo ou a alguém. Portanto, o correto é: "obedeceu ao edital".' },
  { id: 'pt-q91', subjectId: 'portugues', topic: 'Crase', text: 'Assinale a alternativa em que a crase está correta:', options: ['O candidato referiu-se à prova objetiva.', 'O candidato começou à estudar.', 'O candidato entregou o recurso à prazo.', 'O candidato foi à pé ao local.', 'O candidato respondeu à todos.'], correct: 0, explanation: 'Em "referiu-se à prova", há preposição "a" exigida pelo verbo e artigo feminino antes de "prova".' },
  { id: 'pt-q92', subjectId: 'portugues', topic: 'Crase', text: 'Assinale a alternativa em que NÃO ocorre crase:', options: ['Foi à escola.', 'Referiu-se à candidata.', 'Dirigiu-se à autoridade.', 'Começou a revisar.', 'Entregou a ficha à fiscal.'], correct: 3, explanation: 'Não ocorre crase antes de verbo. Em "começou a revisar", o "a" é apenas preposição.' },
  { id: 'pt-q93', subjectId: 'portugues', topic: 'Pontuação', text: 'Assinale a alternativa corretamente pontuada:', options: ['Se houver dúvida, leia o enunciado novamente.', 'Se houver dúvida leia, o enunciado novamente.', 'Se houver, dúvida leia o enunciado novamente.', 'Se houver dúvida leia o enunciado, novamente.', 'Se houver dúvida leia o, enunciado novamente.'], correct: 0, explanation: 'A oração subordinada deslocada para o início pode ser separada por vírgula: "Se houver dúvida, leia...".' },
  { id: 'pt-q94', subjectId: 'portugues', topic: 'Pontuação', text: 'Assinale a alternativa em que a vírgula isola corretamente uma expressão intercalada:', options: ['A prova segundo o edital será objetiva.', 'A prova, segundo o edital, será objetiva.', 'A prova segundo, o edital será objetiva.', 'A prova será, objetiva segundo o edital.', 'A prova será objetiva segundo, o edital.'], correct: 1, explanation: '"Segundo o edital" é expressão intercalada e pode ser isolada por vírgulas.' },
  { id: 'pt-q95', subjectId: 'portugues', topic: 'Figuras de Linguagem', text: 'Em "Seus olhos eram faróis na noite", ocorre:', options: ['Metáfora', 'Eufemismo', 'Onomatopeia', 'Ironia', 'Pleonasmo'], correct: 0, explanation: 'Há metáfora, pois os olhos são associados a faróis sem uso de conectivo comparativo.' },
  { id: 'pt-q96', subjectId: 'portugues', topic: 'Figuras de Linguagem', text: 'Em "Estou morrendo de fome", ocorre:', options: ['Hipérbole', 'Metonímia', 'Prosopopeia', 'Antítese', 'Eufemismo'], correct: 0, explanation: 'Hipérbole é exagero intencional. A pessoa não está morrendo literalmente, apenas com muita fome.' },
  { id: 'pt-q97', subjectId: 'portugues', topic: 'Ortografia e Acentuação', text: 'Assinale a alternativa em que todas as palavras estão corretas:', options: ['Assessoria, exceção, disciplina', 'Acessoria, excessão, disciplina', 'Assessoria, eceção, diciplina', 'Acessoria, exceção, discíplina', 'Assessoria, excessão, diciplina'], correct: 0, explanation: 'As formas corretas são: assessoria, exceção e disciplina.' },
  { id: 'pt-q98', subjectId: 'portugues', topic: 'Ortografia e Acentuação', text: 'Assinale a alternativa correta segundo a ortografia atual:', options: ['Plateia não recebe acento.', 'Platéia deve receber acento.', 'Ideia deve ser grafada idéia.', 'Heroi não recebe acento.', 'Juri não recebe acento.'], correct: 0, explanation: 'Pela ortografia atual, "plateia" e "ideia" não recebem acento. Já "herói" e "júri" recebem acento.' },
  { id: 'pt-q99', subjectId: 'portugues', topic: 'Tipos Textuais', text: 'Um texto que conta uma ocorrência com começo, desenvolvimento e fim é predominantemente:', options: ['Narrativo', 'Injuntivo', 'Expositivo', 'Descritivo técnico', 'Argumentativo jurídico'], correct: 0, explanation: 'Texto narrativo apresenta sequência de fatos, com progressão temporal e acontecimentos.' },
  { id: 'pt-q100', subjectId: 'portugues', topic: 'Tipos Textuais', text: 'Um texto que caracteriza uma pessoa, lugar ou objeto, destacando suas qualidades ou aspectos, é predominantemente:', options: ['Descritivo', 'Narrativo', 'Injuntivo', 'Dissertativo argumentativo', 'Dialogal instrucional'], correct: 0, explanation: 'Texto descritivo apresenta características, aspectos e qualidades de algo ou alguém.' },



  // ====== MATEMÁTICA (100 questões) ======
  { id: 'mt-q01', subjectId: 'matematica', topic: 'Operações Fundamentais', text: 'O resultado de (−8) × (+3) + (−4) × (−5) é:', options: ['−4', '4', '−44', '44', '−24'], correct: 0, explanation: '(−8)×(+3) = −24. (−4)×(−5) = +20. −24 + 20 = −4.' },
  { id: 'mt-q02', subjectId: 'matematica', topic: 'Frações e Decimais', text: 'O resultado de 3/4 + 2/3 é:', options: ['5/7', '5/12', '17/12', '6/7', '1'], correct: 2, explanation: 'MMC de 4 e 3 = 12. 3/4 = 9/12. 2/3 = 8/12. 9/12 + 8/12 = 17/12.' },
  { id: 'mt-q03', subjectId: 'matematica', topic: 'Regra de Três', text: 'Se 8 operários produzem 120 peças em 5 horas, quantas peças 12 operários produzirão em 5 horas?', options: ['160', '180', '200', '150', '140'], correct: 1, explanation: 'Mais operários = mais peças (diretamente proporcional). 8/120 = 12/x → 8x = 1440 → x = 180.' },
  { id: 'mt-q04', subjectId: 'matematica', topic: 'Porcentagem', text: 'Um produto de R$250,00 recebeu um desconto de 12%. O preço final é:', options: ['R$238,00', 'R$220,00', 'R$225,00', 'R$242,00', 'R$230,00'], correct: 1, explanation: 'Desconto: 12% de 250 = 0,12 × 250 = R$30. Preço final: 250 − 30 = R$220. Ou: 250 × 0,88 = 220.' },
  { id: 'mt-q05', subjectId: 'matematica', topic: 'Equação do 1º Grau', text: 'Na equação 3x − 7 = 14, o valor de x é:', options: ['3', '5', '7', '−7', '−3'], correct: 2, explanation: '3x − 7 = 14 → 3x = 21 → x = 7.' },
  { id: 'mt-q06', subjectId: 'matematica', topic: 'Geometria Plana', text: 'A área de um triângulo com base 10 cm e altura 8 cm é:', options: ['80 cm²', '40 cm²', '18 cm²', '60 cm²', '100 cm²'], correct: 1, explanation: 'Área do triângulo = (base × altura) / 2 = (10 × 8) / 2 = 80/2 = 40 cm².' },
  { id: 'mt-q07', subjectId: 'matematica', topic: 'Porcentagem', text: 'João investiu R$5.000,00 a juros simples de 4% ao mês por 3 meses. O montante final é:', options: ['R$5.600', 'R$5.400', 'R$6.000', 'R$5.200', 'R$4.400'], correct: 0, explanation: 'J = P × i × t = 5000 × 0,04 × 3 = R$600. Montante = 5000 + 600 = R$5.600.' },
  { id: 'mt-q08', subjectId: 'matematica', topic: 'Razão e Proporção', text: 'A razão entre 15 e 25, na forma irredutível, é:', options: ['3/5', '5/3', '15/25', '1/2', '2/3'], correct: 0, explanation: '15/25 = 3/5 (dividindo ambos por 5).' },
  { id: 'mt-q09', subjectId: 'matematica', topic: 'Probabilidade', text: 'Uma urna tem 5 bolas brancas, 3 pretas e 2 vermelhas. Retirando-se uma bola ao acaso, a probabilidade de ser preta é:', options: ['3/10', '1/3', '1/2', '5/10', '2/10'], correct: 0, explanation: 'Total: 5+3+2 = 10 bolas. Favoráveis: 3 pretas. P = 3/10.' },
  { id: 'mt-q10', subjectId: 'matematica', topic: 'Análise Combinatória', text: 'De quantas maneiras 5 pessoas podem se sentar em uma fila com 5 cadeiras?', options: ['25', '60', '120', '10', '24'], correct: 2, explanation: 'Permutação de 5: P(5) = 5! = 5×4×3×2×1 = 120 maneiras.' },
  { id: 'mt-q11', subjectId: 'matematica', topic: 'Sistema de Equações', text: 'Resolvendo o sistema x + y = 10 e x − y = 4, encontramos x e y iguais a:', options: ['x=6, y=4', 'x=7, y=3', 'x=8, y=2', 'x=5, y=5', 'x=3, y=7'], correct: 1, explanation: 'Somando as equações: 2x = 14 → x = 7. Substituindo: 7 + y = 10 → y = 3.' },
  { id: 'mt-q12', subjectId: 'matematica', topic: 'Geometria Plana', text: 'O perímetro de um círculo de raio 7 cm é aproximadamente (use π ≈ 3,14):', options: ['21,98 cm', '43,96 cm', '153,86 cm', '14 cm', '87,92 cm'], correct: 1, explanation: 'Perímetro = 2πr = 2 × 3,14 × 7 = 43,96 cm.' },
  { id: 'mt-q13', subjectId: 'matematica', topic: 'Regra de Três', text: 'Um carro percorre 360 km com 30 litros de combustível. Quantos litros são necessários para percorrer 540 km?', options: ['40', '35', '45', '50', '60'], correct: 2, explanation: 'Proporção direta: 360/30 = 540/x → 360x = 16200 → x = 45 litros.' },
  { id: 'mt-q14', subjectId: 'matematica', topic: 'Equação do 1º Grau', text: 'Se 2(x + 3) = x + 11, então x vale:', options: ['3', '5', '7', '4', '2'], correct: 1, explanation: '2x + 6 = x + 11 → 2x − x = 11 − 6 → x = 5.' },
  { id: 'mt-q15', subjectId: 'matematica', topic: 'Frações e Decimais', text: 'Se 3/5 dos alunos de uma turma de 40 alunos foram aprovados, quantos foram reprovados?', options: ['24', '16', '20', '12', '8'], correct: 1, explanation: 'Aprovados: 3/5 × 40 = 24. Reprovados: 40 − 24 = 16.' },


  { id: 'mt-q16', subjectId: 'matematica', topic: 'Porcentagem', text: 'Em uma turma de 80 candidatos, 25% foram aprovados em um simulado. Quantos candidatos foram aprovados?', options: ['15', '18', '20', '25', '30'], correct: 2, explanation: '25% de 80 = 0,25 × 80 = 20 candidatos.' },
  { id: 'mt-q17', subjectId: 'matematica', topic: 'Regra de Três', text: 'Se 6 máquinas produzem 900 peças em um dia, quantas peças 10 máquinas iguais produzem no mesmo período?', options: ['1200', '1350', '1500', '1600', '1800'], correct: 2, explanation: 'A produção é diretamente proporcional ao número de máquinas: 6/900 = 10/x. Então 6x = 9000 e x = 1500.' },
  { id: 'mt-q18', subjectId: 'matematica', topic: 'Frações e Decimais', text: 'O valor de 2/5 de 150 é:', options: ['30', '45', '50', '60', '75'], correct: 3, explanation: '2/5 de 150 = 150 ÷ 5 × 2 = 30 × 2 = 60.' },
  { id: 'mt-q19', subjectId: 'matematica', topic: 'Equação do 1º Grau', text: 'A solução da equação 4x + 8 = 32 é:', options: ['4', '5', '6', '7', '8'], correct: 2, explanation: '4x + 8 = 32. Logo, 4x = 24 e x = 6.' },
  { id: 'mt-q20', subjectId: 'matematica', topic: 'Média Aritmética', text: 'As notas de um candidato em três simulados foram 6, 7 e 8. A média aritmética é:', options: ['6', '6,5', '7', '7,5', '8'], correct: 2, explanation: 'Média = (6 + 7 + 8) ÷ 3 = 21 ÷ 3 = 7.' },
  { id: 'mt-q21', subjectId: 'matematica', topic: 'Geometria Plana', text: 'Um retângulo tem 12 m de comprimento e 5 m de largura. Sua área é:', options: ['17 m²', '34 m²', '50 m²', '60 m²', '120 m²'], correct: 3, explanation: 'Área do retângulo = comprimento × largura = 12 × 5 = 60 m².' },
  { id: 'mt-q22', subjectId: 'matematica', topic: 'Razão e Proporção', text: 'A razão entre 18 e 24, na forma irredutível, é:', options: ['2/3', '3/4', '4/3', '6/8', '18/24'], correct: 1, explanation: '18/24 pode ser simplificado por 6, resultando em 3/4.' },
  { id: 'mt-q23', subjectId: 'matematica', topic: 'Juros Simples', text: 'Um capital de R$ 1.200,00 aplicado a juros simples de 5% ao mês durante 2 meses rende juros de:', options: ['R$ 60,00', 'R$ 90,00', 'R$ 100,00', 'R$ 120,00', 'R$ 150,00'], correct: 3, explanation: 'J = C × i × t = 1200 × 0,05 × 2 = 120.' },
  { id: 'mt-q24', subjectId: 'matematica', topic: 'Probabilidade', text: 'Ao lançar um dado comum, a probabilidade de sair um número maior que 4 é:', options: ['1/6', '1/3', '1/2', '2/3', '5/6'], correct: 1, explanation: 'Os números maiores que 4 são 5 e 6. São 2 casos favoráveis em 6 possíveis: 2/6 = 1/3.' },
  { id: 'mt-q25', subjectId: 'matematica', topic: 'Sistema Métrico', text: '3,5 quilômetros correspondem a quantos metros?', options: ['35 m', '350 m', '3500 m', '35000 m', '0,35 m'], correct: 2, explanation: '1 km = 1000 m. Portanto, 3,5 km = 3,5 × 1000 = 3500 m.' },


  { id: 'mt-q26', subjectId: 'matematica', topic: 'Operações Fundamentais', text: 'O valor de 18 - 3 × 4 + 10 é:', options: ['10', '16', '20', '28', '50'], correct: 1, explanation: 'Primeiro resolvemos a multiplicação: 3 × 4 = 12. Depois: 18 - 12 + 10 = 6 + 10 = 16.' },
  { id: 'mt-q27', subjectId: 'matematica', topic: 'Frações e Decimais', text: 'A fração 3/5 corresponde ao número decimal:', options: ['0,3', '0,35', '0,5', '0,6', '0,8'], correct: 3, explanation: 'Para transformar 3/5 em decimal, fazemos 3 ÷ 5 = 0,6.' },
  { id: 'mt-q28', subjectId: 'matematica', topic: 'Razão e Proporção', text: 'Em uma turma, há 12 mulheres e 18 homens. A razão entre mulheres e homens, na forma simplificada, é:', options: ['2/3', '3/2', '12/30', '1/3', '2/5'], correct: 0, explanation: 'A razão entre mulheres e homens é 12/18. Simplificando por 6, temos 2/3.' },
  { id: 'mt-q29', subjectId: 'matematica', topic: 'Regra de Três', text: 'Se 4 policiais conseguem abordar 320 pessoas em determinado período, mantendo o mesmo ritmo, 6 policiais abordariam:', options: ['400 pessoas', '420 pessoas', '480 pessoas', '500 pessoas', '640 pessoas'], correct: 2, explanation: 'A relação é diretamente proporcional: 4 policiais → 320 pessoas; 6 policiais → x. Então 4x = 6 × 320 = 1920, logo x = 480 pessoas.' },
  { id: 'mt-q30', subjectId: 'matematica', topic: 'Porcentagem', text: 'Um candidato acertou 42 questões de uma prova com 60 questões. Seu percentual de acerto foi:', options: ['60%', '65%', '70%', '75%', '80%'], correct: 2, explanation: 'Percentual = 42/60 = 0,7 = 70%.' },
  { id: 'mt-q31', subjectId: 'matematica', topic: 'Equação do 1º Grau', text: 'A solução da equação 5x - 10 = 30 é:', options: ['4', '6', '8', '10', '12'], correct: 2, explanation: '5x - 10 = 30. Então 5x = 40 e x = 8.' },
  { id: 'mt-q32', subjectId: 'matematica', topic: 'Sistema de Equações', text: 'No sistema x + y = 12 e x - y = 2, os valores de x e y são:', options: ['x=5, y=7', 'x=7, y=5', 'x=8, y=4', 'x=6, y=6', 'x=10, y=2'], correct: 1, explanation: 'Somando as equações: 2x = 14, então x = 7. Substituindo em x + y = 12: 7 + y = 12, logo y = 5.' },
  { id: 'mt-q33', subjectId: 'matematica', topic: 'Geometria Plana', text: 'Um quadrado tem lado de 9 cm. Sua área é:', options: ['18 cm²', '36 cm²', '72 cm²', '81 cm²', '90 cm²'], correct: 3, explanation: 'Área do quadrado = lado × lado = 9 × 9 = 81 cm².' },
  { id: 'mt-q34', subjectId: 'matematica', topic: 'Análise Combinatória', text: 'Uma senha será formada por uma letra escolhida entre A, B e C, seguida de um número escolhido entre 1, 2, 3 e 4. Quantas senhas diferentes podem ser formadas?', options: ['7', '9', '10', '12', '24'], correct: 3, explanation: 'Há 3 opções de letras e 4 opções de números. Pelo princípio multiplicativo: 3 × 4 = 12 senhas.' },
  { id: 'mt-q35', subjectId: 'matematica', topic: 'Probabilidade', text: 'Em uma caixa há 4 bolas azuis, 5 vermelhas e 1 preta. A probabilidade de retirar uma bola preta é:', options: ['1/10', '1/9', '1/5', '4/10', '5/10'], correct: 0, explanation: 'O total de bolas é 4 + 5 + 1 = 10. Há 1 bola preta. Portanto, a probabilidade é 1/10.' },

  { id: 'mt-q36', subjectId: 'matematica', topic: 'Operações Fundamentais', text: 'O valor de 72 ÷ 8 + 5 × 3 é:', options: ['18', '21', '24', '27', '30'], correct: 2, explanation: 'Primeiro resolvemos divisão e multiplicação: 72 ÷ 8 = 9 e 5 × 3 = 15. Depois somamos: 9 + 15 = 24.' },
  { id: 'mt-q37', subjectId: 'matematica', topic: 'Operações Fundamentais', text: 'O resultado de -6 + 4 × 5 é:', options: ['-10', '10', '14', '20', '26'], correct: 2, explanation: 'Primeiro a multiplicação: 4 × 5 = 20. Depois: -6 + 20 = 14.' },
  { id: 'mt-q38', subjectId: 'matematica', topic: 'Frações e Decimais', text: 'O resultado de 2/5 + 1/10 é:', options: ['1/2', '3/15', '2/15', '3/10', '1/5'], correct: 0, explanation: 'MMC de 5 e 10 é 10. 2/5 = 4/10. Então 4/10 + 1/10 = 5/10 = 1/2.' },
  { id: 'mt-q39', subjectId: 'matematica', topic: 'Frações e Decimais', text: 'O número decimal 0,25 corresponde à fração:', options: ['1/2', '1/3', '1/4', '2/5', '3/4'], correct: 2, explanation: '0,25 = 25/100. Simplificando por 25, temos 1/4.' },
  { id: 'mt-q40', subjectId: 'matematica', topic: 'Razão e Proporção', text: 'A razão 15 para 25, na forma simplificada, é:', options: ['1/5', '2/5', '3/5', '5/3', '15/10'], correct: 2, explanation: 'A razão é 15/25. Simplificando por 5, temos 3/5.' },
  { id: 'mt-q41', subjectId: 'matematica', topic: 'Razão e Proporção', text: 'Na proporção 3/4 = x/20, o valor de x é:', options: ['12', '15', '16', '18', '24'], correct: 1, explanation: 'Multiplicando em cruz: 4x = 3 × 20 = 60. Logo, x = 15.' },
  { id: 'mt-q42', subjectId: 'matematica', topic: 'Regra de Três', text: 'Se 3 policiais fazem 45 abordagens em certo período, mantendo o mesmo ritmo, 5 policiais fariam:', options: ['60 abordagens', '65 abordagens', '70 abordagens', '75 abordagens', '90 abordagens'], correct: 3, explanation: 'A relação é diretamente proporcional: 3 policiais → 45 abordagens; 5 policiais → x. Então 3x = 5 × 45 = 225, logo x = 75.' },
  { id: 'mt-q43', subjectId: 'matematica', topic: 'Regra de Três', text: 'Se 6 pessoas fazem um serviço em 8 horas, 4 pessoas, no mesmo ritmo, fariam o mesmo serviço em:', options: ['6 horas', '8 horas', '10 horas', '12 horas', '14 horas'], correct: 3, explanation: 'Menos pessoas levam mais tempo. É relação inversamente proporcional: 6 × 8 = 4 × x. Então 48 = 4x e x = 12 horas.' },
  { id: 'mt-q44', subjectId: 'matematica', topic: 'Porcentagem', text: 'Quanto é 15% de 240?', options: ['24', '30', '36', '40', '45'], correct: 2, explanation: '15% de 240 = 0,15 × 240 = 36.' },
  { id: 'mt-q45', subjectId: 'matematica', topic: 'Porcentagem', text: 'Um valor passou de 80 para 100. O aumento percentual foi de:', options: ['10%', '20%', '25%', '30%', '40%'], correct: 2, explanation: 'O aumento foi 20. Percentual de aumento = 20/80 = 0,25 = 25%.' },
  { id: 'mt-q46', subjectId: 'matematica', topic: 'Equação do 1º Grau', text: 'A solução da equação 3x + 7 = 28 é:', options: ['5', '6', '7', '8', '9'], correct: 2, explanation: '3x + 7 = 28. Então 3x = 21 e x = 7.' },
  { id: 'mt-q47', subjectId: 'matematica', topic: 'Equação do 1º Grau', text: 'A solução da equação 2(x - 3) = 14 é:', options: ['7', '8', '9', '10', '11'], correct: 3, explanation: '2(x - 3) = 14. Dividindo por 2: x - 3 = 7. Logo, x = 10.' },
  { id: 'mt-q48', subjectId: 'matematica', topic: 'Sistema de Equações', text: 'No sistema x + y = 20 e x - y = 6, os valores de x e y são:', options: ['x=12, y=8', 'x=13, y=7', 'x=14, y=6', 'x=15, y=5', 'x=16, y=4'], correct: 1, explanation: 'Somando as equações: 2x = 26, então x = 13. Substituindo em x + y = 20, temos y = 7.' },
  { id: 'mt-q49', subjectId: 'matematica', topic: 'Sistema de Equações', text: 'No sistema 2x + y = 11 e x + y = 7, os valores de x e y são:', options: ['x=2, y=5', 'x=3, y=4', 'x=4, y=3', 'x=5, y=2', 'x=6, y=1'], correct: 2, explanation: 'Subtraindo a segunda equação da primeira: x = 4. Depois, 4 + y = 7, então y = 3.' },
  { id: 'mt-q50', subjectId: 'matematica', topic: 'Geometria Plana', text: 'Um retângulo tem 12 cm de comprimento e 8 cm de largura. Sua área é:', options: ['20 cm²', '40 cm²', '80 cm²', '96 cm²', '120 cm²'], correct: 3, explanation: 'Área do retângulo = comprimento × largura = 12 × 8 = 96 cm².' },
  { id: 'mt-q51', subjectId: 'matematica', topic: 'Geometria Plana', text: 'Um quadrado tem lado de 7 metros. Seu perímetro é:', options: ['14 m', '21 m', '28 m', '35 m', '49 m'], correct: 2, explanation: 'Perímetro do quadrado = 4 × lado = 4 × 7 = 28 m.' },
  { id: 'mt-q52', subjectId: 'matematica', topic: 'Geometria Plana', text: 'Um triângulo tem base de 10 cm e altura de 6 cm. Sua área é:', options: ['16 cm²', '30 cm²', '40 cm²', '50 cm²', '60 cm²'], correct: 1, explanation: 'Área do triângulo = base × altura ÷ 2 = 10 × 6 ÷ 2 = 30 cm².' },
  { id: 'mt-q53', subjectId: 'matematica', topic: 'Análise Combinatória', text: 'Uma pessoa tem 3 camisetas, 2 calças e 2 pares de tênis. Quantas combinações de roupa pode formar?', options: ['7', '10', '12', '14', '18'], correct: 2, explanation: 'Pelo princípio multiplicativo: 3 × 2 × 2 = 12 combinações.' },
  { id: 'mt-q54', subjectId: 'matematica', topic: 'Análise Combinatória', text: 'Uma senha terá 2 algarismos distintos escolhidos entre 1, 2, 3 e 4. Quantas senhas podem ser formadas?', options: ['6', '8', '10', '12', '16'], correct: 3, explanation: 'Há 4 opções para o primeiro algarismo e 3 opções para o segundo, pois não pode repetir. Logo, 4 × 3 = 12.' },
  { id: 'mt-q55', subjectId: 'matematica', topic: 'Probabilidade', text: 'Em uma urna há 3 bolas azuis e 2 vermelhas. A probabilidade de retirar uma bola vermelha é:', options: ['1/5', '2/5', '3/5', '1/2', '2/3'], correct: 1, explanation: 'Há 5 bolas no total e 2 vermelhas. Portanto, a probabilidade é 2/5.' },
  { id: 'mt-q56', subjectId: 'matematica', topic: 'Probabilidade', text: 'Ao lançar um dado comum, a probabilidade de sair um número par é:', options: ['1/6', '1/3', '1/2', '2/3', '5/6'], correct: 2, explanation: 'Os números pares no dado são 2, 4 e 6: 3 resultados favoráveis em 6 possíveis. Logo, 3/6 = 1/2.' },
  { id: 'mt-q57', subjectId: 'matematica', topic: 'Média Aritmética', text: 'A média aritmética dos números 6, 7, 8 e 9 é:', options: ['7', '7,5', '8', '8,5', '9'], correct: 1, explanation: 'Somamos os valores: 6 + 7 + 8 + 9 = 30. Dividindo por 4, temos 7,5.' },
  { id: 'mt-q58', subjectId: 'matematica', topic: 'Juros Simples', text: 'Um capital de R$ 1.000,00 aplicado a juros simples de 2% ao mês por 5 meses rende:', options: ['R$ 50,00', 'R$ 80,00', 'R$ 100,00', 'R$ 120,00', 'R$ 200,00'], correct: 2, explanation: 'Juros simples: J = C × i × t. Então J = 1000 × 0,02 × 5 = 100.' },
  { id: 'mt-q59', subjectId: 'matematica', topic: 'Sistema Métrico', text: '2,5 km correspondem a:', options: ['25 m', '250 m', '2.500 m', '25.000 m', '250.000 m'], correct: 2, explanation: '1 km = 1.000 m. Logo, 2,5 km = 2.500 m.' },
  { id: 'mt-q60', subjectId: 'matematica', topic: 'Sistema Métrico', text: '3,2 litros correspondem a:', options: ['32 mL', '320 mL', '3.200 mL', '32.000 mL', '320.000 mL'], correct: 2, explanation: '1 litro = 1.000 mL. Logo, 3,2 litros = 3.200 mL.' },

  { id: 'mt-q61', subjectId: 'matematica', topic: 'Operações Fundamentais', text: 'O valor de 45 - 6 × 3 + 12 é:', options: ['27', '33', '39', '45', '57'], correct: 2, explanation: 'Primeiro a multiplicação: 6 × 3 = 18. Depois: 45 - 18 + 12 = 27 + 12 = 39.' },
  { id: 'mt-q62', subjectId: 'matematica', topic: 'Operações Fundamentais', text: 'O resultado de 36 ÷ 6 - 2 × 4 é:', options: ['-4', '-2', '0', '2', '4'], correct: 1, explanation: 'Primeiro divisão e multiplicação: 36 ÷ 6 = 6 e 2 × 4 = 8. Depois: 6 - 8 = -2.' },
  { id: 'mt-q63', subjectId: 'matematica', topic: 'Frações e Decimais', text: 'O resultado de 3/8 + 1/4 é:', options: ['1/2', '4/12', '5/8', '3/4', '7/8'], correct: 2, explanation: 'Como 1/4 = 2/8, temos 3/8 + 2/8 = 5/8.' },
  { id: 'mt-q64', subjectId: 'matematica', topic: 'Frações e Decimais', text: 'O número decimal 0,75 corresponde à fração:', options: ['1/4', '2/3', '3/5', '3/4', '4/5'], correct: 3, explanation: '0,75 = 75/100. Simplificando por 25, temos 3/4.' },
  { id: 'mt-q65', subjectId: 'matematica', topic: 'Razão e Proporção', text: 'A razão entre 24 e 36, na forma simplificada, é:', options: ['1/3', '2/3', '3/2', '4/5', '6/5'], correct: 1, explanation: 'A razão é 24/36. Simplificando por 12, temos 2/3.' },
  { id: 'mt-q66', subjectId: 'matematica', topic: 'Razão e Proporção', text: 'Na proporção 5/8 = x/40, o valor de x é:', options: ['20', '25', '30', '32', '35'], correct: 1, explanation: 'Multiplicando em cruz: 8x = 5 × 40 = 200. Logo, x = 25.' },
  { id: 'mt-q67', subjectId: 'matematica', topic: 'Regra de Três', text: 'Se 4 candidatos resolvem 80 questões em um treino, mantendo o mesmo ritmo, 6 candidatos resolveriam:', options: ['100 questões', '110 questões', '120 questões', '130 questões', '140 questões'], correct: 2, explanation: 'A relação é diretamente proporcional: 4 candidatos → 80 questões; 6 candidatos → x. Então 4x = 6 × 80 = 480, logo x = 120.' },
  { id: 'mt-q68', subjectId: 'matematica', topic: 'Regra de Três', text: 'Se 10 máquinas fazem um serviço em 6 horas, 5 máquinas, no mesmo ritmo, fariam o serviço em:', options: ['3 horas', '6 horas', '9 horas', '12 horas', '15 horas'], correct: 3, explanation: 'Menos máquinas levam mais tempo. É relação inversamente proporcional: 10 × 6 = 5 × x. Então 60 = 5x e x = 12 horas.' },
  { id: 'mt-q69', subjectId: 'matematica', topic: 'Porcentagem', text: 'Quanto é 30% de 150?', options: ['30', '35', '40', '45', '50'], correct: 3, explanation: '30% de 150 = 0,30 × 150 = 45.' },
  { id: 'mt-q70', subjectId: 'matematica', topic: 'Porcentagem', text: 'Um produto de R$ 200,00 recebeu desconto de 20%. O valor do desconto foi:', options: ['R$ 20,00', 'R$ 30,00', 'R$ 40,00', 'R$ 50,00', 'R$ 60,00'], correct: 2, explanation: '20% de 200 = 0,20 × 200 = 40. O desconto foi de R$ 40,00.' },
  { id: 'mt-q71', subjectId: 'matematica', topic: 'Equação do 1º Grau', text: 'A solução da equação 4x - 12 = 20 é:', options: ['4', '6', '8', '10', '12'], correct: 2, explanation: '4x - 12 = 20. Então 4x = 32 e x = 8.' },
  { id: 'mt-q72', subjectId: 'matematica', topic: 'Equação do 1º Grau', text: 'A solução da equação x/3 + 5 = 11 é:', options: ['12', '15', '18', '21', '24'], correct: 2, explanation: 'x/3 + 5 = 11. Então x/3 = 6. Multiplicando por 3, x = 18.' },
  { id: 'mt-q73', subjectId: 'matematica', topic: 'Sistema de Equações', text: 'No sistema x + y = 18 e x - y = 4, os valores de x e y são:', options: ['x=10, y=8', 'x=11, y=7', 'x=12, y=6', 'x=13, y=5', 'x=14, y=4'], correct: 1, explanation: 'Somando as equações: 2x = 22, então x = 11. Substituindo em x + y = 18, temos y = 7.' },
  { id: 'mt-q74', subjectId: 'matematica', topic: 'Geometria Plana', text: 'Um terreno retangular mede 15 m por 10 m. Seu perímetro é:', options: ['25 m', '30 m', '40 m', '50 m', '150 m'], correct: 3, explanation: 'Perímetro do retângulo = 2 × (comprimento + largura) = 2 × (15 + 10) = 50 m.' },
  { id: 'mt-q75', subjectId: 'matematica', topic: 'Geometria Plana', text: 'Um círculo tem raio de 5 cm. Usando π = 3,14, sua área aproximada é:', options: ['15,7 cm²', '31,4 cm²', '50 cm²', '78,5 cm²', '100 cm²'], correct: 3, explanation: 'Área do círculo = π × r². Então A = 3,14 × 5² = 3,14 × 25 = 78,5 cm².' },
  { id: 'mt-q76', subjectId: 'matematica', topic: 'Análise Combinatória', text: 'Com os algarismos 1, 2 e 3, quantos números de 2 algarismos distintos podem ser formados?', options: ['3', '4', '5', '6', '9'], correct: 3, explanation: 'Há 3 opções para o primeiro algarismo e 2 para o segundo, sem repetição. Logo, 3 × 2 = 6.' },
  { id: 'mt-q77', subjectId: 'matematica', topic: 'Probabilidade', text: 'Em uma caixa há 6 bolas brancas e 4 pretas. A probabilidade de retirar uma bola branca é:', options: ['2/5', '3/5', '4/5', '1/2', '1/4'], correct: 1, explanation: 'Há 10 bolas no total e 6 brancas. A probabilidade é 6/10 = 3/5.' },
  { id: 'mt-q78', subjectId: 'matematica', topic: 'Média Aritmética', text: 'A média aritmética de 10, 12, 14 e 16 é:', options: ['12', '13', '14', '15', '16'], correct: 1, explanation: 'Somamos os valores: 10 + 12 + 14 + 16 = 52. Dividindo por 4, temos 13.' },
  { id: 'mt-q79', subjectId: 'matematica', topic: 'Juros Simples', text: 'Um capital de R$ 500,00 aplicado a juros simples de 4% ao mês por 3 meses rende:', options: ['R$ 40,00', 'R$ 50,00', 'R$ 60,00', 'R$ 80,00', 'R$ 100,00'], correct: 2, explanation: 'Juros simples: J = C × i × t. Então J = 500 × 0,04 × 3 = 60.' },
  { id: 'mt-q80', subjectId: 'matematica', topic: 'Sistema Métrico', text: '450 centímetros correspondem a:', options: ['0,45 m', '4,5 m', '45 m', '450 m', '4.500 m'], correct: 1, explanation: '1 metro = 100 centímetros. Logo, 450 cm = 4,5 m.' },

  { id: 'mt-q81', subjectId: 'matematica', topic: 'Operações Fundamentais', text: 'O valor de 100 - 4 × 12 + 18 é:', options: ['58', '60', '70', '78', '88'], correct: 2, explanation: 'Primeiro a multiplicação: 4 × 12 = 48. Depois: 100 - 48 + 18 = 52 + 18 = 70.' },
  { id: 'mt-q82', subjectId: 'matematica', topic: 'Operações Fundamentais', text: 'O resultado de 9² - 5 × 6 é:', options: ['21', '31', '41', '51', '61'], correct: 3, explanation: 'Primeiro a potência: 9² = 81. Depois a multiplicação: 5 × 6 = 30. Então 81 - 30 = 51.' },
  { id: 'mt-q83', subjectId: 'matematica', topic: 'Frações e Decimais', text: 'O resultado de 5/6 - 1/3 é:', options: ['1/6', '1/3', '1/2', '2/3', '5/3'], correct: 2, explanation: 'Como 1/3 = 2/6, temos 5/6 - 2/6 = 3/6 = 1/2.' },
  { id: 'mt-q84', subjectId: 'matematica', topic: 'Frações e Decimais', text: 'O número decimal 1,25 corresponde à fração:', options: ['1/4', '5/4', '3/4', '4/5', '6/5'], correct: 1, explanation: '1,25 = 125/100. Simplificando por 25, temos 5/4.' },
  { id: 'mt-q85', subjectId: 'matematica', topic: 'Razão e Proporção', text: 'A razão entre 18 e 30, na forma simplificada, é:', options: ['1/3', '2/3', '3/5', '5/3', '6/5'], correct: 2, explanation: 'A razão é 18/30. Simplificando por 6, temos 3/5.' },
  { id: 'mt-q86', subjectId: 'matematica', topic: 'Razão e Proporção', text: 'Na proporção 7/10 = x/50, o valor de x é:', options: ['25', '30', '35', '40', '45'], correct: 2, explanation: 'Multiplicando em cruz: 10x = 7 × 50 = 350. Logo, x = 35.' },
  { id: 'mt-q87', subjectId: 'matematica', topic: 'Regra de Três', text: 'Se 8 candidatos resolvem 160 questões em um treino, mantendo o mesmo ritmo, 5 candidatos resolveriam:', options: ['80 questões', '90 questões', '100 questões', '110 questões', '120 questões'], correct: 2, explanation: 'A relação é diretamente proporcional: 8 candidatos → 160 questões; 5 candidatos → x. Então 8x = 5 × 160 = 800, logo x = 100.' },
  { id: 'mt-q88', subjectId: 'matematica', topic: 'Regra de Três', text: 'Se 12 servidores fazem um trabalho em 5 horas, 6 servidores, no mesmo ritmo, fariam o trabalho em:', options: ['2,5 horas', '5 horas', '7,5 horas', '10 horas', '12 horas'], correct: 3, explanation: 'Menos servidores levam mais tempo. É relação inversamente proporcional: 12 × 5 = 6 × x. Então 60 = 6x e x = 10 horas.' },
  { id: 'mt-q89', subjectId: 'matematica', topic: 'Porcentagem', text: 'Quanto é 12% de 250?', options: ['20', '25', '30', '35', '40'], correct: 2, explanation: '12% de 250 = 0,12 × 250 = 30.' },
  { id: 'mt-q90', subjectId: 'matematica', topic: 'Porcentagem', text: 'Um candidato acertou 48 questões de uma prova com 60 questões. O percentual de acerto foi:', options: ['70%', '75%', '80%', '85%', '90%'], correct: 2, explanation: 'Percentual = 48/60 = 0,8 = 80%.' },
  { id: 'mt-q91', subjectId: 'matematica', topic: 'Equação do 1º Grau', text: 'A solução da equação 6x + 4 = 40 é:', options: ['4', '5', '6', '7', '8'], correct: 2, explanation: '6x + 4 = 40. Então 6x = 36 e x = 6.' },
  { id: 'mt-q92', subjectId: 'matematica', topic: 'Equação do 1º Grau', text: 'A solução da equação 3(x + 2) = 27 é:', options: ['5', '6', '7', '8', '9'], correct: 2, explanation: '3(x + 2) = 27. Dividindo por 3: x + 2 = 9. Logo, x = 7.' },
  { id: 'mt-q93', subjectId: 'matematica', topic: 'Sistema de Equações', text: 'No sistema x + y = 15 e x - y = 3, os valores de x e y são:', options: ['x=8, y=7', 'x=9, y=6', 'x=10, y=5', 'x=11, y=4', 'x=12, y=3'], correct: 1, explanation: 'Somando as equações: 2x = 18, então x = 9. Substituindo em x + y = 15, temos y = 6.' },
  { id: 'mt-q94', subjectId: 'matematica', topic: 'Geometria Plana', text: 'Um retângulo tem área de 72 m² e largura de 8 m. Seu comprimento é:', options: ['6 m', '7 m', '8 m', '9 m', '10 m'], correct: 3, explanation: 'Área = comprimento × largura. Então 72 = comprimento × 8. Logo, comprimento = 72/8 = 9 m.' },
  { id: 'mt-q95', subjectId: 'matematica', topic: 'Geometria Plana', text: 'Um triângulo tem área de 48 cm² e base de 12 cm. Sua altura é:', options: ['4 cm', '6 cm', '8 cm', '10 cm', '12 cm'], correct: 2, explanation: 'Área do triângulo = base × altura ÷ 2. Então 48 = 12 × h ÷ 2. Logo, 48 = 6h e h = 8 cm.' },
  { id: 'mt-q96', subjectId: 'matematica', topic: 'Análise Combinatória', text: 'Um lanche pode ser montado com 4 tipos de pão e 3 tipos de recheio. Quantas combinações diferentes são possíveis?', options: ['7', '10', '12', '14', '16'], correct: 2, explanation: 'Pelo princípio multiplicativo: 4 × 3 = 12 combinações.' },
  { id: 'mt-q97', subjectId: 'matematica', topic: 'Probabilidade', text: 'Em uma urna há 5 bolas verdes, 3 amarelas e 2 azuis. A probabilidade de retirar uma bola azul é:', options: ['1/10', '1/5', '2/5', '1/2', '3/10'], correct: 1, explanation: 'O total de bolas é 5 + 3 + 2 = 10. Há 2 bolas azuis. Logo, a probabilidade é 2/10 = 1/5.' },
  { id: 'mt-q98', subjectId: 'matematica', topic: 'Média Aritmética', text: 'A média aritmética de 15, 20 e 25 é:', options: ['18', '19', '20', '21', '22'], correct: 2, explanation: 'Somamos: 15 + 20 + 25 = 60. Dividindo por 3, temos 20.' },
  { id: 'mt-q99', subjectId: 'matematica', topic: 'Juros Simples', text: 'Um capital de R$ 800,00 aplicado a juros simples de 5% ao mês por 2 meses rende:', options: ['R$ 40,00', 'R$ 60,00', 'R$ 80,00', 'R$ 100,00', 'R$ 120,00'], correct: 2, explanation: 'Juros simples: J = C × i × t. Então J = 800 × 0,05 × 2 = 80.' },
  { id: 'mt-q100', subjectId: 'matematica', topic: 'Sistema Métrico', text: '7.500 metros correspondem a:', options: ['0,75 km', '7,5 km', '75 km', '750 km', '7.500 km'], correct: 1, explanation: '1 km = 1.000 m. Logo, 7.500 m = 7,5 km.' },


  // ====== CONHECIMENTOS GERAIS (100 questões) ======
  { id: 'cg-q01', subjectId: 'gerais', topic: 'História do Brasil', text: 'A Proclamação da República no Brasil ocorreu em:', options: ['1822', '1888', '1889', '1891', '1900'], correct: 2, explanation: 'A República foi proclamada em 15 de novembro de 1889, pelo Marechal Deodoro da Fonseca, pondo fim ao Império.' },
  { id: 'cg-q02', subjectId: 'gerais', topic: 'Geografia do Brasil', text: 'O maior bioma brasileiro em extensão territorial é:', options: ['Mata Atlântica', 'Cerrado', 'Caatinga', 'Amazônia', 'Pampa'], correct: 3, explanation: 'A Amazônia é o maior bioma brasileiro, cobrindo cerca de 49% do território nacional.' },
  { id: 'cg-q03', subjectId: 'gerais', topic: 'Constituição Federal', text: 'O artigo 5º da Constituição Federal de 1988 trata dos:', options: ['Direitos sociais', 'Direitos e garantias individuais', 'Organização do Estado', 'Tributação', 'Administração pública'], correct: 1, explanation: 'O Art. 5º da CF/88 estabelece os direitos e garantias fundamentais individuais, como vida, liberdade, igualdade e propriedade.' },
  { id: 'cg-q04', subjectId: 'gerais', topic: 'História do Brasil', text: 'A Lei Áurea, que aboliu a escravidão no Brasil, foi assinada por:', options: ['Dom Pedro I', 'Dom Pedro II', 'Princesa Isabel', 'Deodoro da Fonseca', 'Rui Barbosa'], correct: 2, explanation: 'A Princesa Isabel assinou a Lei Áurea em 13 de maio de 1888, abolindo a escravidão no Brasil.' },
  { id: 'cg-q05', subjectId: 'gerais', topic: 'Geografia de São Paulo', text: 'O estado de São Paulo é banhado pelo oceano:', options: ['Atlântico', 'Pacífico', 'Índico', 'Ártico', 'Nenhum, é estado interiorano'], correct: 0, explanation: 'São Paulo tem litoral banhado pelo Oceano Atlântico, com praias como Santos, Guarujá e Ubatuba.' },
  { id: 'cg-q06', subjectId: 'gerais', topic: 'Constituição Federal', text: 'Segundo o Art. 144 da CF/88, a segurança pública é:', options: ['Dever exclusivo da polícia', 'Direito e responsabilidade de todos', 'Atribuição do Poder Judiciário', 'Competência privativa da União', 'Função das Forças Armadas'], correct: 1, explanation: 'O Art. 144 afirma que "a segurança pública, dever do Estado, direito e responsabilidade de todos, é exercida para a preservação da ordem pública e da incolumidade das pessoas e do patrimônio".' },
  { id: 'cg-q07', subjectId: 'gerais', topic: 'História do Brasil', text: 'A Era Vargas no Brasil teve início com a Revolução de:', options: ['1922', '1930', '1937', '1945', '1964'], correct: 1, explanation: 'Getúlio Vargas assumiu o poder em 1930, após a Revolução de 1930, e governou até 1945 (e depois de 1951 a 1954).' },
  { id: 'cg-q08', subjectId: 'gerais', topic: 'Geografia do Brasil', text: 'O rio que banha a cidade de São Paulo é:', options: ['Paraíba do Sul', 'Tietê', 'Amazonas', 'São Francisco', 'Paraná'], correct: 1, explanation: 'O Rio Tietê banha a cidade de São Paulo. Nasce em Salesópolis e atravessa o estado.' },
  { id: 'cg-q09', subjectId: 'gerais', topic: 'Meio Ambiente e Sustentabilidade', text: 'A conferência da ONU sobre meio ambiente realizada no Rio de Janeiro em 1992 ficou conhecida como:', options: ['COP21', 'Rio-92 ou Eco-92', 'Conferência de Estocolmo', 'Protocolo de Kyoto', 'Agenda 2030'], correct: 1, explanation: 'A Rio-92 (ou ECO-92) foi a Conferência das Nações Unidas sobre Meio Ambiente e Desenvolvimento, realizada no Rio de Janeiro em 1992.' },
  { id: 'cg-q10', subjectId: 'gerais', topic: 'Organização do Estado', text: 'Os três Poderes da República são:', options: ['Executivo, Legislativo e Judiciário', 'Presidência, Congresso e STF', 'Federal, Estadual e Municipal', 'Civil, Militar e Eleitoral', 'Constitucional, Administrativo e Penal'], correct: 0, explanation: 'Os três Poderes da República, conforme a CF/88, são: Executivo, Legislativo e Judiciário.' },
  { id: 'cg-q11', subjectId: 'gerais', topic: 'Atualidades', text: 'A LGPD (Lei Geral de Proteção de Dados) é a Lei nº:', options: ['12.527/2011', '13.709/2018', '14.133/2021', '8.429/1992', '10.406/2002'], correct: 1, explanation: 'A LGPD é a Lei nº 13.709/2018, que disciplina o tratamento de dados pessoais no Brasil.' },
  { id: 'cg-q12', subjectId: 'gerais', topic: 'Geografia do Brasil', text: 'O bioma brasileiro mais ameaçado, com apenas cerca de 12% de sua cobertura original, é:', options: ['Amazônia', 'Cerrado', 'Mata Atlântica', 'Caatinga', 'Pantanal'], correct: 2, explanation: 'A Mata Atlântica é o bioma mais devastado do Brasil, restando apenas cerca de 12% de sua cobertura original.' },
  { id: 'cg-q13', subjectId: 'gerais', topic: 'Constituição Federal', text: 'O remédio constitucional utilizado para proteger o direito de locomoção (liberdade de ir e vir) é:', options: ['Mandado de segurança', 'Habeas corpus', 'Ação popular', 'Mandado de injunção', 'Habeas data'], correct: 1, explanation: 'O habeas corpus é o remédio constitucional usado para proteger o direito de locomoção (liberdade de ir e vir).' },
  { id: 'cg-q14', subjectId: 'gerais', topic: 'Segurança Pública', text: 'A Polícia Militar é responsável pela:', options: ['Polícia judiciária', 'Polícia ostensiva e preservação da ordem pública', 'Investigação de crimes', 'Polícia federal', 'Polícia legislativa'], correct: 1, explanation: 'A PM é responsável pela polícia ostensiva e pela preservação da ordem pública, conforme o Art. 144, §5º da CF/88.' },
  { id: 'cg-q15', subjectId: 'gerais', topic: 'História de São Paulo', text: 'A Revolução Constitucionalista de 1932 teve início no estado de:', options: ['Minas Gerais', 'Rio de Janeiro', 'São Paulo', 'Rio Grande do Sul', 'Bahia'], correct: 2, explanation: 'A Revolução de 1932 começou em São Paulo em 9 de julho, exigindo a constitucionalização do país e novas eleições.' },


  { id: 'cg-q16', subjectId: 'gerais', topic: 'Constituição Federal', text: 'Segundo a Constituição Federal, a segurança pública é exercida para a preservação:', options: ['Da ordem pública e da incolumidade das pessoas e do patrimônio', 'Apenas da propriedade privada', 'Exclusivamente da ordem econômica', 'Somente dos bens públicos federais', 'Apenas da segurança das autoridades'], correct: 0, explanation: 'O art. 144 da Constituição Federal estabelece que a segurança pública é exercida para a preservação da ordem pública e da incolumidade das pessoas e do patrimônio.' },
  { id: 'cg-q17', subjectId: 'gerais', topic: 'História do Brasil', text: 'O movimento conhecido como Inconfidência Mineira ocorreu no contexto:', options: ['Da crise da mineração e da cobrança de impostos pela Coroa portuguesa', 'Da Proclamação da República', 'Da industrialização do Estado Novo', 'Da Guerra do Paraguai', 'Da Revolução Constitucionalista'], correct: 0, explanation: 'A Inconfidência Mineira ocorreu no século XVIII, em meio à crise da mineração e à insatisfação com impostos como a derrama.' },
  { id: 'cg-q18', subjectId: 'gerais', topic: 'Geografia do Brasil', text: 'A região brasileira com maior participação histórica na industrialização do país é:', options: ['Norte', 'Nordeste', 'Centro-Oeste', 'Sudeste', 'Sul apenas'], correct: 3, explanation: 'A Região Sudeste, especialmente São Paulo, teve papel central na industrialização brasileira devido à infraestrutura, mercado consumidor, capital acumulado e concentração populacional.' },
  { id: 'cg-q19', subjectId: 'gerais', topic: 'Constituição Federal', text: 'O princípio constitucional da igualdade está associado à ideia de que:', options: ['Todos devem ser tratados de forma arbitrária', 'Todos são iguais perante a lei, sem distinção injustificada', 'A lei só vale para servidores públicos', 'Os direitos fundamentais podem ser ignorados em qualquer situação', 'A igualdade elimina todos os deveres do cidadão'], correct: 1, explanation: 'O art. 5º da Constituição Federal afirma que todos são iguais perante a lei, sem distinção injustificada.' },
  { id: 'cg-q20', subjectId: 'gerais', topic: 'História de São Paulo', text: 'A Revolução Constitucionalista de 1932 tinha como uma de suas principais reivindicações:', options: ['A volta da monarquia', 'A elaboração de uma nova Constituição', 'A extinção do Estado de São Paulo', 'A independência do Brasil', 'A criação do Plano Real'], correct: 1, explanation: 'O movimento de 1932 defendia a constitucionalização do país, após a Revolução de 1930 e a ascensão de Getúlio Vargas ao poder.' },
  { id: 'cg-q21', subjectId: 'gerais', topic: 'Meio Ambiente e Sustentabilidade', text: 'O desenvolvimento sustentável busca conciliar:', options: ['Crescimento econômico, preservação ambiental e justiça social', 'Apenas crescimento econômico', 'Apenas proteção ambiental sem atividade humana', 'Exploração ilimitada dos recursos naturais', 'A substituição completa da legislação ambiental'], correct: 0, explanation: 'Desenvolvimento sustentável procura atender às necessidades atuais sem comprometer as gerações futuras, conciliando economia, ambiente e sociedade.' },
  { id: 'cg-q22', subjectId: 'gerais', topic: 'Atualidades', text: 'A desinformação nas redes sociais representa risco à cidadania porque:', options: ['Facilita sempre o acesso à verdade', 'Pode manipular opiniões e prejudicar decisões públicas conscientes', 'Elimina a necessidade de educação midiática', 'Impede qualquer forma de comunicação', 'É sempre produzida por órgãos oficiais'], correct: 1, explanation: 'A desinformação pode influenciar escolhas políticas, sociais e individuais, prejudicando o debate público e a tomada de decisões conscientes.' },
  { id: 'cg-q23', subjectId: 'gerais', topic: 'Organização do Estado', text: 'No Brasil, União, Estados, Distrito Federal e Municípios são:', options: ['Empresas públicas', 'Entes federativos autônomos', 'Órgãos do Poder Judiciário', 'Partidos políticos', 'Autarquias federais'], correct: 1, explanation: 'A Constituição organiza a Federação brasileira em União, Estados, Distrito Federal e Municípios, todos com autonomia nos termos constitucionais.' },
  { id: 'cg-q24', subjectId: 'gerais', topic: 'Geografia de São Paulo', text: 'O estado de São Paulo se destaca na economia brasileira principalmente por:', options: ['Ter economia pouco diversificada', 'Concentrar importante parque industrial, serviços e agropecuária moderna', 'Depender exclusivamente da pesca', 'Não possuir infraestrutura logística relevante', 'Ser o menor mercado consumidor do país'], correct: 1, explanation: 'São Paulo possui economia diversificada, com forte presença industrial, setor de serviços, tecnologia, agropecuária moderna e infraestrutura logística.' },
  { id: 'cg-q25', subjectId: 'gerais', topic: 'Segurança Pública', text: 'A atuação preventiva da Polícia Militar está mais diretamente ligada:', options: ['À polícia ostensiva e à preservação da ordem pública', 'À elaboração de sentenças judiciais', 'À investigação exclusiva de crimes federais', 'À emissão de moeda', 'À fiscalização de contas públicas'], correct: 0, explanation: 'A Polícia Militar exerce polícia ostensiva e atua na preservação da ordem pública, o que inclui presença preventiva e atendimento de ocorrências.' },


  { id: 'cg-q26', subjectId: 'gerais', topic: 'Atualidades', text: 'No debate atual sobre transição energética, uma medida diretamente relacionada ao tema é:', options: ['Ampliar o uso de fontes renováveis de energia', 'Eliminar totalmente o saneamento básico', 'Substituir a Constituição por normas privadas', 'Reduzir a fiscalização ambiental a zero', 'Impedir qualquer inovação tecnológica'], correct: 0, explanation: 'Transição energética envolve mudança gradual para fontes mais limpas e renováveis, buscando reduzir impactos ambientais e dependência de combustíveis fósseis.' },
  { id: 'cg-q27', subjectId: 'gerais', topic: 'História do Brasil', text: 'O coronelismo, característico da Primeira República, estava associado:', options: ['Ao fortalecimento do voto livre e secreto', 'Ao poder local de líderes políticos e controle eleitoral', 'À industrialização avançada do Norte do Brasil', 'À extinção das oligarquias estaduais', 'À implantação imediata da democracia plena'], correct: 1, explanation: 'O coronelismo envolvia o poder de lideranças locais, controle político e práticas como o voto de cabresto.' },
  { id: 'cg-q28', subjectId: 'gerais', topic: 'Geografia do Brasil', text: 'A Caatinga é um bioma brasileiro associado principalmente:', options: ['Ao clima semiárido', 'Ao clima polar', 'À floresta equatorial úmida', 'À planície permanentemente alagada', 'Ao clima temperado frio'], correct: 0, explanation: 'A Caatinga é típica do semiárido brasileiro, com vegetação adaptada à escassez de água.' },
  { id: 'cg-q29', subjectId: 'gerais', topic: 'Organização do Estado', text: 'No Brasil, a função típica do Poder Legislativo é:', options: ['Julgar conflitos entre particulares', 'Administrar políticas públicas diretamente', 'Legislar e fiscalizar', 'Comandar exclusivamente as polícias militares', 'Executar sentenças penais'], correct: 2, explanation: 'O Poder Legislativo tem como funções típicas legislar e fiscalizar a atuação do Poder Executivo.' },
  { id: 'cg-q30', subjectId: 'gerais', topic: 'Segurança Pública', text: 'A atuação da Polícia Militar está mais diretamente relacionada:', options: ['À polícia ostensiva e à preservação da ordem pública', 'À emissão de moeda nacional', 'Ao julgamento de crimes dolosos contra a vida', 'À elaboração de leis federais', 'À fiscalização exclusiva de contratos administrativos'], correct: 0, explanation: 'A Polícia Militar exerce policiamento ostensivo e atua na preservação da ordem pública, conforme a Constituição Federal.' },


  { id: 'cg-q31', subjectId: 'gerais', topic: 'História do Brasil', text: 'No período colonial, o pacto colonial significava que:', options: ['A colônia tinha plena liberdade comercial', 'A colônia deveria atender aos interesses econômicos da metrópole', 'A metrópole não interferia na economia colonial', 'A colônia podia eleger livremente seu presidente', 'O Brasil já era uma república independente'], correct: 1, explanation: 'O pacto colonial subordinava a economia da colônia aos interesses da metrópole, no caso, Portugal.' },
  { id: 'cg-q32', subjectId: 'gerais', topic: 'Geografia de São Paulo', text: 'O interior paulista se destaca, entre outros fatores, por:', options: ['Não possuir relevância econômica', 'Concentrar apenas atividades pesqueiras', 'Ter agropecuária moderna, indústria e cidades médias importantes', 'Ser totalmente isolado da capital', 'Não possuir infraestrutura logística'], correct: 2, explanation: 'O interior de São Paulo possui agropecuária moderna, polos industriais, universidades, tecnologia e cidades médias fortes.' },
  { id: 'cg-q33', subjectId: 'gerais', topic: 'Constituição Federal', text: 'O princípio da legalidade, previsto na Constituição, indica que:', options: ['Qualquer autoridade pode agir sem limite', 'Ninguém será obrigado a fazer ou deixar de fazer algo senão em virtude de lei', 'A lei vale apenas para particulares', 'Direitos fundamentais podem ser ignorados em serviço público', 'A Administração Pública não precisa obedecer à lei'], correct: 1, explanation: 'O princípio da legalidade protege o cidadão contra imposições sem base legal.' },
  { id: 'cg-q34', subjectId: 'gerais', topic: 'Meio Ambiente e Sustentabilidade', text: 'O saneamento básico está diretamente relacionado:', options: ['Apenas ao lazer da população', 'À saúde pública e à qualidade de vida', 'Somente à produção industrial', 'À extinção da cidadania', 'Apenas ao transporte urbano'], correct: 1, explanation: 'Saneamento básico envolve água, esgoto, limpeza urbana e drenagem, impactando diretamente a saúde pública e a qualidade de vida.' },
  { id: 'cg-q35', subjectId: 'gerais', topic: 'Atualidades', text: 'A educação midiática é importante porque ajuda o cidadão a:', options: ['Compartilhar qualquer informação rapidamente', 'Identificar fontes confiáveis e evitar desinformação', 'Acreditar em todo conteúdo de rede social', 'Substituir a Constituição Federal', 'Eliminar o debate público'], correct: 1, explanation: 'Educação midiática ajuda a analisar informações, verificar fontes e reduzir os efeitos da desinformação.' },

  { id: 'cg-q36', subjectId: 'gerais', topic: 'História do Brasil', text: 'A Independência do Brasil foi proclamada em:', options: ['1500', '1822', '1889', '1930', '1988'], correct: 1, explanation: 'A Independência do Brasil foi proclamada em 7 de setembro de 1822, por Dom Pedro I.' },
  { id: 'cg-q37', subjectId: 'gerais', topic: 'História do Brasil', text: 'A Lei Áurea, assinada em 1888, determinou:', options: ['A Proclamação da República', 'A abolição da escravidão no Brasil', 'A criação da Constituição de 1988', 'A transferência da capital para Brasília', 'O início da Era Vargas'], correct: 1, explanation: 'A Lei Áurea aboliu formalmente a escravidão no Brasil em 13 de maio de 1888.' },
  { id: 'cg-q38', subjectId: 'gerais', topic: 'História do Brasil', text: 'O Estado Novo, durante o governo Vargas, caracterizou-se principalmente por:', options: ['Ampla descentralização política', 'Regime democrático com eleições diretas livres', 'Autoritarismo e centralização do poder', 'Fim do poder presidencial', 'Monarquia parlamentarista'], correct: 2, explanation: 'O Estado Novo, de 1937 a 1945, foi um período autoritário, com centralização política e restrição de liberdades.' },
  { id: 'cg-q39', subjectId: 'gerais', topic: 'História de São Paulo', text: 'Os bandeirantes, ligados à história paulista, tiveram papel associado:', options: ['À interiorização do território colonial', 'À construção de Brasília', 'À criação da ONU', 'À industrialização do século XXI', 'À independência dos Estados Unidos'], correct: 0, explanation: 'Os bandeirantes partiram principalmente de São Paulo e contribuíram para a interiorização do território colonial, embora também estejam associados a práticas violentas contra indígenas e escravizados.' },
  { id: 'cg-q40', subjectId: 'gerais', topic: 'História de São Paulo', text: 'A expansão da economia cafeeira em São Paulo esteve ligada, entre outros fatores:', options: ['À inexistência de ferrovias', 'Ao avanço de ferrovias e ao crescimento econômico do interior paulista', 'À proibição da imigração', 'Ao fim da agricultura no estado', 'À ausência de exportações'], correct: 1, explanation: 'O café impulsionou ferrovias, imigração, urbanização e crescimento econômico em diversas regiões paulistas.' },
  { id: 'cg-q41', subjectId: 'gerais', topic: 'Geografia do Brasil', text: 'O Brasil é considerado um país de grande extensão territorial porque:', options: ['Possui pequena área e baixa diversidade regional', 'Tem território amplo e diversidade de paisagens, climas e formações naturais', 'Está localizado apenas no hemisfério norte', 'Não possui fronteiras terrestres', 'É formado por apenas uma região geográfica'], correct: 1, explanation: 'O Brasil tem dimensões continentais e grande diversidade natural, social e econômica entre suas regiões.' },
  { id: 'cg-q42', subjectId: 'gerais', topic: 'Geografia do Brasil', text: 'A Região Sudeste do Brasil é formada pelos estados:', options: ['São Paulo, Rio de Janeiro, Minas Gerais e Espírito Santo', 'São Paulo, Paraná, Santa Catarina e Rio Grande do Sul', 'Bahia, Sergipe, Alagoas e Pernambuco', 'Amazonas, Pará, Acre e Rondônia', 'Goiás, Mato Grosso, Tocantins e Maranhão'], correct: 0, explanation: 'A Região Sudeste é composta por São Paulo, Rio de Janeiro, Minas Gerais e Espírito Santo.' },
  { id: 'cg-q43', subjectId: 'gerais', topic: 'Geografia do Brasil', text: 'O processo de urbanização está relacionado:', options: ['Ao crescimento da população e das atividades nas cidades', 'À eliminação total das áreas rurais', 'À ausência de migração', 'Ao fim das atividades industriais', 'À redução obrigatória da população urbana'], correct: 0, explanation: 'Urbanização é o crescimento da população urbana e da importância das cidades na organização econômica e social.' },
  { id: 'cg-q44', subjectId: 'gerais', topic: 'Geografia de São Paulo', text: 'O estado de São Paulo se destaca no Brasil por:', options: ['Não possuir atividade industrial relevante', 'Ter forte participação econômica, industrial, tecnológica e de serviços', 'Depender exclusivamente da pesca artesanal', 'Não possuir cidades médias importantes', 'Ser isolado das principais redes de transporte'], correct: 1, explanation: 'São Paulo tem grande peso econômico no Brasil, com indústria, serviços, tecnologia, agropecuária moderna e infraestrutura logística.' },
  { id: 'cg-q45', subjectId: 'gerais', topic: 'Geografia de São Paulo', text: 'O rio Tietê é importante para o estado de São Paulo porque:', options: ['Corre apenas fora do território paulista', 'Tem relação histórica, econômica e ambiental com o estado', 'É um rio localizado exclusivamente na Amazônia', 'Não atravessa áreas urbanas', 'Não possui relevância ambiental'], correct: 1, explanation: 'O rio Tietê tem grande importância histórica, econômica e ambiental para São Paulo, atravessando áreas urbanas e do interior.' },
  { id: 'cg-q46', subjectId: 'gerais', topic: 'Constituição Federal', text: 'Segundo a Constituição Federal, todos são iguais perante a lei, sem distinção de qualquer natureza. Essa ideia expressa o princípio da:', options: ['Igualdade', 'Censura', 'Hereditariedade', 'Arbitrariedade', 'Irresponsabilidade'], correct: 0, explanation: 'A igualdade perante a lei é um princípio fundamental previsto no artigo 5º da Constituição Federal.' },
  { id: 'cg-q47', subjectId: 'gerais', topic: 'Constituição Federal', text: 'São exemplos de direitos sociais previstos na Constituição Federal:', options: ['Educação, saúde, trabalho e moradia', 'Censura, perseguição e confisco sem lei', 'Apenas propriedade privada absoluta', 'Exclusivamente direito ao voto', 'Somente liberdade de imprensa'], correct: 0, explanation: 'A Constituição prevê direitos sociais como educação, saúde, alimentação, trabalho, moradia, transporte, lazer, segurança, previdência social, proteção à maternidade e à infância e assistência aos desamparados.' },
  { id: 'cg-q48', subjectId: 'gerais', topic: 'Organização do Estado', text: 'No Brasil, os Poderes da União são:', options: ['Executivo, Legislativo e Judiciário', 'Militar, Religioso e Econômico', 'Federal, Estadual e Municipal', 'Policial, Fiscal e Privado', 'Administrativo, Comercial e Familiar'], correct: 0, explanation: 'A Constituição estabelece que são Poderes da União, independentes e harmônicos entre si, o Legislativo, o Executivo e o Judiciário.' },
  { id: 'cg-q49', subjectId: 'gerais', topic: 'Organização do Estado', text: 'A forma federativa do Brasil envolve a existência de:', options: ['Apenas governo federal', 'União, estados, Distrito Federal e municípios com autonomia política', 'Somente estados sem municípios', 'Monarquia centralizada', 'Ausência de Constituição'], correct: 1, explanation: 'A federação brasileira é formada pela União, estados, Distrito Federal e municípios, todos com autonomia nos termos da Constituição.' },
  { id: 'cg-q50', subjectId: 'gerais', topic: 'Segurança Pública', text: 'A segurança pública, conforme a Constituição Federal, é:', options: ['Dever do Estado, direito e responsabilidade de todos', 'Atividade exclusiva de empresas privadas', 'Tema sem relação com cidadania', 'Responsabilidade apenas dos municípios', 'Função proibida ao poder público'], correct: 0, explanation: 'A Constituição afirma que a segurança pública é dever do Estado, direito e responsabilidade de todos.' },
  { id: 'cg-q51', subjectId: 'gerais', topic: 'Segurança Pública', text: 'O policiamento comunitário busca principalmente:', options: ['Afastar a polícia da comunidade', 'Aproximar polícia e comunidade para prevenção e solução de problemas', 'Eliminar o diálogo com moradores', 'Substituir todas as políticas públicas', 'Atuar sem respeito à legalidade'], correct: 1, explanation: 'O policiamento comunitário valoriza aproximação, confiança, prevenção e cooperação entre polícia e sociedade.' },
  { id: 'cg-q52', subjectId: 'gerais', topic: 'Segurança Pública', text: 'A atuação policial deve estar sempre vinculada:', options: ['À legalidade, à técnica e ao respeito aos direitos fundamentais', 'À vontade pessoal do agente acima da lei', 'À punição sem processo legal', 'À ausência de controle público', 'Ao uso da força como primeira opção em qualquer situação'], correct: 0, explanation: 'A atuação policial deve respeitar a lei, a técnica profissional, a proporcionalidade e os direitos fundamentais.' },
  { id: 'cg-q53', subjectId: 'gerais', topic: 'Meio Ambiente e Sustentabilidade', text: 'Desenvolvimento sustentável significa:', options: ['Usar recursos naturais sem qualquer limite', 'Atender às necessidades atuais sem comprometer as futuras gerações', 'Eliminar toda atividade econômica', 'Priorizar apenas o lucro imediato', 'Ignorar impactos ambientais'], correct: 1, explanation: 'Desenvolvimento sustentável busca conciliar necessidades presentes, proteção ambiental e responsabilidade com as futuras gerações.' },
  { id: 'cg-q54', subjectId: 'gerais', topic: 'Meio Ambiente e Sustentabilidade', text: 'A coleta seletiva contribui para:', options: ['Misturar todos os resíduos', 'Separar materiais recicláveis e reduzir impactos ambientais', 'Aumentar o desperdício', 'Eliminar a reciclagem', 'Impedir o reaproveitamento de materiais'], correct: 1, explanation: 'A coleta seletiva separa resíduos recicláveis, favorece reaproveitamento e reduz impactos ambientais.' },
  { id: 'cg-q55', subjectId: 'gerais', topic: 'Meio Ambiente e Sustentabilidade', text: 'O efeito estufa é um fenômeno natural, mas sua intensificação está associada:', options: ['À redução total de gases na atmosfera', 'Ao aumento de gases de efeito estufa por atividades humanas', 'À inexistência de atividades industriais', 'À ausência de queimadas', 'Ao fim do consumo de combustíveis fósseis'], correct: 1, explanation: 'O efeito estufa natural ajuda a manter a temperatura da Terra, mas sua intensificação está ligada ao aumento de gases como CO₂ e metano.' },
  { id: 'cg-q56', subjectId: 'gerais', topic: 'Atualidades', text: 'Em temas de atualidades, a análise crítica exige:', options: ['Verificar fontes e contexto antes de aceitar uma informação', 'Compartilhar rapidamente qualquer boato', 'Ignorar dados e fatos', 'Aceitar apenas títulos chamativos', 'Evitar comparar informações'], correct: 0, explanation: 'Atualidades exige leitura crítica, verificação de fontes, contexto e consequências dos fatos.' },
  { id: 'cg-q57', subjectId: 'gerais', topic: 'Atualidades', text: 'A desinformação pode prejudicar a sociedade porque:', options: ['Melhora automaticamente o debate público', 'Pode manipular opiniões e dificultar decisões conscientes', 'Sempre apresenta dados científicos corretos', 'Substitui a necessidade de educação', 'Elimina conflitos sociais'], correct: 1, explanation: 'A desinformação pode confundir a população, manipular opiniões e prejudicar decisões individuais e coletivas.' },
  { id: 'cg-q58', subjectId: 'gerais', topic: 'Atualidades', text: 'Cidadania envolve:', options: ['Apenas possuir documentos pessoais', 'Direitos, deveres e participação na vida social e política', 'Somente pagar impostos', 'Obedecer sem questionar qualquer ordem ilegal', 'Não participar da comunidade'], correct: 1, explanation: 'Cidadania envolve exercício de direitos, cumprimento de deveres e participação responsável na sociedade.' },
  { id: 'cg-q59', subjectId: 'gerais', topic: 'Direitos e Garantias', text: 'O devido processo legal garante que:', options: ['Ninguém sofra restrições de direitos sem procedimento previsto em lei', 'Qualquer punição possa ocorrer sem defesa', 'A autoridade esteja acima da Constituição', 'A lei seja aplicada apenas a alguns cidadãos', 'A defesa seja sempre proibida'], correct: 0, explanation: 'O devido processo legal protege contra arbitrariedades e exige procedimento previsto em lei, com respeito à defesa e às garantias fundamentais.' },
  { id: 'cg-q60', subjectId: 'gerais', topic: 'Direitos e Garantias', text: 'A liberdade de expressão é um direito fundamental, mas deve ser exercida:', options: ['Com responsabilidade e respeito aos limites legais', 'Sem qualquer consequência em caso de crime', 'Para eliminar direitos de outras pessoas', 'Apenas por autoridades públicas', 'Sem relação com a Constituição'], correct: 0, explanation: 'A liberdade de expressão é protegida pela Constituição, mas não autoriza crimes, ameaças, calúnias ou violações de direitos.' },

  { id: 'cg-q61', subjectId: 'gerais', topic: 'História do Brasil', text: 'A Constituição de 1988 ficou conhecida como Constituição Cidadã porque:', options: ['Eliminou todos os direitos sociais', 'Ampliou direitos e garantias fundamentais após o período autoritário', 'Restaurou a monarquia no Brasil', 'Acabou com a separação dos Poderes', 'Proibiu a participação popular'], correct: 1, explanation: 'A Constituição de 1988 ampliou direitos fundamentais, sociais e mecanismos de participação democrática, por isso é chamada de Constituição Cidadã.' },
  { id: 'cg-q62', subjectId: 'gerais', topic: 'História do Brasil', text: 'O período da Ditadura Militar no Brasil começou em 1964 e foi marcado por:', options: ['Plena liberdade política sem restrições', 'Regime autoritário e restrição de direitos políticos', 'Volta imediata da monarquia', 'Ausência de censura e perseguições', 'Fim das Forças Armadas'], correct: 1, explanation: 'O regime militar iniciado em 1964 foi autoritário, com censura, perseguições políticas e restrições a direitos.' },
  { id: 'cg-q63', subjectId: 'gerais', topic: 'História do Brasil', text: 'A Era Vargas teve importância na história brasileira, entre outros fatores, por:', options: ['Impedir qualquer mudança trabalhista', 'Criar políticas de industrialização e legislação trabalhista', 'Extinguir o Estado brasileiro', 'Proibir a urbanização', 'Eliminar a administração pública'], correct: 1, explanation: 'A Era Vargas é associada à centralização política, incentivo à industrialização e consolidação de direitos trabalhistas.' },
  { id: 'cg-q64', subjectId: 'gerais', topic: 'História de São Paulo', text: 'A Revolução Constitucionalista de 1932, em São Paulo, teve como uma de suas bandeiras:', options: ['A defesa de uma nova Constituição', 'A volta do Brasil ao período colonial', 'A extinção dos estados brasileiros', 'A independência de Portugal', 'A criação da capital Brasília'], correct: 0, explanation: 'O movimento de 1932, em São Paulo, reivindicava principalmente a constitucionalização do país.' },
  { id: 'cg-q65', subjectId: 'gerais', topic: 'Geografia do Brasil', text: 'O Cerrado brasileiro é conhecido por:', options: ['Ser exclusivamente polar', 'Apresentar vegetação adaptada a períodos de seca e grande biodiversidade', 'Não possuir rios importantes', 'Ser idêntico à Caatinga em todos os aspectos', 'Ocupar apenas áreas litorâneas'], correct: 1, explanation: 'O Cerrado possui vegetação adaptada à sazonalidade climática, solos específicos e grande biodiversidade.' },
  { id: 'cg-q66', subjectId: 'gerais', topic: 'Geografia do Brasil', text: 'A Mata Atlântica é um bioma brasileiro que:', options: ['Nunca sofreu impacto humano', 'Está associado ao litoral e foi muito reduzido pela ocupação histórica', 'Existe apenas no interior do Amazonas', 'Não possui biodiversidade relevante', 'É formado exclusivamente por desertos'], correct: 1, explanation: 'A Mata Atlântica acompanha grande parte do litoral brasileiro e foi muito reduzida pela urbanização, agricultura e ocupação histórica.' },
  { id: 'cg-q67', subjectId: 'gerais', topic: 'Geografia de São Paulo', text: 'A Região Metropolitana de São Paulo é caracterizada por:', options: ['Baixa integração urbana', 'Grande concentração populacional, econômica e de serviços', 'Ausência de transporte e indústria', 'Predomínio exclusivo de atividades rurais isoladas', 'Não ter relação com municípios vizinhos'], correct: 1, explanation: 'A Região Metropolitana de São Paulo concentra população, serviços, indústria, comércio e fluxos intensos entre municípios.' },
  { id: 'cg-q68', subjectId: 'gerais', topic: 'Geografia de São Paulo', text: 'No interior paulista, a presença de rodovias, ferrovias e centros logísticos contribui para:', options: ['Isolar economicamente as cidades', 'Integrar produção, comércio e deslocamentos regionais', 'Eliminar a atividade industrial', 'Impedir o transporte de mercadorias', 'Reduzir a importância das cidades médias'], correct: 1, explanation: 'A infraestrutura de transporte e logística integra regiões, facilita circulação de mercadorias e fortalece a economia paulista.' },
  { id: 'cg-q69', subjectId: 'gerais', topic: 'Constituição Federal', text: 'O direito à vida, à liberdade, à igualdade, à segurança e à propriedade está previsto principalmente:', options: ['No artigo 5º da Constituição Federal', 'No Código de Trânsito Brasileiro apenas', 'Em normas privadas sem valor público', 'Somente em leis municipais', 'Apenas em regulamentos escolares'], correct: 0, explanation: 'O artigo 5º da Constituição Federal reúne direitos e garantias fundamentais, incluindo vida, liberdade, igualdade, segurança e propriedade.' },
  { id: 'cg-q70', subjectId: 'gerais', topic: 'Constituição Federal', text: 'A inviolabilidade da intimidade, da vida privada, da honra e da imagem das pessoas protege:', options: ['A exposição ilimitada de dados pessoais', 'Direitos da personalidade e a dignidade humana', 'A censura obrigatória de toda opinião', 'A ausência de responsabilidade civil', 'A violação de correspondência sem ordem legal'], correct: 1, explanation: 'A Constituição protege intimidade, vida privada, honra e imagem, garantindo indenização em caso de dano material ou moral.' },
  { id: 'cg-q71', subjectId: 'gerais', topic: 'Organização do Estado', text: 'A autonomia dos municípios na federação brasileira significa que eles podem:', options: ['Agir fora da Constituição', 'Organizar seus assuntos locais dentro dos limites constitucionais', 'Criar moeda própria', 'Extinguir direitos fundamentais', 'Substituir o Poder Judiciário'], correct: 1, explanation: 'Municípios têm autonomia política, administrativa e financeira, mas devem respeitar a Constituição e as leis.' },
  { id: 'cg-q72', subjectId: 'gerais', topic: 'Organização do Estado', text: 'O Poder Judiciário tem como função típica:', options: ['Julgar conflitos aplicando a lei', 'Criar moeda nacional', 'Administrar diretamente todos os serviços públicos', 'Comandar exclusivamente a política econômica', 'Elaborar o orçamento municipal sozinho'], correct: 0, explanation: 'A função típica do Judiciário é julgar conflitos e aplicar o Direito aos casos concretos.' },
  { id: 'cg-q73', subjectId: 'gerais', topic: 'Segurança Pública', text: 'A prevenção criminal envolve:', options: ['Apenas agir depois que o crime ocorre', 'Ações para reduzir riscos, oportunidades e fatores que favorecem delitos', 'Ignorar a comunidade', 'Eliminar políticas sociais', 'Desconsiderar dados e planejamento'], correct: 1, explanation: 'Prevenção criminal busca reduzir riscos e oportunidades para o crime por meio de planejamento, presença, integração e políticas públicas.' },
  { id: 'cg-q74', subjectId: 'gerais', topic: 'Segurança Pública', text: 'O uso progressivo da força está relacionado:', options: ['Ao emprego de qualquer força sem critério', 'À proporcionalidade e adequação da resposta policial à situação', 'À dispensa de treinamento técnico', 'À punição antes do julgamento', 'À ausência de responsabilidade funcional'], correct: 1, explanation: 'O uso progressivo da força exige avaliação, proporcionalidade, necessidade e adequação conforme a situação enfrentada.' },
  { id: 'cg-q75', subjectId: 'gerais', topic: 'Meio Ambiente e Sustentabilidade', text: 'A preservação de áreas verdes urbanas contribui para:', options: ['Piorar obrigatoriamente a qualidade do ar', 'Reduzir ilhas de calor e melhorar a qualidade de vida', 'Eliminar a biodiversidade', 'Impedir qualquer lazer público', 'Aumentar necessariamente a poluição'], correct: 1, explanation: 'Áreas verdes ajudam na regulação térmica, qualidade do ar, drenagem, lazer e bem-estar da população.' },
  { id: 'cg-q76', subjectId: 'gerais', topic: 'Meio Ambiente e Sustentabilidade', text: 'O consumo consciente está relacionado:', options: ['Ao desperdício sem limites', 'À escolha responsável de produtos e redução de impactos ambientais', 'À compra impulsiva de tudo que aparece', 'À impossibilidade de reciclar', 'À eliminação da responsabilidade social'], correct: 1, explanation: 'Consumo consciente envolve reduzir desperdícios, avaliar impactos e fazer escolhas mais responsáveis.' },
  { id: 'cg-q77', subjectId: 'gerais', topic: 'Atualidades', text: 'Ao analisar uma notícia, uma atitude adequada é:', options: ['Verificar fonte, data, autoria e contexto', 'Confiar apenas no título', 'Compartilhar antes de ler', 'Ignorar dados oficiais', 'Aceitar qualquer imagem sem checagem'], correct: 0, explanation: 'Uma análise crítica exige verificar fonte, data, autoria, contexto e coerência das informações.' },
  { id: 'cg-q78', subjectId: 'gerais', topic: 'Atualidades', text: 'A polarização nas redes sociais pode dificultar o debate público quando:', options: ['Estimula escuta e análise cuidadosa', 'Reduz o diálogo e transforma divergências em hostilidade', 'Amplia sempre a compreensão dos fatos', 'Impede a desinformação automaticamente', 'Substitui conflitos por consenso total'], correct: 1, explanation: 'A polarização pode reduzir o diálogo, aumentar hostilidade e dificultar análise equilibrada dos fatos.' },
  { id: 'cg-q79', subjectId: 'gerais', topic: 'Direitos e Garantias', text: 'A presunção de inocência significa que:', options: ['Ninguém será considerado culpado até decisão condenatória definitiva', 'Toda pessoa investigada já é culpada', 'A defesa é desnecessária', 'A acusação não precisa provar nada', 'A pena vem antes do processo'], correct: 0, explanation: 'A presunção de inocência protege o indivíduo até o trânsito em julgado de sentença penal condenatória.' },
  { id: 'cg-q80', subjectId: 'gerais', topic: 'Direitos e Garantias', text: 'O habeas corpus é uma garantia constitucional voltada principalmente à proteção:', options: ['Da liberdade de locomoção', 'Do direito de propriedade intelectual apenas', 'Do sigilo bancário empresarial', 'Da organização de partidos políticos', 'Do orçamento público'], correct: 0, explanation: 'O habeas corpus protege a liberdade de locomoção contra ilegalidade ou abuso de poder.' },

  { id: 'cg-q81', subjectId: 'gerais', topic: 'História do Brasil', text: 'A Proclamação da República no Brasil ocorreu em 1889 e representou:', options: ['O fim do regime monárquico e o início do regime republicano', 'A independência do Brasil em relação a Portugal', 'A abolição da escravidão', 'A criação da Constituição de 1988', 'A transferência da capital para Brasília'], correct: 0, explanation: 'A Proclamação da República, em 15 de novembro de 1889, encerrou o Império e iniciou o regime republicano no Brasil.' },
  { id: 'cg-q82', subjectId: 'gerais', topic: 'História do Brasil', text: 'Na Primeira República, o chamado voto de cabresto estava relacionado:', options: ['Ao voto plenamente livre e secreto', 'Ao controle político local sobre eleitores', 'À participação feminina obrigatória', 'À eleição direta para presidente com urna eletrônica', 'À ausência de coronelismo'], correct: 1, explanation: 'O voto de cabresto era uma prática de controle eleitoral ligada ao coronelismo e ao poder local das oligarquias.' },
  { id: 'cg-q83', subjectId: 'gerais', topic: 'História do Brasil', text: 'O movimento Diretas Já, na década de 1980, defendia:', options: ['Eleições diretas para presidente da República', 'A volta do Brasil ao período colonial', 'A extinção dos partidos políticos', 'A continuidade da monarquia', 'A proibição da participação popular'], correct: 0, explanation: 'O movimento Diretas Já mobilizou a sociedade pela volta das eleições diretas para presidente durante a redemocratização.' },
  { id: 'cg-q84', subjectId: 'gerais', topic: 'História de São Paulo', text: 'A industrialização paulista foi favorecida, entre outros fatores, por:', options: ['Capital acumulado com o café, infraestrutura e mercado consumidor', 'Ausência de ferrovias e de mão de obra', 'Isolamento total do estado', 'Fim das cidades médias', 'Proibição de investimentos urbanos'], correct: 0, explanation: 'A economia cafeeira, a infraestrutura de transporte, a imigração, o mercado consumidor e o capital disponível favoreceram a industrialização de São Paulo.' },
  { id: 'cg-q85', subjectId: 'gerais', topic: 'Geografia do Brasil', text: 'A maior parte do território brasileiro localiza-se:', options: ['No Hemisfério Sul', 'No Hemisfério Norte', 'Na zona polar ártica', 'Apenas na Europa', 'No continente asiático'], correct: 0, explanation: 'A maior parte do Brasil está localizada no Hemisfério Sul, embora uma pequena parte do território esteja no Hemisfério Norte.' },
  { id: 'cg-q86', subjectId: 'gerais', topic: 'Geografia do Brasil', text: 'A Região Centro-Oeste é formada por:', options: ['Goiás, Mato Grosso, Mato Grosso do Sul e Distrito Federal', 'São Paulo, Minas Gerais, Rio de Janeiro e Espírito Santo', 'Paraná, Santa Catarina e Rio Grande do Sul', 'Bahia, Sergipe, Alagoas e Pernambuco', 'Amazonas, Pará, Acre e Roraima'], correct: 0, explanation: 'A Região Centro-Oeste é composta por Goiás, Mato Grosso, Mato Grosso do Sul e Distrito Federal.' },
  { id: 'cg-q87', subjectId: 'gerais', topic: 'Geografia de São Paulo', text: 'O Porto de Santos é importante para o Brasil porque:', options: ['Tem grande relevância logística e comercial para exportações e importações', 'Está localizado no interior do Amazonas', 'É usado apenas para pesca artesanal sem impacto econômico', 'Não possui relação com comércio exterior', 'Substitui todos os aeroportos do país'], correct: 0, explanation: 'O Porto de Santos, em São Paulo, é um dos principais complexos portuários do Brasil e tem grande importância econômica e logística.' },
  { id: 'cg-q88', subjectId: 'gerais', topic: 'Geografia de São Paulo', text: 'A Macrometrópole Paulista está relacionada:', options: ['À integração entre regiões urbanas e econômicas do estado', 'Ao isolamento rural de todo o estado', 'À ausência de infraestrutura', 'A uma área sem circulação de pessoas e mercadorias', 'A um bioma exclusivo do litoral norte'], correct: 0, explanation: 'A Macrometrópole Paulista envolve integração urbana, econômica e logística entre regiões como São Paulo, Campinas, Sorocaba, Baixada Santista e Vale do Paraíba.' },
  { id: 'cg-q89', subjectId: 'gerais', topic: 'Constituição Federal', text: 'A casa é asilo inviolável do indivíduo, segundo a Constituição Federal. Isso significa que:', options: ['A entrada forçada no domicílio depende de hipóteses legais específicas', 'Qualquer pessoa pode entrar a qualquer momento', 'A polícia nunca pode entrar em nenhuma situação', 'O domicílio não tem proteção constitucional', 'A inviolabilidade vale apenas para prédios públicos'], correct: 0, explanation: 'A Constituição protege o domicílio, mas admite entrada em situações legais específicas, como flagrante delito, desastre, socorro ou determinação judicial durante o dia.' },
  { id: 'cg-q90', subjectId: 'gerais', topic: 'Constituição Federal', text: 'O direito de reunião, previsto constitucionalmente, permite que pessoas se reúnam pacificamente:', options: ['Sem armas, em locais abertos ao público, observadas as condições legais', 'Somente com autorização de partido político', 'Apenas dentro de prédios militares', 'Sempre de forma secreta e armada', 'Sem qualquer limite em qualquer circunstância'], correct: 0, explanation: 'A Constituição protege reunião pacífica, sem armas, em locais abertos ao público, desde que não frustre outra reunião anteriormente convocada e com aviso prévio à autoridade competente.' },
  { id: 'cg-q91', subjectId: 'gerais', topic: 'Organização do Estado', text: 'A competência dos estados na federação brasileira inclui:', options: ['Organizar-se por Constituição estadual, respeitada a Constituição Federal', 'Criar moeda própria', 'Extinguir municípios sem regra legal', 'Desobedecer direitos fundamentais', 'Substituir a União em todas as funções'], correct: 0, explanation: 'Os estados têm autonomia e podem organizar-se por suas Constituições estaduais, respeitando os princípios da Constituição Federal.' },
  { id: 'cg-q92', subjectId: 'gerais', topic: 'Organização do Estado', text: 'O chefe do Poder Executivo estadual é o:', options: ['Governador', 'Prefeito', 'Presidente da Câmara Municipal', 'Vereador', 'Ministro do Supremo Tribunal Federal'], correct: 0, explanation: 'Nos estados, o Poder Executivo é exercido pelo governador.' },
  { id: 'cg-q93', subjectId: 'gerais', topic: 'Segurança Pública', text: 'A preservação da ordem pública envolve:', options: ['Atuação preventiva e repressiva dentro da legalidade', 'Apenas ações sem planejamento', 'Desrespeito obrigatório aos direitos fundamentais', 'Ausência de controle das instituições', 'Substituição do Poder Judiciário pela polícia'], correct: 0, explanation: 'A preservação da ordem pública exige atuação legal, técnica, planejada, preventiva e repressiva quando necessário.' },
  { id: 'cg-q94', subjectId: 'gerais', topic: 'Segurança Pública', text: 'A integração entre órgãos de segurança e outras políticas públicas é importante porque:', options: ['Problemas de segurança também têm causas sociais, urbanas e econômicas', 'A segurança pública não tem relação com a sociedade', 'Toda ocorrência se resolve apenas com punição imediata', 'Planejamento é desnecessário', 'Dados e estatísticas devem ser ignorados'], correct: 0, explanation: 'Segurança pública pode envolver policiamento, urbanismo, educação, assistência social, saúde, iluminação, transporte e outras ações integradas.' },
  { id: 'cg-q95', subjectId: 'gerais', topic: 'Meio Ambiente e Sustentabilidade', text: 'A poluição dos rios pode gerar como consequência:', options: ['Prejuízos à saúde, ao abastecimento, à fauna e à flora', 'Melhoria automática da água potável', 'Aumento obrigatório da biodiversidade', 'Fim da necessidade de saneamento', 'Redução de todos os problemas urbanos'], correct: 0, explanation: 'A poluição hídrica afeta saúde pública, abastecimento, ecossistemas e qualidade de vida.' },
  { id: 'cg-q96', subjectId: 'gerais', topic: 'Meio Ambiente e Sustentabilidade', text: 'A educação ambiental busca:', options: ['Formar consciência crítica sobre preservação, consumo e responsabilidade socioambiental', 'Incentivar desperdício de água e energia', 'Eliminar a participação social', 'Impedir a reciclagem', 'Separar cidadania de meio ambiente'], correct: 0, explanation: 'A educação ambiental promove consciência, responsabilidade, participação e práticas voltadas à proteção ambiental.' },
  { id: 'cg-q97', subjectId: 'gerais', topic: 'Atualidades', text: 'O uso responsável da tecnologia envolve:', options: ['Segurança digital, respeito à privacidade e avaliação crítica de informações', 'Compartilhamento de senhas pessoais', 'Aceitação de todos os links recebidos', 'Divulgação de dados sensíveis sem cuidado', 'Desprezo por fontes confiáveis'], correct: 0, explanation: 'Tecnologia deve ser usada com segurança, cuidado com dados pessoais, respeito à privacidade e verificação de informações.' },
  { id: 'cg-q98', subjectId: 'gerais', topic: 'Atualidades', text: 'Em debates públicos, dados estatísticos devem ser analisados considerando:', options: ['Fonte, metodologia, data e contexto', 'Apenas a aparência do gráfico', 'Somente opiniões pessoais', 'Títulos de redes sociais', 'Preferências individuais sem evidência'], correct: 0, explanation: 'Dados precisam ser avaliados com atenção à fonte, metodologia, período, contexto e possíveis limitações.' },
  { id: 'cg-q99', subjectId: 'gerais', topic: 'Direitos e Garantias', text: 'O mandado de segurança protege:', options: ['Direito líquido e certo não amparado por habeas corpus ou habeas data', 'Apenas liberdade de locomoção', 'Somente crimes militares', 'Qualquer interesse sem prova documental', 'Exclusivamente relações entre empresas privadas'], correct: 0, explanation: 'O mandado de segurança protege direito líquido e certo contra ilegalidade ou abuso de poder, quando não for caso de habeas corpus ou habeas data.' },
  { id: 'cg-q100', subjectId: 'gerais', topic: 'Direitos e Garantias', text: 'O habeas data é uma garantia constitucional utilizada para:', options: ['Acessar ou corrigir informações pessoais em bancos de dados de entidades governamentais ou de caráter público', 'Criar novas leis penais', 'Substituir o habeas corpus em prisões ilegais', 'Anular qualquer eleição', 'Autorizar censura prévia'], correct: 0, explanation: 'O habeas data permite conhecer ou retificar informações pessoais constantes de registros ou bancos de dados de entidades governamentais ou de caráter público.' },



  // ====== INFORMÁTICA (100 questões) ======
  { id: 'inf-q01', subjectId: 'informatica', topic: 'Hardware e Software', text: 'A memória RAM é do tipo:', options: ['Permanente', 'Temporária/volátil', 'Secundária', 'ROM', 'De armazenamento em massa'], correct: 1, explanation: 'A memória RAM (Random Access Memory) é volátil, ou seja, perde seus dados quando o computador é desligado.' },
  { id: 'inf-q02', subjectId: 'informatica', topic: 'Windows', text: 'O atalho de teclado para copiar um texto no Windows é:', options: ['Ctrl+V', 'Ctrl+X', 'Ctrl+C', 'Ctrl+Z', 'Ctrl+P'], correct: 2, explanation: 'Ctrl+C é o atalho para copiar. Ctrl+V = colar, Ctrl+X = recortar, Ctrl+Z = desfazer, Ctrl+P = imprimir.' },
  { id: 'inf-q03', subjectId: 'informatica', topic: 'Microsoft Excel', text: 'No Excel, a fórmula =SOMA(A1:A5) realiza:', options: ['A multiplicação dos valores de A1 a A5', 'A soma dos valores de A1 a A5', 'A média dos valores de A1 a A5', 'A contagem de células preenchidas', 'O valor máximo no intervalo'], correct: 1, explanation: 'A função SOMA adiciona todos os valores no intervalo especificado, no caso de A1 até A5.' },
  { id: 'inf-q04', subjectId: 'informatica', topic: 'Internet e Navegadores', text: 'O protocolo HTTPS é mais seguro que o HTTP porque utiliza:', options: ['Cookies', 'Criptografia SSL/TLS', 'Cache', 'Firewall', 'Antivírus'], correct: 1, explanation: 'O HTTPS usa criptografia SSL/TLS para proteger a comunicação entre navegador e servidor, tornando os dados mais seguros.' },
  { id: 'inf-q05', subjectId: 'informatica', topic: 'Segurança da Informação', text: 'Phishing é um tipo de golpe que consiste em:', options: ['Danificar o hardware do computador', 'Enganar o usuário para obter dados pessoais', 'Infectar o computador com vírus', 'Bloquear o acesso à internet', 'Monitorar o teclado do usuário'], correct: 1, explanation: 'Phishing é uma técnica de engenharia social em que o criminoso se passa por uma entidade confiável para roubar dados pessoais como senhas e dados bancários.' },
  { id: 'inf-q06', subjectId: 'informatica', topic: 'Microsoft Word', text: 'Para inserir uma quebra de página no Word, o atalho é:', options: ['Ctrl+Enter', 'Ctrl+Shift+Enter', 'Ctrl+Page Down', 'Alt+Enter', 'Ctrl+End'], correct: 0, explanation: 'Ctrl+Enter insere uma quebra de página no Microsoft Word.' },
  { id: 'inf-q07', subjectId: 'informatica', topic: 'E-mail e Comunicação Digital', text: 'O campo CCO (Com Cópia Oculta) serve para:', options: ['Enviar cópia visível a todos', 'Ocultar os destinatários entre si', 'Encaminhar e-mails automaticamente', 'Responder a todos', 'Arquivar mensagens'], correct: 1, explanation: 'O CCO (BCC) permite enviar e-mails para múltiplos destinatários sem que eles vejam os endereços uns dos outros.' },
  { id: 'inf-q08', subjectId: 'informatica', topic: 'Redes de Computadores', text: 'O DNS (Domain Name System) tem a função de:', options: ['Proteger contra vírus', 'Traduzir nomes de domínio em endereços IP', 'Acelerar a internet', 'Comprimir arquivos', 'Fazer backup de dados'], correct: 1, explanation: 'O DNS traduz nomes de domínio (ex: google.com) em endereços IP (ex: 142.250.185.78), facilitando o acesso a sites.' },
  { id: 'inf-q09', subjectId: 'informatica', topic: 'Microsoft Excel', text: 'A função =SE(A1>10;"Aprovado";"Reprovado") no Excel retornará "Aprovado" se A1 contiver:', options: ['5', '10', '8', '15', 'Nenhuma das anteriores'], correct: 3, explanation: 'A função SE verifica a condição A1>10. Se verdadeiro, retorna "Aprovado". Apenas 15 é maior que 10 entre as opções.' },
  { id: 'inf-q10', subjectId: 'informatica', topic: 'Segurança da Informação', text: 'A LGPD (Lei Geral de Proteção de Dados) tem como objetivo principal:', options: ['Proteger softwares contra pirataria', 'Proteger dados pessoais dos cidadãos', 'Regular o comércio eletrônico', 'Combater hackers', 'Controlar o acesso à internet'], correct: 1, explanation: 'A LGPD visa proteger os dados pessoais dos cidadãos, estabelecendo regras para coleta, tratamento e armazenamento de informações pessoais.' },


  { id: 'inf-q11', subjectId: 'informatica', topic: 'Windows', text: 'No Windows, a combinação de teclas Alt + Tab é utilizada para:', options: ['Fechar o programa atual', 'Alternar entre janelas abertas', 'Abrir o menu iniciar', 'Bloquear o computador', 'Renomear arquivos'], correct: 1, explanation: 'Alt + Tab permite alternar rapidamente entre janelas e programas abertos no Windows.' },
  { id: 'inf-q12', subjectId: 'informatica', topic: 'Segurança da Informação', text: 'Uma senha forte deve conter, preferencialmente:', options: ['Apenas números repetidos', 'Nome próprio e data de nascimento', 'Letras, números e caracteres especiais', 'Somente letras minúsculas', 'A palavra senha seguida de números'], correct: 2, explanation: 'Senhas fortes combinam letras maiúsculas e minúsculas, números e caracteres especiais, evitando informações pessoais previsíveis.' },
  { id: 'inf-q13', subjectId: 'informatica', topic: 'Internet e Navegadores', text: 'O navegador de internet é um programa utilizado para:', options: ['Editar planilhas exclusivamente', 'Acessar páginas e serviços da web', 'Formatar discos rígidos', 'Criar circuitos eletrônicos', 'Substituir o sistema operacional'], correct: 1, explanation: 'Navegadores como Chrome, Edge e Firefox permitem acessar páginas, sistemas e serviços disponíveis na internet.' },
  { id: 'inf-q14', subjectId: 'informatica', topic: 'E-mail e Comunicação Digital', text: 'Ao anexar um arquivo em uma mensagem de e-mail, o usuário está:', options: ['Apagando o conteúdo da mensagem', 'Enviando um arquivo junto com a mensagem', 'Criptografando automaticamente todo o computador', 'Bloqueando o destinatário', 'Criando uma nova conta de e-mail'], correct: 1, explanation: 'Anexar significa incluir um arquivo, como PDF, imagem ou documento, junto com a mensagem enviada.' },
  { id: 'inf-q15', subjectId: 'informatica', topic: 'Microsoft Excel', text: 'Em uma planilha eletrônica, a célula B3 representa:', options: ['Linha B e coluna 3', 'Coluna B e linha 3', 'Página B e parágrafo 3', 'Arquivo B com 3 abas', 'Fórmula de soma automática'], correct: 1, explanation: 'Em planilhas, a letra indica a coluna e o número indica a linha. Assim, B3 é coluna B, linha 3.' },
  { id: 'inf-q16', subjectId: 'informatica', topic: 'Segurança da Informação', text: 'A principal finalidade do backup é:', options: ['Aumentar o brilho da tela', 'Criar cópias de segurança dos dados', 'Melhorar a cor da impressão', 'Trocar automaticamente a senha do usuário', 'Excluir arquivos duplicados sem confirmação'], correct: 1, explanation: 'Backup é a cópia de segurança feita para recuperar dados em caso de falha, perda, exclusão acidental ou ataque.' },
  { id: 'inf-q17', subjectId: 'informatica', topic: 'Segurança da Informação', text: 'Malware é:', options: ['Um tipo de monitor', 'Um programa ou código malicioso', 'Uma função de planilha', 'Um cabo de rede', 'Um editor de apresentações'], correct: 1, explanation: 'Malware é qualquer software malicioso criado para causar dano, roubar informações, espionar ou comprometer sistemas.' },
  { id: 'inf-q18', subjectId: 'informatica', topic: 'Ferramentas Office e Nuvem', text: 'Um exemplo de serviço de armazenamento em nuvem é:', options: ['Google Drive', 'Teclado virtual', 'Painel de controle', 'Lixeira do Windows', 'Gerenciador de tarefas'], correct: 0, explanation: 'Google Drive é um serviço de armazenamento em nuvem, permitindo guardar e acessar arquivos pela internet.' },
  { id: 'inf-q19', subjectId: 'informatica', topic: 'Microsoft Word', text: 'O LibreOffice Writer é utilizado principalmente para:', options: ['Editar textos e documentos', 'Criar bancos de dados físicos', 'Substituir o processador do computador', 'Medir velocidade da internet', 'Compactar memória RAM'], correct: 0, explanation: 'O Writer é o editor de textos do pacote LibreOffice, semelhante ao Microsoft Word.' },
  { id: 'inf-q20', subjectId: 'informatica', topic: 'Redes de Computadores', text: 'Em uma rede Wi-Fi doméstica, o roteador tem como uma de suas funções:', options: ['Distribuir conexão entre dispositivos', 'Imprimir documentos sem papel', 'Apagar vírus automaticamente', 'Criar textos no formato DOCX', 'Substituir a memória do computador'], correct: 0, explanation: 'O roteador permite compartilhar a conexão de rede entre dispositivos, como celulares, computadores e impressoras.' },


  { id: 'inf-q21', subjectId: 'informatica', topic: 'Hardware e Software', text: 'Assinale a alternativa que apresenta apenas exemplos de hardware:', options: ['Windows, Word e Excel', 'Mouse, teclado e monitor', 'Chrome, Edge e Firefox', 'Antivírus, firewall e backup', 'Google Drive, OneDrive e iCloud'], correct: 1, explanation: 'Hardware é a parte física do computador, como mouse, teclado, monitor, placa-mãe, processador e impressora.' },
  { id: 'inf-q22', subjectId: 'informatica', topic: 'Windows', text: 'No Windows, a Lixeira é utilizada principalmente para:', options: ['Guardar arquivos excluídos temporariamente', 'Aumentar a memória RAM', 'Proteger contra vírus automaticamente', 'Criar planilhas eletrônicas', 'Atualizar drivers sem internet'], correct: 0, explanation: 'A Lixeira armazena temporariamente arquivos excluídos, permitindo restauração antes da exclusão definitiva.' },
  { id: 'inf-q23', subjectId: 'informatica', topic: 'Microsoft Excel', text: 'Em uma planilha, a fórmula =MÉDIA(A1:A4) calcula:', options: ['A soma dos valores de A1 até A4', 'O maior valor entre A1 e A4', 'A média dos valores de A1 até A4', 'A quantidade de letras no intervalo', 'A formatação das células'], correct: 2, explanation: 'A função MÉDIA calcula a média aritmética dos valores no intervalo indicado.' },
  { id: 'inf-q24', subjectId: 'informatica', topic: 'Segurança da Informação', text: 'Ransomware é um tipo de malware que:', options: ['Organiza arquivos em pastas', 'Bloqueia ou sequestra dados e pode exigir resgate', 'Aumenta a velocidade da internet', 'Cria apresentações automaticamente', 'Transforma arquivos em PDF'], correct: 1, explanation: 'Ransomware é um malware que bloqueia ou criptografa dados da vítima e geralmente exige pagamento para liberá-los.' },
  { id: 'inf-q25', subjectId: 'informatica', topic: 'Redes de Computadores', text: 'O DHCP tem como função:', options: ['Distribuir endereços IP automaticamente na rede', 'Criar textos no Word', 'Apagar cookies do navegador', 'Compactar imagens', 'Criar senhas fortes'], correct: 0, explanation: 'O DHCP distribui automaticamente endereços IP e outras configurações de rede para dispositivos conectados.' },


  { id: 'inf-q26', subjectId: 'informatica', topic: 'E-mail e Comunicação Digital', text: 'No envio de e-mail, o campo CCO deve ser usado quando se deseja:', options: ['Enviar cópia visível para todos', 'Ocultar os destinatários que recebem cópia', 'Apagar automaticamente os anexos', 'Responder somente ao remetente', 'Transformar a mensagem em spam'], correct: 1, explanation: 'CCO significa cópia oculta. Os destinatários inseridos nesse campo recebem a mensagem, mas não ficam visíveis aos demais.' },
  { id: 'inf-q27', subjectId: 'informatica', topic: 'Internet e Navegadores', text: 'A navegação anônima ou privada em um navegador:', options: ['Torna o usuário invisível para todos os sites', 'Impede completamente a ação de vírus', 'Evita salvar histórico local daquela sessão no navegador', 'Substitui o uso de antivírus', 'Garante que nenhum provedor veja a conexão'], correct: 2, explanation: 'A navegação privada evita salvar localmente histórico, cookies e dados daquela sessão, mas não torna o usuário invisível na internet.' },
  { id: 'inf-q28', subjectId: 'informatica', topic: 'Sistemas Operacionais Móveis', text: 'Ao instalar um aplicativo no celular, uma permissão sensível que deve ser analisada com cuidado é:', options: ['Alterar o brilho da tela', 'Acessar localização, câmera ou microfone', 'Mudar o papel de parede', 'Organizar os ícones da tela inicial', 'Ativar o modo escuro'], correct: 1, explanation: 'Localização, câmera e microfone são permissões sensíveis, pois envolvem privacidade e podem expor dados do usuário.' },
  { id: 'inf-q29', subjectId: 'informatica', topic: 'Ferramentas Office e Nuvem', text: 'No PowerPoint, a diferença correta entre transição e animação é:', options: ['Transição ocorre entre slides; animação ocorre em objetos do slide', 'Transição ocorre em palavras; animação ocorre entre arquivos', 'Transição serve para salvar; animação serve para imprimir', 'Transição apaga slides; animação bloqueia edição', 'Não existe diferença entre elas'], correct: 0, explanation: 'Transição é o efeito de passagem entre slides. Animação é o efeito aplicado a elementos dentro de um slide.' },
  { id: 'inf-q30', subjectId: 'informatica', topic: 'Microsoft Word', text: 'No Microsoft Word, o recurso de cabeçalho é utilizado para inserir conteúdo:', options: ['Apenas no rodapé da última página', 'No topo das páginas do documento', 'Somente dentro de tabelas', 'Apenas em imagens', 'Exclusivamente em planilhas'], correct: 1, explanation: 'Cabeçalho é a área superior da página. Pode conter informações como título, nome, data ou numeração associada ao documento.' },

  // ====== INFORMÁTICA — GOOGLE WORKSPACE / MICROSOFT TEAMS (complemento; prova oficial: 5 questões) ======

  { id: 'inf-q31', subjectId: 'informatica', topic: 'Google Workspace', text: 'No Google Docs, ao compartilhar um documento com permissão de "comentador", o usuário poderá:', options: ['Editar livremente todo o texto', 'Comentar sem alterar diretamente o conteúdo principal', 'Excluir o documento da conta do proprietário', 'Alterar o proprietário do arquivo', 'Impedir o acesso de todos os outros usuários'], correct: 1, explanation: 'A permissão de comentador permite sugerir ou comentar, mas não editar diretamente o conteúdo principal como um editor.' },
  { id: 'inf-q32', subjectId: 'informatica', topic: 'Google Workspace', text: 'No Google Sheets ou no Excel, a referência $A$1 em uma fórmula indica:', options: ['Referência relativa de linha e coluna', 'Referência absoluta de coluna e linha', 'Erro de fórmula', 'Intervalo entre A e 1', 'Texto comum sem função'], correct: 1, explanation: 'O símbolo $ fixa coluna e linha. Assim, $A$1 permanece travado ao copiar a fórmula para outras células.' },
  { id: 'inf-q33', subjectId: 'informatica', topic: 'Google Workspace', text: 'No Google Meet, o ato de fixar um participante geralmente serve para:', options: ['Destacar aquele participante na tela do próprio usuário', 'Remover o participante da reunião', 'Enviar automaticamente um e-mail para todos', 'Bloquear o microfone de todos os presentes', 'Alterar a senha da conta Google'], correct: 0, explanation: 'Fixar um participante destaca sua imagem na visualização do próprio usuário. Não significa remover, bloquear ou controlar a reunião inteira.' },
  { id: 'inf-q34', subjectId: 'informatica', topic: 'Microsoft Teams', text: 'No Microsoft Teams, a diferença correta entre equipe e canal é:', options: ['Equipe é um arquivo; canal é uma fórmula', 'Equipe é um grupo maior de trabalho; canal organiza conversas e arquivos por tema dentro da equipe', 'Canal é sempre privado e equipe é sempre pública', 'Equipe serve apenas para chamadas telefônicas', 'Canal substitui o sistema operacional'], correct: 1, explanation: 'No Teams, a equipe reúne pessoas de um grupo ou projeto, enquanto canais organizam conversas, arquivos e atividades por tema ou área.' },
  { id: 'inf-q35', subjectId: 'informatica', topic: 'Microsoft Teams', text: 'Durante uma reunião no Microsoft Teams, o recurso de compartilhamento de tela permite:', options: ['Exibir a tela ou uma janela para os participantes', 'Formatar automaticamente uma planilha', 'Apagar os arquivos dos demais usuários', 'Criar uma senha do Windows', 'Desinstalar aplicativos do computador'], correct: 0, explanation: 'O compartilhamento de tela permite mostrar a tela inteira ou uma janela específica aos participantes da reunião.' },

  { id: 'inf-q36', subjectId: 'informatica', topic: 'Hardware e Software', text: 'A placa-mãe de um computador tem como função principal:', options: ['Armazenar arquivos na nuvem', 'Interligar e permitir a comunicação entre os componentes do computador', 'Criar textos automaticamente', 'Proteger o computador contra quedas de energia sem equipamento externo', 'Substituir o sistema operacional'], correct: 1, explanation: 'A placa-mãe conecta processador, memória, armazenamento, placas e outros componentes, permitindo a comunicação entre eles.' },
  { id: 'inf-q37', subjectId: 'informatica', topic: 'Hardware e Software', text: 'O SSD é um dispositivo utilizado principalmente para:', options: ['Processar cálculos gráficos', 'Armazenar dados de forma permanente', 'Exibir imagens na tela', 'Fornecer energia ao computador', 'Controlar a velocidade da internet'], correct: 1, explanation: 'O SSD é uma unidade de armazenamento permanente, geralmente mais rápida que o HD tradicional.' },
  { id: 'inf-q38', subjectId: 'informatica', topic: 'Windows', text: 'No Windows, o Gerenciador de Tarefas permite:', options: ['Visualizar processos e desempenho do sistema', 'Criar fórmulas de planilha', 'Editar imagens em vetor', 'Enviar e-mails automaticamente', 'Formatar documentos jurídicos'], correct: 0, explanation: 'O Gerenciador de Tarefas mostra processos, consumo de CPU, memória, disco, rede e permite encerrar tarefas travadas.' },
  { id: 'inf-q39', subjectId: 'informatica', topic: 'Windows', text: 'No Windows, o Explorador de Arquivos é utilizado para:', options: ['Navegar, organizar, copiar, mover e excluir arquivos e pastas', 'Criar slides com animações', 'Realizar cálculos financeiros diretamente', 'Instalar antivírus sem ação do usuário', 'Substituir o navegador de internet'], correct: 0, explanation: 'O Explorador de Arquivos permite gerenciar arquivos, pastas, unidades e dispositivos conectados.' },
  { id: 'inf-q40', subjectId: 'informatica', topic: 'Microsoft Word', text: 'No Microsoft Word, o recurso "Localizar e Substituir" serve para:', options: ['Encontrar palavras e trocar ocorrências por outro texto', 'Criar uma senha para o computador', 'Compactar arquivos grandes', 'Alterar a resolução do monitor', 'Bloquear o acesso à internet'], correct: 0, explanation: 'Localizar e Substituir permite encontrar termos no documento e substituí-los por outros de forma rápida.' },
  { id: 'inf-q41', subjectId: 'informatica', topic: 'Microsoft Word', text: 'No Word, a opção de alinhamento "justificado" faz com que o texto:', options: ['Fique alinhado apenas à esquerda', 'Fique centralizado na página', 'Fique alinhado às margens esquerda e direita', 'Fique sempre em negrito', 'Seja convertido em tabela'], correct: 2, explanation: 'O alinhamento justificado distribui o texto entre as margens esquerda e direita.' },
  { id: 'inf-q42', subjectId: 'informatica', topic: 'Microsoft Excel', text: 'No Excel, a fórmula =SOMA(B1:B5) realiza:', options: ['A soma dos valores de B1 até B5', 'A média dos valores de B1 até B5', 'A contagem de letras em B1', 'A formatação automática da coluna B', 'A exclusão das células B1 a B5'], correct: 0, explanation: 'A função SOMA adiciona os valores numéricos dentro do intervalo informado.' },
  { id: 'inf-q43', subjectId: 'informatica', topic: 'Microsoft Excel', text: 'No Excel, uma célula identificada como C3 indica:', options: ['Coluna C e linha 3', 'Linha C e coluna 3', 'Página C e parágrafo 3', 'Arquivo C e pasta 3', 'Planilha C e arquivo 3'], correct: 0, explanation: 'Em planilhas, a letra indica a coluna e o número indica a linha. C3 é coluna C, linha 3.' },
  { id: 'inf-q44', subjectId: 'informatica', topic: 'Ferramentas Office e Nuvem', text: 'No PowerPoint, o modo de apresentação é usado para:', options: ['Exibir os slides em tela cheia para uma apresentação', 'Compactar arquivos do computador', 'Apagar automaticamente documentos antigos', 'Criar senhas de rede', 'Atualizar o sistema operacional'], correct: 0, explanation: 'O modo de apresentação exibe os slides em sequência, normalmente em tela cheia.' },
  { id: 'inf-q45', subjectId: 'informatica', topic: 'Ferramentas Office e Nuvem', text: 'Serviços de armazenamento em nuvem, como Google Drive e OneDrive, permitem principalmente:', options: ['Salvar e acessar arquivos pela internet', 'Aumentar fisicamente a memória RAM', 'Substituir o processador do computador', 'Impedir qualquer vírus sem antivírus', 'Desligar automaticamente a rede elétrica'], correct: 0, explanation: 'Armazenamento em nuvem permite guardar arquivos em servidores online e acessá-los pela internet.' },
  { id: 'inf-q46', subjectId: 'informatica', topic: 'Internet e Navegadores', text: 'O cache do navegador serve principalmente para:', options: ['Armazenar temporariamente dados de páginas para acelerar acessos futuros', 'Apagar todos os arquivos do computador', 'Criar senhas fortes automaticamente', 'Bloquear qualquer conexão com a internet', 'Substituir o sistema operacional'], correct: 0, explanation: 'O cache guarda temporariamente elementos de páginas, como imagens e arquivos, para agilizar carregamentos futuros.' },
  { id: 'inf-q47', subjectId: 'informatica', topic: 'Internet e Navegadores', text: 'Um endereço iniciado por https indica, em regra, que:', options: ['A conexão usa protocolo com criptografia entre navegador e site', 'O site não precisa de senha', 'O computador está sem antivírus', 'A página está sempre livre de golpes', 'O arquivo foi baixado automaticamente'], correct: 0, explanation: 'HTTPS usa criptografia na comunicação entre navegador e servidor, embora isso não garanta sozinho que o site seja confiável.' },
  { id: 'inf-q48', subjectId: 'informatica', topic: 'E-mail e Comunicação Digital', text: 'Em e-mails, um anexo é:', options: ['Um arquivo enviado junto com a mensagem', 'O assunto da mensagem', 'O endereço do remetente', 'A senha do provedor', 'O histórico do navegador'], correct: 0, explanation: 'Anexo é um arquivo incluído no envio da mensagem, como documento, imagem ou PDF.' },
  { id: 'inf-q49', subjectId: 'informatica', topic: 'E-mail e Comunicação Digital', text: 'Uma prática segura ao receber e-mail suspeito é:', options: ['Não clicar em links ou anexos antes de verificar a origem', 'Informar senhas para confirmar a conta', 'Baixar todos os arquivos imediatamente', 'Responder com dados pessoais', 'Encaminhar para todos os contatos'], correct: 0, explanation: 'E-mails suspeitos podem conter phishing ou malware. O ideal é verificar remetente, links e anexos antes de qualquer ação.' },
  { id: 'inf-q50', subjectId: 'informatica', topic: 'Segurança da Informação', text: 'Phishing é uma técnica usada para:', options: ['Enganar usuários e obter dados sensíveis, como senhas e informações bancárias', 'Aumentar a velocidade do processador', 'Corrigir automaticamente erros de digitação', 'Criar planilhas financeiras', 'Melhorar a resolução de imagens'], correct: 0, explanation: 'Phishing é golpe que tenta enganar a vítima para roubar dados, senhas, códigos ou informações financeiras.' },
  { id: 'inf-q51', subjectId: 'informatica', topic: 'Segurança da Informação', text: 'A autenticação em dois fatores aumenta a segurança porque:', options: ['Exige uma segunda confirmação além da senha', 'Elimina a necessidade de qualquer senha', 'Permite compartilhar senhas com terceiros', 'Desativa todas as atualizações', 'Transforma arquivos em PDF'], correct: 0, explanation: 'A autenticação em dois fatores combina senha com outro fator, como código temporário, aplicativo autenticador ou biometria.' },
  { id: 'inf-q52', subjectId: 'informatica', topic: 'Segurança da Informação', text: 'Um backup é importante porque:', options: ['Permite recuperar dados em caso de perda, falha ou ataque', 'Impede que o computador ligue', 'Apaga arquivos duplicados sem confirmação', 'Substitui a necessidade de atualizar sistemas', 'Aumenta automaticamente a velocidade da internet'], correct: 0, explanation: 'Backup é cópia de segurança. Ele ajuda a recuperar arquivos em caso de perda, exclusão acidental, falha ou ataque.' },
  { id: 'inf-q53', subjectId: 'informatica', topic: 'Redes de Computadores', text: 'Um roteador doméstico é utilizado principalmente para:', options: ['Distribuir conexão de rede entre dispositivos', 'Criar textos no Word', 'Aumentar fisicamente o tamanho da tela', 'Formatar planilhas', 'Excluir vírus automaticamente'], correct: 0, explanation: 'O roteador encaminha dados e distribui conexão entre dispositivos, por cabo ou Wi-Fi.' },
  { id: 'inf-q54', subjectId: 'informatica', topic: 'Redes de Computadores', text: 'O endereço IP serve para:', options: ['Identificar um dispositivo em uma rede', 'Criar slides automaticamente', 'Salvar imagens apenas em PDF', 'Aumentar a memória do teclado', 'Substituir o monitor'], correct: 0, explanation: 'O endereço IP identifica dispositivos em uma rede, permitindo comunicação entre eles.' },
  { id: 'inf-q55', subjectId: 'informatica', topic: 'Google Workspace', text: 'No Google Drive, compartilhar um arquivo como "leitor" permite que a pessoa:', options: ['Visualize o arquivo sem poder editá-lo', 'Altere livremente o conteúdo', 'Exclua o arquivo original do proprietário', 'Transfira automaticamente a propriedade', 'Bloqueie todos os demais usuários'], correct: 0, explanation: 'A permissão de leitor permite visualizar o arquivo, mas não editar o conteúdo.' },
  { id: 'inf-q56', subjectId: 'informatica', topic: 'Google Workspace', text: 'No Google Docs, o histórico de versões permite:', options: ['Consultar e restaurar versões anteriores do documento', 'Aumentar a memória física do computador', 'Remover a internet do arquivo', 'Excluir automaticamente todos os comentários', 'Criar antivírus para o navegador'], correct: 0, explanation: 'O histórico de versões mostra alterações feitas no documento e pode permitir restaurar versões anteriores.' },
  { id: 'inf-q57', subjectId: 'informatica', topic: 'Microsoft Teams', text: 'No Microsoft Teams, canais são usados principalmente para:', options: ['Organizar conversas e arquivos por tema, equipe ou projeto', 'Formatar o disco rígido', 'Criar fórmulas matemáticas no Excel', 'Substituir o sistema operacional', 'Bloquear o teclado do computador'], correct: 0, explanation: 'Canais ajudam a organizar conversas, reuniões, arquivos e atividades por assunto ou equipe.' },
  { id: 'inf-q58', subjectId: 'informatica', topic: 'Microsoft Teams', text: 'Durante uma reunião no Microsoft Teams, o recurso de compartilhamento de tela permite:', options: ['Mostrar aos participantes a tela ou uma janela do computador', 'Apagar todos os arquivos da equipe', 'Aumentar a bateria do notebook', 'Criar senhas automaticamente', 'Desinstalar aplicativos remotamente'], correct: 0, explanation: 'O compartilhamento de tela permite mostrar a tela inteira ou uma janela específica aos participantes da reunião.' },
  { id: 'inf-q59', subjectId: 'informatica', topic: 'Sistemas Operacionais Móveis', text: 'Em smartphones, atualizar o sistema operacional é importante para:', options: ['Corrigir falhas, melhorar segurança e receber recursos', 'Apagar obrigatoriamente todos os contatos', 'Desativar permanentemente a internet', 'Impedir o uso de aplicativos', 'Remover a bateria do aparelho'], correct: 0, explanation: 'Atualizações podem corrigir vulnerabilidades, melhorar estabilidade, desempenho e adicionar recursos.' },
  { id: 'inf-q60', subjectId: 'informatica', topic: 'Sistemas Operacionais Móveis', text: 'Ao baixar aplicativos no celular, uma prática segura é:', options: ['Usar lojas oficiais e verificar permissões solicitadas', 'Instalar arquivos de qualquer link recebido', 'Ignorar avaliações e origem do aplicativo', 'Conceder todas as permissões sem analisar', 'Desativar toda proteção do aparelho'], correct: 0, explanation: 'Usar lojas oficiais, verificar permissões e evitar links desconhecidos reduz o risco de golpes e aplicativos maliciosos.' },

  { id: 'inf-q61', subjectId: 'informatica', topic: 'Hardware e Software', text: 'A CPU, também chamada de processador, é responsável principalmente por:', options: ['Executar instruções e processar dados', 'Armazenar arquivos permanentemente', 'Exibir imagens no monitor', 'Fornecer energia elétrica ao computador', 'Imprimir documentos'], correct: 0, explanation: 'A CPU executa instruções, realiza cálculos e coordena o processamento de dados do computador.' },
  { id: 'inf-q62', subjectId: 'informatica', topic: 'Hardware e Software', text: 'A diferença básica entre hardware e software é que:', options: ['Hardware é a parte física; software são programas e sistemas', 'Hardware é sempre gratuito; software é sempre pago', 'Hardware funciona apenas na internet', 'Software é a parte física do computador', 'Hardware é usado apenas em celulares'], correct: 0, explanation: 'Hardware são componentes físicos, como teclado, monitor e placa-mãe. Software são programas, aplicativos e sistemas operacionais.' },
  { id: 'inf-q63', subjectId: 'informatica', topic: 'Windows', text: 'No Windows, a Lixeira serve para:', options: ['Armazenar temporariamente arquivos excluídos antes da remoção definitiva', 'Aumentar a memória RAM', 'Criar cópias automáticas na nuvem', 'Proteger contra todos os vírus', 'Instalar atualizações do sistema'], correct: 0, explanation: 'A Lixeira mantém arquivos excluídos temporariamente, permitindo restauração antes da exclusão definitiva.' },
  { id: 'inf-q64', subjectId: 'informatica', topic: 'Windows', text: 'O atalho Alt + Tab no Windows é usado para:', options: ['Alternar entre janelas ou aplicativos abertos', 'Salvar automaticamente um documento', 'Abrir a calculadora', 'Excluir arquivos sem confirmação', 'Desligar o computador imediatamente'], correct: 0, explanation: 'Alt + Tab permite alternar rapidamente entre janelas e aplicativos abertos.' },
  { id: 'inf-q65', subjectId: 'informatica', topic: 'Microsoft Word', text: 'No Word, o recurso de revisão ortográfica e gramatical serve para:', options: ['Indicar possíveis erros de escrita e gramática', 'Criar senhas de acesso ao Windows', 'Compactar arquivos de imagem', 'Aumentar a velocidade da internet', 'Excluir páginas automaticamente'], correct: 0, explanation: 'A revisão ortográfica e gramatical ajuda a identificar possíveis erros no texto, embora ainda seja necessário revisar com atenção.' },
  { id: 'inf-q66', subjectId: 'informatica', topic: 'Microsoft Word', text: 'No Word, uma quebra de página é usada para:', options: ['Iniciar o conteúdo em uma nova página', 'Apagar todo o documento', 'Transformar texto em imagem', 'Alterar a senha do arquivo', 'Desinstalar fontes do sistema'], correct: 0, explanation: 'A quebra de página força o conteúdo seguinte a começar em uma nova página.' },
  { id: 'inf-q67', subjectId: 'informatica', topic: 'Microsoft Excel', text: 'No Excel, a fórmula =MÉDIA(A1:A4) calcula:', options: ['A média dos valores de A1 até A4', 'A soma dos textos da planilha', 'O maior valor da coluna A inteira', 'A quantidade de linhas vazias', 'A formatação das células A1 até A4'], correct: 0, explanation: 'A função MÉDIA calcula a média aritmética dos valores no intervalo indicado.' },
  { id: 'inf-q68', subjectId: 'informatica', topic: 'Microsoft Excel', text: 'No Excel, o símbolo $ em uma referência como $A$1 indica:', options: ['Referência absoluta', 'Erro de digitação', 'Texto sem função', 'Célula vazia', 'Comentário oculto'], correct: 0, explanation: 'O símbolo $ fixa coluna e linha, criando uma referência absoluta que não muda ao copiar a fórmula.' },
  { id: 'inf-q69', subjectId: 'informatica', topic: 'Ferramentas Office e Nuvem', text: 'No PowerPoint, uma transição é:', options: ['Efeito de passagem entre slides', 'Correção automática de ortografia', 'Fórmula de planilha', 'Senha de acesso ao arquivo', 'Tipo de backup externo'], correct: 0, explanation: 'Transição é o efeito aplicado na passagem de um slide para outro.' },
  { id: 'inf-q70', subjectId: 'informatica', topic: 'Ferramentas Office e Nuvem', text: 'O salvamento automático em nuvem pode ajudar porque:', options: ['Reduz risco de perda de alterações e permite acesso em diferentes dispositivos', 'Impede qualquer erro do usuário', 'Substitui a necessidade de internet para sincronizar', 'Desliga o computador após cada edição', 'Remove todos os arquivos locais'], correct: 0, explanation: 'O salvamento em nuvem pode preservar alterações e permitir acesso em diferentes dispositivos, desde que haja sincronização adequada.' },
  { id: 'inf-q71', subjectId: 'informatica', topic: 'Internet e Navegadores', text: 'Cookies de navegador são usados principalmente para:', options: ['Armazenar pequenas informações de navegação e preferências de sites', 'Aumentar fisicamente a memória do computador', 'Impedir qualquer golpe online', 'Substituir o antivírus', 'Apagar automaticamente o sistema operacional'], correct: 0, explanation: 'Cookies armazenam pequenas informações usadas por sites, como sessão, preferências e dados de navegação.' },
  { id: 'inf-q72', subjectId: 'informatica', topic: 'Internet e Navegadores', text: 'DNS é um serviço relacionado a:', options: ['Traduzir nomes de sites em endereços IP', 'Editar textos no navegador', 'Criar apresentações de slides', 'Formatar discos rígidos', 'Desativar conexões Wi-Fi'], correct: 0, explanation: 'O DNS traduz nomes de domínio, como endereços de sites, em endereços IP usados na comunicação em rede.' },
  { id: 'inf-q73', subjectId: 'informatica', topic: 'E-mail e Comunicação Digital', text: 'No campo CC de um e-mail, os destinatários:', options: ['Recebem cópia visível da mensagem', 'Recebem cópia oculta da mensagem', 'São bloqueados automaticamente', 'Não recebem anexos', 'Apagam o remetente da conversa'], correct: 0, explanation: 'CC significa cópia. Os destinatários em CC recebem a mensagem e ficam visíveis aos demais destinatários.' },
  { id: 'inf-q74', subjectId: 'informatica', topic: 'E-mail e Comunicação Digital', text: 'Uma assinatura de e-mail geralmente serve para:', options: ['Inserir informações de identificação ao final da mensagem', 'Criptografar todo o computador', 'Excluir mensagens antigas', 'Criar uma nova conta bancária', 'Bloquear todos os anexos'], correct: 0, explanation: 'A assinatura de e-mail costuma trazer nome, cargo, telefone, instituição ou outras informações de identificação.' },
  { id: 'inf-q75', subjectId: 'informatica', topic: 'Segurança da Informação', text: 'Ransomware é um tipo de ameaça que normalmente:', options: ['Sequestra ou criptografa dados e exige pagamento para liberação', 'Aumenta o brilho da tela', 'Organiza arquivos por ordem alfabética', 'Melhora a velocidade da internet', 'Cria backups seguros automaticamente'], correct: 0, explanation: 'Ransomware é malware que bloqueia ou criptografa arquivos e exige resgate, geralmente em dinheiro ou criptoativos.' },
  { id: 'inf-q76', subjectId: 'informatica', topic: 'Segurança da Informação', text: 'Uma senha forte deve, preferencialmente:', options: ['Ser longa, única e difícil de adivinhar', 'Ser o próprio nome do usuário', 'Ser igual em todos os serviços', 'Ter apenas a data de nascimento', 'Ser compartilhada com colegas'], correct: 0, explanation: 'Senhas fortes devem ser longas, únicas e difíceis de prever. O ideal é não reutilizar a mesma senha em vários serviços.' },
  { id: 'inf-q77', subjectId: 'informatica', topic: 'Redes de Computadores', text: 'Wi-Fi é uma tecnologia usada para:', options: ['Conectar dispositivos a redes sem fio', 'Imprimir documentos em papel carbono', 'Aumentar o tamanho físico do HD', 'Criar fórmulas no Word', 'Trocar o processador do computador'], correct: 0, explanation: 'Wi-Fi permite conexão sem fio entre dispositivos e redes locais, geralmente com acesso à internet.' },
  { id: 'inf-q78', subjectId: 'informatica', topic: 'Redes de Computadores', text: 'Bluetooth é usado principalmente para:', options: ['Comunicação sem fio de curto alcance entre dispositivos', 'Criar páginas da internet', 'Formatar planilhas automaticamente', 'Bloquear o sistema operacional', 'Substituir todos os cabos de energia'], correct: 0, explanation: 'Bluetooth permite comunicação sem fio de curto alcance, como entre celular, fone, teclado, mouse e outros dispositivos.' },
  { id: 'inf-q79', subjectId: 'informatica', topic: 'Google Workspace', text: 'No Google Forms, uma aplicação comum é:', options: ['Criar formulários, questionários e pesquisas online', 'Formatar o disco do computador', 'Editar exclusivamente vídeos profissionais', 'Substituir o antivírus', 'Instalar impressoras automaticamente'], correct: 0, explanation: 'Google Forms permite criar formulários, pesquisas, enquetes e questionários com coleta de respostas online.' },
  { id: 'inf-q80', subjectId: 'informatica', topic: 'Sistemas Operacionais Móveis', text: 'Permissões de aplicativos em celulares devem ser analisadas porque:', options: ['Podem dar acesso a dados sensíveis como localização, câmera, microfone e contatos', 'Sempre impedem o funcionamento do aparelho', 'São apenas decorativas', 'Não têm relação com privacidade', 'Apagam automaticamente o aplicativo'], correct: 0, explanation: 'Permissões podem envolver dados sensíveis. Por isso, é importante permitir apenas o que for necessário e confiável.' },

  { id: 'inf-q81', subjectId: 'informatica', topic: 'Hardware e Software', text: 'A fonte de alimentação de um computador tem como função principal:', options: ['Fornecer energia elétrica adequada aos componentes', 'Armazenar arquivos permanentemente', 'Executar fórmulas de planilha', 'Exibir páginas da internet', 'Criar cópias de segurança na nuvem'], correct: 0, explanation: 'A fonte de alimentação converte e distribui energia elétrica para os componentes internos do computador.' },
  { id: 'inf-q82', subjectId: 'informatica', topic: 'Hardware e Software', text: 'Um periférico de entrada é um dispositivo usado para:', options: ['Enviar dados ou comandos ao computador', 'Armazenar energia elétrica', 'Imprimir relatórios automaticamente', 'Aumentar a velocidade da internet', 'Proteger contra todos os vírus'], correct: 0, explanation: 'Periféricos de entrada permitem inserir dados ou comandos, como teclado, mouse, scanner e microfone.' },
  { id: 'inf-q83', subjectId: 'informatica', topic: 'Windows', text: 'No Windows, criar uma pasta serve principalmente para:', options: ['Organizar arquivos e subpastas', 'Aumentar a memória RAM', 'Formatar o computador', 'Instalar atualizações obrigatórias', 'Desativar o antivírus'], correct: 0, explanation: 'Pastas ajudam a organizar arquivos e outras pastas dentro do sistema de arquivos.' },
  { id: 'inf-q84', subjectId: 'informatica', topic: 'Windows', text: 'A extensão de arquivo .pdf normalmente indica:', options: ['Documento em formato portátil', 'Arquivo executável do Windows', 'Planilha do Excel exclusivamente', 'Imagem sem compressão obrigatória', 'Arquivo de áudio editável'], correct: 0, explanation: 'PDF é um formato portátil de documento, muito usado para preservar layout e facilitar compartilhamento.' },
  { id: 'inf-q85', subjectId: 'informatica', topic: 'Microsoft Word', text: 'No Word, o recurso de cabeçalho e rodapé é usado para:', options: ['Inserir informações repetidas no topo ou no final das páginas', 'Criar conexão Wi-Fi', 'Compactar o documento em ZIP', 'Apagar automaticamente imagens', 'Bloquear o teclado'], correct: 0, explanation: 'Cabeçalho e rodapé podem exibir numeração, título, data, logotipo e outras informações repetidas nas páginas.' },
  { id: 'inf-q86', subjectId: 'informatica', topic: 'Microsoft Word', text: 'No Word, o recurso de estilos é útil porque:', options: ['Padroniza títulos, subtítulos e formatação do documento', 'Aumenta fisicamente o tamanho do monitor', 'Cria senhas bancárias', 'Substitui o navegador de internet', 'Remove automaticamente vírus'], correct: 0, explanation: 'Estilos ajudam a manter padrão visual e facilitam a criação de sumário e organização do documento.' },
  { id: 'inf-q87', subjectId: 'informatica', topic: 'Microsoft Excel', text: 'No Excel, a função =MÁXIMO(A1:A10) retorna:', options: ['O maior valor do intervalo A1 até A10', 'O menor valor do intervalo', 'A soma dos valores', 'A média dos textos', 'A quantidade de células vazias'], correct: 0, explanation: 'A função MÁXIMO retorna o maior valor numérico dentro do intervalo indicado.' },
  { id: 'inf-q88', subjectId: 'informatica', topic: 'Microsoft Excel', text: 'No Excel, um gráfico é usado principalmente para:', options: ['Representar dados visualmente', 'Apagar linhas duplicadas sem confirmação', 'Criar contas de e-mail', 'Substituir o sistema operacional', 'Alterar a senha do computador'], correct: 0, explanation: 'Gráficos facilitam a visualização, comparação e interpretação de dados de uma planilha.' },
  { id: 'inf-q89', subjectId: 'informatica', topic: 'Internet e Navegadores', text: 'Uma URL é:', options: ['O endereço de um recurso na internet', 'Um tipo de memória RAM', 'Um programa antivírus', 'Uma fórmula de planilha', 'Um cabo de rede'], correct: 0, explanation: 'URL é o endereço usado para localizar páginas, arquivos e recursos na internet.' },
  { id: 'inf-q90', subjectId: 'informatica', topic: 'Internet e Navegadores', text: 'A navegação anônima ou privada geralmente:', options: ['Evita salvar histórico local daquela sessão no navegador', 'Torna o usuário invisível para todos os sites e provedores', 'Dispensa cuidados com golpes', 'Remove vírus automaticamente', 'Aumenta a velocidade do processador'], correct: 0, explanation: 'A navegação privada reduz rastros locais, como histórico daquela sessão, mas não torna o usuário completamente anônimo na internet.' },
  { id: 'inf-q91', subjectId: 'informatica', topic: 'E-mail e Comunicação Digital', text: 'No campo CCO de um e-mail, os destinatários:', options: ['Recebem cópia oculta da mensagem', 'Ficam visíveis para todos os destinatários', 'São impedidos de receber anexos', 'Viraram remetentes automaticamente', 'São bloqueados pelo provedor'], correct: 0, explanation: 'CCO significa cópia oculta. Os destinatários recebem a mensagem sem que seus endereços fiquem visíveis aos demais.' },
  { id: 'inf-q92', subjectId: 'informatica', topic: 'E-mail e Comunicação Digital', text: 'Um assunto claro em um e-mail profissional ajuda a:', options: ['Identificar rapidamente o tema da mensagem', 'Criptografar automaticamente todos os anexos', 'Impedir qualquer erro de português', 'Aumentar a memória do computador', 'Excluir mensagens antigas'], correct: 0, explanation: 'O assunto resume o tema da mensagem e facilita organização, busca e prioridade de leitura.' },
  { id: 'inf-q93', subjectId: 'informatica', topic: 'Segurança da Informação', text: 'Malware é um termo usado para:', options: ['Software malicioso criado para causar dano, roubar dados ou comprometer sistemas', 'Programa de edição de texto', 'Dispositivo físico de armazenamento', 'Tipo de planilha eletrônica', 'Cabo de conexão sem fio'], correct: 0, explanation: 'Malware é qualquer software malicioso, como vírus, trojans, spyware, ransomware e outros códigos prejudiciais.' },
  { id: 'inf-q94', subjectId: 'informatica', topic: 'Segurança da Informação', text: 'Uma atualização de segurança deve ser instalada porque pode:', options: ['Corrigir vulnerabilidades exploradas por ataques', 'Eliminar a necessidade de backup', 'Aumentar fisicamente a tela', 'Garantir que todo site seja confiável', 'Desativar todas as senhas'], correct: 0, explanation: 'Atualizações de segurança corrigem falhas que poderiam ser usadas por criminosos ou malwares.' },
  { id: 'inf-q95', subjectId: 'informatica', topic: 'Redes de Computadores', text: 'Uma rede local, ou LAN, normalmente conecta:', options: ['Dispositivos em uma área limitada, como casa, escola ou escritório', 'Apenas satélites espaciais', 'Somente computadores de países diferentes', 'Exclusivamente impressoras antigas', 'Apenas aparelhos sem internet'], correct: 0, explanation: 'LAN é uma rede local usada para conectar dispositivos em uma área relativamente pequena.' },
  { id: 'inf-q96', subjectId: 'informatica', topic: 'Redes de Computadores', text: 'Firewall é um recurso usado para:', options: ['Controlar e filtrar tráfego de rede conforme regras de segurança', 'Criar documentos no Word', 'Aumentar a memória física do computador', 'Formatar pendrives automaticamente', 'Trocar a bateria do celular'], correct: 0, explanation: 'Firewall ajuda a controlar conexões de entrada e saída, filtrando tráfego de acordo com regras de segurança.' },
  { id: 'inf-q97', subjectId: 'informatica', topic: 'Google Workspace', text: 'No Google Sheets, o compartilhamento colaborativo permite que:', options: ['Mais de uma pessoa trabalhe na planilha, conforme permissões concedidas', 'A planilha vire um antivírus', 'O computador seja formatado remotamente', 'Todos os arquivos sejam apagados', 'A internet seja desligada'], correct: 0, explanation: 'Ferramentas colaborativas permitem edição, comentários ou visualização por vários usuários, de acordo com permissões.' },
  { id: 'inf-q98', subjectId: 'informatica', topic: 'Microsoft Teams', text: 'No Microsoft Teams, o chat pode ser usado para:', options: ['Trocar mensagens, arquivos e informações com usuários ou grupos', 'Aumentar a memória RAM', 'Criar fórmulas automáticas no Word', 'Remover o sistema operacional', 'Bloquear todos os navegadores'], correct: 0, explanation: 'O chat do Teams permite comunicação por mensagens, envio de arquivos e interação individual ou em grupo.' },
  { id: 'inf-q99', subjectId: 'informatica', topic: 'Sistemas Operacionais Móveis', text: 'O bloqueio de tela por senha, PIN, padrão ou biometria ajuda a:', options: ['Proteger o acesso ao aparelho e aos dados pessoais', 'Aumentar a capacidade da bateria', 'Melhorar o sinal de telefonia automaticamente', 'Apagar todos os aplicativos', 'Dispensar atualizações de segurança'], correct: 0, explanation: 'O bloqueio de tela dificulta o acesso não autorizado ao aparelho e aos dados armazenados nele.' },
  { id: 'inf-q100', subjectId: 'informatica', topic: 'Sistemas Operacionais Móveis', text: 'Em celulares, manter cópia de segurança dos dados é útil para:', options: ['Recuperar informações em caso de perda, troca, roubo ou defeito do aparelho', 'Impedir que o aparelho use internet', 'Remover a necessidade de senha', 'Desativar todos os aplicativos', 'Aumentar fisicamente o armazenamento interno'], correct: 0, explanation: 'Backup em celular ajuda a recuperar contatos, fotos, arquivos e configurações em caso de perda, roubo, troca ou falha do aparelho.' },



  // ====== ADMINISTRAÇÃO PÚBLICA (100 questões) ======
  { id: 'ap-q01', subjectId: 'administracao', topic: 'Princípios da Administração Pública', text: 'O princípio que determina que a administração pública deve buscar os melhores resultados com os recursos disponíveis é o princípio da:', options: ['Legalidade', 'Publicidade', 'Eficiência', 'Moralidade', 'Impessoalidade'], correct: 2, explanation: 'O princípio da eficiência exige que a administração pública atue com presteza, qualidade e rendimento, buscando os melhores resultados.' },
  { id: 'ap-q02', subjectId: 'administracao', topic: 'Poderes Administrativos', text: 'O poder que permite à administração limitar o exercício de direitos individuais em prol do interesse público é o poder de:', options: ['Hierarquia', 'Disciplina', 'Polícia', 'Regulamentar', 'Vinculado'], correct: 2, explanation: 'O poder de polícia permite ao Estado limitar ou disciplinar direitos e atividades individuais em benefício do interesse público (ex: licenças, fiscalizações, multas).' },
  { id: 'ap-q03', subjectId: 'administracao', topic: 'Organização Administrativa', text: 'As autarquias fazem parte da administração:', options: ['Direta', 'Indireta', 'Privada', 'Mista', 'Popular'], correct: 1, explanation: 'As autarquias são entidades da administração indireta, com personalidade jurídica própria, criadas por lei para desempenhar atividades típicas do Estado.' },
  { id: 'ap-q04', subjectId: 'administracao', topic: 'Licitações', text: 'A modalidade de licitação utilizada para bens e serviços comuns é o:', options: ['Concorrência', 'Pregão', 'Concurso', 'Leilão', 'Tomada de preços'], correct: 1, explanation: 'O pregão é a modalidade destinada à aquisição de bens e serviços comuns, cujo critério de julgamento é o menor preço.' },
  { id: 'ap-q05', subjectId: 'administracao', topic: 'Servidores Públicos', text: 'A regra geral para ingresso em cargo público é:', options: ['Indicação', 'Concurso público de provas ou provas e títulos', 'Eleição', 'Nomeação livre', 'Aprovação em curso'], correct: 1, explanation: 'O Art. 37, II da CF/88 estabelece que a investidura em cargo público depende de aprovação em concurso público de provas ou de provas e títulos.' },
  { id: 'ap-q06', subjectId: 'administracao', topic: 'Controle da Administração Pública', text: 'O controle externo da administração pública é exercido pelo:', options: ['Poder Executivo', 'Poder Legislativo, com auxílio do Tribunal de Contas', 'Poder Judiciário, exclusivamente', 'Ministério Público, exclusivamente', 'Conselho de Contabilidade'], correct: 1, explanation: 'O controle externo é exercido pelo Poder Legislativo com auxílio do Tribunal de Contas (Art. 70, CF/88).' },
  { id: 'ap-q07', subjectId: 'administracao', topic: 'Princípios da Administração Pública', text: 'O princípio segundo o qual a administração pública deve agir sem favoritismo ou perseguição é o da:', options: ['Publicidade', 'Legalidade', 'Impessoalidade', 'Eficiência', 'Supremacia'], correct: 2, explanation: 'A impessoalidade proíbe a administração de promover ou prejudicar pessoas em razão de preferências pessoais. Atos devem visar ao interesse público.' },
  { id: 'ap-q08', subjectId: 'administracao', topic: 'Atos Administrativos', text: 'Um ato administrativo que não deixa margem de escolha ao administrador, que deve agir estritamente conforme a lei, é:', options: ['Discricionário', 'Vinculado', 'Complexo', 'Bilateral', 'Condicionado'], correct: 1, explanation: 'O ato vinculado é aquele em que a lei não deixa margem de escolha ao administrador, que deve praticá-lo exatamente como a lei determina.' },
  { id: 'ap-q09', subjectId: 'administracao', topic: 'Improbidade Administrativa', text: 'Os atos de improbidade administrativa que causam prejuízo ao erário são tipificados na:', options: ['Lei 8.112/1990', 'Lei 8.429/1992', 'Lei 14.133/2021', 'LC 101/2000', 'Lei 9.784/1999'], correct: 1, explanation: 'A Lei 8.429/1992 (Lei de Improbidade Administrativa) tipifica os atos de improbidade: enriquecimento ilícito, prejuízo ao erário e ofensa aos princípios.' },
  { id: 'ap-q10', subjectId: 'administracao', topic: 'Responsabilidade Fiscal', text: 'A Lei de Responsabilidade Fiscal (LC 101/2000) tem como objetivo principal:', options: ['Extinguir a necessidade de orçamento público', 'Estabelecer normas de responsabilidade na gestão fiscal', 'Substituir a Constituição Federal em matéria tributária', 'Autorizar gastos públicos sem planejamento', 'Regular exclusivamente concursos públicos'], correct: 1, explanation: 'A LRF estabelece normas de finanças públicas voltadas para a responsabilidade na gestão fiscal, exigindo planejamento, controle, transparência e equilíbrio das contas públicas.' },
  { id: 'ap-q11', subjectId: 'administracao', topic: 'Princípios da Administração Pública', text: 'O princípio da legalidade na Administração Pública significa que o agente público deve:', options: ['Agir apenas conforme a lei autoriza', 'Agir conforme sua preferência pessoal', 'Ignorar normas internas', 'Criar punições sem previsão legal', 'Atuar sem controle institucional'], correct: 0, explanation: 'Pelo princípio da legalidade, a Administração Pública só pode agir quando houver autorização ou previsão legal.' },
  { id: 'ap-q12', subjectId: 'administracao', topic: 'Princípios da Administração Pública', text: 'O princípio da publicidade busca garantir:', options: ['Sigilo absoluto de todos os atos públicos', 'Transparência e acesso às informações públicas', 'Promoção pessoal de autoridades', 'Ausência de controle social', 'Fim da motivação dos atos administrativos'], correct: 1, explanation: 'A publicidade exige transparência dos atos administrativos, permitindo controle social, ressalvadas hipóteses legais de sigilo.' },
  { id: 'ap-q13', subjectId: 'administracao', topic: 'Princípios da Administração Pública', text: 'O princípio da moralidade administrativa exige que o agente público atue com:', options: ['Ética, boa-fé e honestidade', 'Interesse exclusivamente particular', 'Favoritismo político', 'Desvio de finalidade', 'Omissão deliberada'], correct: 0, explanation: 'A moralidade administrativa exige conduta ética, honesta e compatível com o interesse público.' },
  { id: 'ap-q14', subjectId: 'administracao', topic: 'Princípios da Administração Pública', text: 'A eficiência na Administração Pública está relacionada:', options: ['À busca de bons resultados com qualidade e racionalidade', 'Ao aumento de burocracia sem necessidade', 'À demora proposital no atendimento', 'À ausência de metas', 'À repetição de atos inúteis'], correct: 0, explanation: 'O princípio da eficiência exige atuação com qualidade, rapidez, racionalidade e busca por melhores resultados.' },
  { id: 'ap-q15', subjectId: 'administracao', topic: 'Atos Administrativos', text: 'São requisitos clássicos do ato administrativo:', options: ['Competência, finalidade, forma, motivo e objeto', 'Preço, lucro, mercado, cliente e risco', 'Cargo, salário, férias, licença e promoção', 'Voto, partido, coligação, campanha e urna', 'Contrato, propaganda, estoque, venda e entrega'], correct: 0, explanation: 'Os requisitos do ato administrativo são competência, finalidade, forma, motivo e objeto.' },
  { id: 'ap-q16', subjectId: 'administracao', topic: 'Poderes Administrativos', text: 'O poder hierárquico permite à Administração Pública:', options: ['Organizar, coordenar e controlar órgãos e agentes subordinados', 'Criar crimes sem lei', 'Julgar ações penais', 'Emitir moeda', 'Substituir o Poder Legislativo'], correct: 0, explanation: 'O poder hierárquico permite distribuir funções, fiscalizar, revisar atos e dar ordens dentro da estrutura administrativa.' },
  { id: 'ap-q17', subjectId: 'administracao', topic: 'Poderes Administrativos', text: 'O poder disciplinar autoriza a Administração a:', options: ['Apurar infrações e aplicar sanções a servidores e pessoas sujeitas à disciplina administrativa', 'Alterar a Constituição sem processo legislativo', 'Cobrar tributos sem lei', 'Julgar crimes dolosos contra a vida', 'Nomear qualquer pessoa sem requisitos legais'], correct: 0, explanation: 'O poder disciplinar permite apurar infrações e aplicar penalidades no âmbito das relações administrativas.' },
  { id: 'ap-q18', subjectId: 'administracao', topic: 'Organização Administrativa', text: 'Fazem parte da Administração Pública indireta:', options: ['Autarquias, fundações públicas, empresas públicas e sociedades de economia mista', 'Somente ministérios e secretarias', 'Apenas órgãos sem personalidade jurídica', 'Exclusivamente partidos políticos', 'Somente empresas privadas sem participação estatal'], correct: 0, explanation: 'A Administração indireta é composta por entidades com personalidade jurídica própria, como autarquias, fundações públicas, empresas públicas e sociedades de economia mista.' },
  { id: 'ap-q19', subjectId: 'administracao', topic: 'Licitações', text: 'A licitação tem como uma de suas finalidades:', options: ['Selecionar a proposta mais vantajosa para a Administração', 'Impedir qualquer competição', 'Permitir contratação sem critérios', 'Substituir todos os concursos públicos', 'Criar cargo público automaticamente'], correct: 0, explanation: 'A licitação busca selecionar a proposta mais vantajosa e garantir isonomia entre os participantes, conforme a legislação aplicável.' },
  { id: 'ap-q20', subjectId: 'administracao', topic: 'Serviço Público', text: 'Serviço público é atividade prestada pelo Estado ou por seus delegados com o objetivo de:', options: ['Atender necessidades coletivas', 'Atender apenas interesses privados de agentes públicos', 'Eliminar direitos dos usuários', 'Substituir a Constituição Federal', 'Impedir o controle da sociedade'], correct: 0, explanation: 'Serviços públicos existem para atender necessidades coletivas, diretamente pelo Estado ou por delegação a particulares.' },


  { id: 'ap-q21', subjectId: 'administracao', topic: 'Princípios da Administração Pública', text: 'Na Administração Pública, o princípio da legalidade significa que o agente público:', options: ['Pode fazer tudo que não for proibido', 'Deve agir conforme a lei autoriza', 'Pode escolher livremente sem previsão legal', 'Só obedece ordens verbais', 'Não precisa justificar seus atos'], correct: 1, explanation: 'Para a Administração Pública, legalidade significa agir conforme autorização legal. O particular tem liberdade maior; o agente público atua dentro da lei.' },
  { id: 'ap-q22', subjectId: 'administracao', topic: 'Poderes Administrativos', text: 'O poder de polícia administrativa permite ao Estado:', options: ['Criar crimes sem lei', 'Limitar direitos individuais em favor do interesse coletivo', 'Julgar ações penais', 'Substituir o Poder Legislativo', 'Nomear servidores sem concurso'], correct: 1, explanation: 'O poder de polícia permite limitar ou condicionar direitos e atividades individuais para proteger o interesse público.' },
  { id: 'ap-q23', subjectId: 'administracao', topic: 'Atos Administrativos', text: 'Quando um ato administrativo é ilegal, a medida adequada é sua:', options: ['Revogação por conveniência', 'Anulação', 'Promoção', 'Homologação obrigatória', 'Convalidação automática em todos os casos'], correct: 1, explanation: 'Ato ilegal deve ser anulado. Revogação ocorre por conveniência e oportunidade em ato válido.' },
  { id: 'ap-q24', subjectId: 'administracao', topic: 'Licitações', text: 'Na contratação direta, quando a competição é inviável, ocorre hipótese de:', options: ['Pregão', 'Concorrência', 'Inexigibilidade de licitação', 'Leilão', 'Concurso público'], correct: 2, explanation: 'Inexigibilidade ocorre quando não há viabilidade de competição. Dispensa ocorre quando a competição seria possível, mas a lei autoriza não licitar.' },
  { id: 'ap-q25', subjectId: 'administracao', topic: 'Controle da Administração Pública', text: 'O controle popular da Administração Pública está relacionado:', options: ['À participação do cidadão na fiscalização dos atos públicos', 'À ausência de transparência', 'Ao sigilo absoluto das contas públicas', 'À impossibilidade de denúncia', 'À extinção do controle externo'], correct: 0, explanation: 'O controle popular permite que cidadãos acompanhem, fiscalizem, denunciem irregularidades e participem do controle social da Administração Pública.' },


  { id: 'ap-q26', subjectId: 'administracao', topic: 'Organização Administrativa', text: 'A desconcentração administrativa ocorre quando:', options: ['Uma atividade é transferida para pessoa jurídica diferente', 'Há criação de órgãos dentro da mesma pessoa jurídica', 'O Estado deixa de prestar serviço público', 'Uma empresa privada assume função legislativa', 'O Poder Judiciário cria uma autarquia'], correct: 1, explanation: 'Desconcentração é distribuição interna de competências dentro da mesma pessoa jurídica, por meio de órgãos.' },
  { id: 'ap-q27', subjectId: 'administracao', topic: 'Responsabilidade Fiscal', text: 'A responsabilidade fiscal está relacionada principalmente:', options: ['Ao gasto público sem planejamento', 'À gestão equilibrada, planejada e transparente das contas públicas', 'À ausência de controle sobre despesas', 'À eliminação do orçamento público', 'À contratação direta sem justificativa'], correct: 1, explanation: 'Responsabilidade fiscal envolve planejamento, controle, transparência e equilíbrio na gestão das contas públicas.' },
  { id: 'ap-q28', subjectId: 'administracao', topic: 'Improbidade Administrativa', text: 'A improbidade administrativa está associada a condutas graves contra a Administração Pública, como:', options: ['Pontualidade no serviço', 'Enriquecimento ilícito, dano ao erário ou violação relevante de princípios', 'Cumprimento do edital', 'Atendimento eficiente ao cidadão', 'Publicação transparente de atos oficiais'], correct: 1, explanation: 'A improbidade envolve condutas graves, como enriquecimento ilícito, prejuízo aos cofres públicos e violação relevante de princípios administrativos.' },
  { id: 'ap-q29', subjectId: 'administracao', topic: 'Servidores Públicos', text: 'A estabilidade do servidor público ocupante de cargo efetivo significa que:', options: ['Ele nunca poderá perder o cargo', 'Ele pode descumprir deveres sem punição', 'Ele possui garantia legal, mas pode perder o cargo nas hipóteses previstas em lei', 'Ele está dispensado de avaliação e responsabilidade', 'Ele pode acumular qualquer cargo público livremente'], correct: 2, explanation: 'Estabilidade não é impunidade. O servidor estável pode perder o cargo nas hipóteses legais, como processo administrativo com ampla defesa.' },
  { id: 'ap-q30', subjectId: 'administracao', topic: 'Políticas Públicas e Cidadania', text: 'Políticas públicas podem ser entendidas como:', options: ['Ações organizadas do Estado para enfrentar problemas coletivos', 'Decisões privadas sem relação com a sociedade', 'Atos secretos sem controle social', 'Regras exclusivas de empresas particulares', 'Medidas sem planejamento ou avaliação'], correct: 0, explanation: 'Políticas públicas são ações, programas e decisões organizadas pelo Estado para enfrentar problemas coletivos, como saúde, educação, segurança e mobilidade.' },


  { id: 'ap-q31', subjectId: 'administracao', topic: 'Constituição do Estado de SP', text: 'A Constituição do Estado de São Paulo deve ser compreendida como:', options: ['Norma estadual que organiza o Estado, respeitando a Constituição Federal', 'Lei privada sem relação com o poder público', 'Documento superior à Constituição Federal', 'Regulamento exclusivo de empresas particulares', 'Manual sem valor jurídico'], correct: 0, explanation: 'A Constituição Estadual organiza o Estado de São Paulo, mas deve respeitar a Constituição Federal, que é a norma superior do país.' },
  { id: 'ap-q32', subjectId: 'administracao', topic: 'Constituição do Estado de SP', text: 'No âmbito da segurança pública estadual paulista, a Polícia Militar está mais ligada à:', options: ['Polícia ostensiva e preservação da ordem pública', 'Julgamento de ações penais', 'Emissão de moeda', 'Fiscalização exclusiva do comércio exterior', 'Criação de leis federais'], correct: 0, explanation: 'A Polícia Militar atua principalmente na polícia ostensiva e na preservação da ordem pública, dentro do sistema de segurança pública.' },
  { id: 'ap-q33', subjectId: 'administracao', topic: 'Constituição do Estado de SP', text: 'A Polícia Civil, no sistema de segurança pública, tem como função típica:', options: ['Polícia judiciária e apuração de infrações penais, ressalvadas as militares', 'Policiamento ostensivo fardado nas ruas', 'Julgamento definitivo dos acusados', 'Elaboração do orçamento da União', 'Controle da política monetária'], correct: 0, explanation: 'A Polícia Civil exerce funções de polícia judiciária e apuração de infrações penais, exceto as de natureza militar.' },
  { id: 'ap-q34', subjectId: 'administracao', topic: 'Constituição do Estado de SP', text: 'Em relação à segurança pública, o Corpo de Bombeiros está associado principalmente a atividades como:', options: ['Prevenção e combate a incêndios, busca, salvamento e defesa civil', 'Julgamento de crimes eleitorais', 'Emissão de passaportes', 'Fiscalização de tributos federais', 'Criação de partidos políticos'], correct: 0, explanation: 'O Corpo de Bombeiros atua em atividades de prevenção e combate a incêndios, busca, salvamento, socorro e defesa civil.' },
  { id: 'ap-q35', subjectId: 'administracao', topic: 'Constituição do Estado de SP', text: 'Uma questão sobre Constituição do Estado de São Paulo deve ser resolvida considerando que:', options: ['A norma estadual não pode contrariar a Constituição Federal', 'A Constituição Estadual revoga automaticamente todas as leis federais', 'O Estado pode ignorar direitos fundamentais', 'A Administração Pública atua sem princípios', 'A segurança pública não possui previsão constitucional'], correct: 0, explanation: 'A Constituição Estadual deve respeitar a Constituição Federal. Em prova, cuidado com alternativas que colocam a norma estadual acima da Constituição Federal.' },


  { id: 'ap-q36', subjectId: 'administracao', topic: 'Princípios da Administração Pública', text: 'O princípio da legalidade, na Administração Pública, significa que o agente público deve:', options: ['Fazer tudo o que não for proibido', 'Agir conforme a lei e dentro dos limites legais', 'Atuar apenas segundo sua vontade pessoal', 'Ignorar normas quando houver urgência', 'Priorizar interesses privados'], correct: 1, explanation: 'Na Administração Pública, legalidade significa que o agente só pode agir conforme a lei autoriza ou determina.' },
  { id: 'ap-q37', subjectId: 'administracao', topic: 'Princípios da Administração Pública', text: 'O princípio da impessoalidade exige que a atuação administrativa:', options: ['Busque favorecer amigos e conhecidos', 'Seja voltada ao interesse público, sem promoção pessoal ou perseguição', 'Dependa sempre da preferência pessoal do servidor', 'Ignore critérios objetivos', 'Use o cargo para autopromoção'], correct: 1, explanation: 'A impessoalidade impede favorecimentos, perseguições e promoção pessoal com recursos ou atos públicos.' },
  { id: 'ap-q38', subjectId: 'administracao', topic: 'Princípios da Administração Pública', text: 'O princípio da publicidade determina que os atos administrativos devem, em regra:', options: ['Ser secretos em qualquer situação', 'Ser divulgados para permitir controle e transparência', 'Ser conhecidos apenas pelo chefe imediato', 'Dispensar motivação e registro', 'Ficar ocultos até o fim do mandato'], correct: 1, explanation: 'A publicidade dá transparência aos atos administrativos e permite controle social, salvo hipóteses legais de sigilo.' },
  { id: 'ap-q39', subjectId: 'administracao', topic: 'Atos Administrativos', text: 'Ato administrativo é, em regra, uma manifestação da Administração Pública que:', options: ['Produz efeitos jurídicos no exercício da função administrativa', 'Tem apenas valor moral sem efeito jurídico', 'Só pode ser praticada por empresas privadas', 'Não precisa respeitar a lei', 'Sempre depende de votação popular'], correct: 0, explanation: 'O ato administrativo é manifestação unilateral da Administração, no exercício da função administrativa, capaz de produzir efeitos jurídicos.' },
  { id: 'ap-q40', subjectId: 'administracao', topic: 'Atos Administrativos', text: 'A competência, como requisito do ato administrativo, refere-se:', options: ['Ao conteúdo econômico do ato', 'À atribuição legal de quem pratica o ato', 'Ao local onde o servidor mora', 'À opinião pessoal do agente', 'Ao tempo de serviço do particular'], correct: 1, explanation: 'Competência é o poder legal atribuído ao agente ou órgão para praticar determinado ato.' },
  { id: 'ap-q41', subjectId: 'administracao', topic: 'Atos Administrativos', text: 'A anulação de um ato administrativo ocorre quando o ato é:', options: ['Legal, mas inconveniente', 'Ilegal', 'Sempre perfeito e acabado', 'Privado e sem efeito público', 'Apenas impopular'], correct: 1, explanation: 'A anulação ocorre por ilegalidade. Já a revogação ocorre por conveniência e oportunidade, quando o ato é válido.' },
  { id: 'ap-q42', subjectId: 'administracao', topic: 'Poderes Administrativos', text: 'O poder hierárquico permite à Administração:', options: ['Organizar, distribuir funções, fiscalizar e rever atos de subordinados', 'Criar crimes sem lei', 'Aplicar pena a qualquer cidadão sem processo', 'Desrespeitar a Constituição', 'Eliminar todos os controles internos'], correct: 0, explanation: 'O poder hierárquico estrutura a Administração, permitindo subordinação, fiscalização, delegação, avocação e revisão de atos.' },
  { id: 'ap-q43', subjectId: 'administracao', topic: 'Poderes Administrativos', text: 'O poder disciplinar permite à Administração:', options: ['Punir infrações funcionais de servidores e pessoas sujeitas à disciplina administrativa', 'Criar impostos sem lei', 'Julgar crimes comuns como regra', 'Desfazer decisões judiciais', 'Agir sem contraditório em qualquer caso'], correct: 0, explanation: 'O poder disciplinar permite apurar e punir infrações administrativas, respeitando devido processo, contraditório e ampla defesa.' },
  { id: 'ap-q44', subjectId: 'administracao', topic: 'Poderes Administrativos', text: 'O poder de polícia administrativa permite ao Estado:', options: ['Condicionar ou limitar direitos em benefício do interesse público', 'Extinguir direitos fundamentais sem lei', 'Agir sempre sem proporcionalidade', 'Impedir toda atividade econômica lícita', 'Substituir o Poder Legislativo'], correct: 0, explanation: 'O poder de polícia limita ou condiciona atividades e direitos individuais para proteger o interesse público, dentro da lei.' },
  { id: 'ap-q45', subjectId: 'administracao', topic: 'Organização Administrativa', text: 'A Administração Direta é composta por:', options: ['Órgãos integrantes das pessoas políticas, como União, estados, Distrito Federal e municípios', 'Apenas empresas privadas contratadas', 'Somente organizações internacionais', 'Exclusivamente autarquias e fundações', 'Apenas concessionárias de serviço público'], correct: 0, explanation: 'Administração Direta corresponde aos órgãos que integram as pessoas políticas: União, estados, Distrito Federal e municípios.' },
  { id: 'ap-q46', subjectId: 'administracao', topic: 'Organização Administrativa', text: 'A Administração Indireta inclui entidades como:', options: ['Autarquias, fundações públicas, empresas públicas e sociedades de economia mista', 'Apenas secretarias municipais', 'Somente ministérios', 'Exclusivamente órgãos sem personalidade jurídica', 'Apenas tribunais eleitorais'], correct: 0, explanation: 'A Administração Indireta é formada por entidades com personalidade jurídica própria, como autarquias, fundações públicas, empresas públicas e sociedades de economia mista.' },
  { id: 'ap-q47', subjectId: 'administracao', topic: 'Organização Administrativa', text: 'Uma autarquia é uma entidade da Administração Indireta que possui:', options: ['Personalidade jurídica de direito público', 'Personalidade exclusivamente privada sem vínculo estatal', 'Ausência total de autonomia', 'Finalidade apenas comercial sem interesse público', 'Poder de legislar acima da Constituição'], correct: 0, explanation: 'Autarquias são pessoas jurídicas de direito público, criadas por lei, para desempenhar atividades típicas da Administração.' },
  { id: 'ap-q48', subjectId: 'administracao', topic: 'Licitações', text: 'A licitação tem como finalidade principal:', options: ['Escolher proposta vantajosa e garantir igualdade entre os interessados', 'Favorecer sempre uma empresa previamente escolhida', 'Dispensar qualquer controle dos gastos públicos', 'Impedir competição entre fornecedores', 'Contratar sem critérios objetivos'], correct: 0, explanation: 'A licitação busca selecionar proposta vantajosa para a Administração e assegurar isonomia entre os participantes.' },
  { id: 'ap-q49', subjectId: 'administracao', topic: 'Licitações', text: 'A contratação direta na Administração Pública:', options: ['Pode ocorrer nas hipóteses legais de dispensa ou inexigibilidade', 'É sempre livre, sem fundamento legal', 'Substitui toda licitação obrigatória', 'Dispensa motivação e processo administrativo', 'É proibida em qualquer hipótese'], correct: 0, explanation: 'Contratação direta só pode ocorrer quando a lei permite, como nos casos de dispensa ou inexigibilidade, sempre com justificativa e processo.' },
  { id: 'ap-q50', subjectId: 'administracao', topic: 'Licitações', text: 'Na licitação, o princípio da vinculação ao edital significa que:', options: ['Administração e participantes devem seguir as regras previstas no edital', 'O edital pode ser ignorado após a abertura das propostas', 'Cada candidato escolhe quais regras cumprir', 'A Administração pode mudar critérios sem publicidade', 'O edital não tem importância jurídica'], correct: 0, explanation: 'O edital vincula a Administração e os licitantes, funcionando como a regra do procedimento licitatório.' },
  { id: 'ap-q51', subjectId: 'administracao', topic: 'Servidores Públicos', text: 'Servidor público estatutário é aquele que:', options: ['Ocupa cargo público regido por estatuto próprio', 'Trabalha sempre sem vínculo com o Estado', 'Atua apenas em empresa privada', 'Não se submete a deveres funcionais', 'É contratado exclusivamente por contrato comercial'], correct: 0, explanation: 'Servidor estatutário ocupa cargo público e tem relação jurídica regida por estatuto, não pela CLT como regra.' },
  { id: 'ap-q52', subjectId: 'administracao', topic: 'Servidores Públicos', text: 'A estabilidade do servidor público efetivo, quando preenchidos os requisitos legais, busca:', options: ['Proteger o servidor contra perseguições e garantir continuidade do serviço público', 'Impedir qualquer responsabilização', 'Permitir faltas sem controle', 'Eliminar avaliação de desempenho', 'Autorizar descumprimento da lei'], correct: 0, explanation: 'A estabilidade protege a função pública contra pressões indevidas, mas não impede punição ou perda do cargo nas hipóteses legais.' },
  { id: 'ap-q53', subjectId: 'administracao', topic: 'Servidores Públicos', text: 'A responsabilidade administrativa do servidor pode ocorrer quando ele:', options: ['Pratica infração funcional no exercício do cargo', 'Apenas discorda de uma opinião política', 'Usa corretamente os recursos públicos', 'Cumpre todos os deveres legais', 'Age de acordo com a hierarquia e a lei'], correct: 0, explanation: 'A responsabilidade administrativa decorre de infração funcional, apurada em procedimento adequado.' },
  { id: 'ap-q54', subjectId: 'administracao', topic: 'Controle da Administração Pública', text: 'O controle da Administração Pública serve para:', options: ['Verificar legalidade, legitimidade, eficiência e correção dos atos administrativos', 'Impedir toda transparência', 'Afastar a fiscalização social', 'Permitir atos sem prestação de contas', 'Eliminar responsabilidade dos agentes públicos'], correct: 0, explanation: 'O controle busca assegurar que a Administração atue conforme a lei, o interesse público, a eficiência e a moralidade.' },
  { id: 'ap-q55', subjectId: 'administracao', topic: 'Controle da Administração Pública', text: 'O controle interno é aquele realizado:', options: ['Dentro do próprio órgão ou Poder', 'Apenas por organismos internacionais', 'Somente por empresas privadas', 'Exclusivamente pelo eleitor no dia da votação', 'Apenas pelo contratado particular'], correct: 0, explanation: 'Controle interno é exercido no âmbito da própria Administração, por seus órgãos e sistemas de controle.' },
  { id: 'ap-q56', subjectId: 'administracao', topic: 'Improbidade Administrativa', text: 'A improbidade administrativa está relacionada a condutas que:', options: ['Violam a honestidade, legalidade e deveres de boa administração', 'Representam qualquer erro sem relevância', 'São sempre atos privados sem relação pública', 'Dispensam apuração legal', 'São permitidas quando trazem vantagem pessoal ao agente'], correct: 0, explanation: 'Improbidade envolve condutas desonestas ou gravemente contrárias aos deveres públicos, conforme a legislação aplicável.' },
  { id: 'ap-q57', subjectId: 'administracao', topic: 'Responsabilidade Fiscal', text: 'A responsabilidade fiscal busca:', options: ['Equilibrar receitas e despesas e controlar o uso dos recursos públicos', 'Incentivar gasto público sem planejamento', 'Eliminar transparência orçamentária', 'Permitir endividamento ilimitado', 'Proibir controle das contas públicas'], correct: 0, explanation: 'A responsabilidade fiscal busca planejamento, equilíbrio, transparência e controle na gestão dos recursos públicos.' },
  { id: 'ap-q58', subjectId: 'administracao', topic: 'Serviço Público', text: 'Serviço público é atividade prestada pelo Estado ou por quem lhe faça as vezes, voltada:', options: ['Ao atendimento de necessidades coletivas', 'Exclusivamente ao lucro pessoal do agente', 'A interesses privados sem controle', 'À eliminação de direitos sociais', 'A atividades proibidas pela Constituição'], correct: 0, explanation: 'Serviço público atende necessidades da coletividade e pode ser prestado diretamente pelo Estado ou por particulares delegados.' },
  { id: 'ap-q59', subjectId: 'administracao', topic: 'Políticas Públicas e Cidadania', text: 'Políticas públicas são:', options: ['Ações e programas do Estado voltados à solução de problemas coletivos', 'Decisões pessoais sem interesse social', 'Atividades exclusivamente privadas sem participação estatal', 'Regras sem qualquer aplicação prática', 'Ações proibidas em uma democracia'], correct: 0, explanation: 'Políticas públicas são programas, ações e decisões governamentais voltadas a demandas sociais, como saúde, educação, segurança e transporte.' },
  { id: 'ap-q60', subjectId: 'administracao', topic: 'Políticas Públicas e Cidadania', text: 'A participação social na Administração Pública contribui para:', options: ['Controle, transparência e aproximação entre Estado e sociedade', 'Eliminar toda fiscalização', 'Impedir a cidadania', 'Concentrar decisões sem diálogo', 'Substituir a Constituição por opiniões pessoais'], correct: 0, explanation: 'A participação social fortalece cidadania, transparência, controle social e qualidade das decisões públicas.' },


  { id: 'ap-q61', subjectId: 'administracao', topic: 'Princípios da Administração Pública', text: 'O princípio da moralidade administrativa exige que o agente público atue:', options: ['Com ética, boa-fé e honestidade institucional', 'Apenas buscando vantagem pessoal', 'Sem qualquer compromisso com a finalidade pública', 'Ignorando padrões de conduta', 'Com sigilo absoluto em todos os atos'], correct: 0, explanation: 'A moralidade administrativa exige conduta ética, honesta, leal e compatível com o interesse público.' },
  { id: 'ap-q62', subjectId: 'administracao', topic: 'Princípios da Administração Pública', text: 'O princípio da eficiência está ligado principalmente à ideia de:', options: ['Melhor resultado possível com qualidade e bom uso dos recursos públicos', 'Gasto sem planejamento', 'Atuação lenta como regra', 'Falta de avaliação dos serviços', 'Prioridade ao interesse privado'], correct: 0, explanation: 'Eficiência significa buscar bons resultados, qualidade, produtividade e racionalidade no uso dos recursos públicos.' },
  { id: 'ap-q63', subjectId: 'administracao', topic: 'Princípios da Administração Pública', text: 'Quando um agente público usa a máquina administrativa para promoção pessoal, há violação mais direta ao princípio da:', options: ['Impessoalidade', 'Continuidade', 'Autotutela', 'Especialidade', 'Motivação privada'], correct: 0, explanation: 'A impessoalidade impede que atos, obras e serviços públicos sejam usados para promoção pessoal de autoridades ou servidores.' },
  { id: 'ap-q64', subjectId: 'administracao', topic: 'Atos Administrativos', text: 'A motivação do ato administrativo consiste em:', options: ['Indicar os fundamentos de fato e de direito que justificam o ato', 'Escolher qualquer justificativa depois do resultado', 'Dispensar explicações em todos os casos', 'Substituir a competência legal', 'Permitir ato sem finalidade pública'], correct: 0, explanation: 'Motivar é apresentar as razões fáticas e jurídicas que sustentam a decisão administrativa.' },
  { id: 'ap-q65', subjectId: 'administracao', topic: 'Atos Administrativos', text: 'A revogação de um ato administrativo válido ocorre por motivo de:', options: ['Conveniência e oportunidade', 'Ilegalidade obrigatória', 'Inexistência do ato', 'Crime comum sempre', 'Ausência de competência judicial'], correct: 0, explanation: 'A revogação retira ato válido por razões de mérito administrativo: conveniência e oportunidade.' },
  { id: 'ap-q66', subjectId: 'administracao', topic: 'Atos Administrativos', text: 'A finalidade do ato administrativo deve estar sempre ligada:', options: ['Ao interesse público previsto em lei', 'Ao interesse pessoal do agente', 'À vontade do particular favorecido', 'À propaganda individual', 'Ao lucro privado do servidor'], correct: 0, explanation: 'Todo ato administrativo deve buscar finalidade pública. Desvio de finalidade torna o ato inválido.' },
  { id: 'ap-q67', subjectId: 'administracao', topic: 'Poderes Administrativos', text: 'O poder regulamentar permite ao chefe do Executivo:', options: ['Expedir atos normativos para fiel execução da lei', 'Criar leis penais sem Legislativo', 'Julgar definitivamente qualquer cidadão', 'Ignorar normas constitucionais', 'Extinguir direitos fundamentais'], correct: 0, explanation: 'O poder regulamentar permite editar regulamentos e decretos para detalhar a execução da lei, sem inovar além dela.' },
  { id: 'ap-q68', subjectId: 'administracao', topic: 'Poderes Administrativos', text: 'O abuso de poder pode ocorrer quando o agente público:', options: ['Excede sua competência ou atua com finalidade diversa da prevista em lei', 'Age exatamente nos limites legais', 'Cumpre ordem legítima', 'Motiva corretamente o ato', 'Respeita a proporcionalidade'], correct: 0, explanation: 'Abuso de poder pode ocorrer por excesso de poder ou desvio de finalidade.' },
  { id: 'ap-q69', subjectId: 'administracao', topic: 'Poderes Administrativos', text: 'No exercício do poder de polícia, a Administração deve observar:', options: ['Legalidade, necessidade, proporcionalidade e interesse público', 'Arbitrariedade sem controle', 'Apenas vontade pessoal do agente', 'Ausência de motivação em todos os casos', 'Punição sem previsão legal'], correct: 0, explanation: 'O poder de polícia não é ilimitado; deve respeitar a lei, a razoabilidade, a proporcionalidade e os direitos fundamentais.' },
  { id: 'ap-q70', subjectId: 'administracao', topic: 'Organização Administrativa', text: 'A descentralização administrativa ocorre quando:', options: ['O Estado transfere a execução de atividade a outra pessoa jurídica', 'Um chefe distribui tarefas dentro do mesmo órgão', 'Um servidor muda de sala', 'Um órgão elimina sua hierarquia', 'A Administração deixa de existir'], correct: 0, explanation: 'Na descentralização, a atividade é atribuída a outra pessoa jurídica, como entidade da Administração Indireta ou particular delegado.' },
  { id: 'ap-q71', subjectId: 'administracao', topic: 'Organização Administrativa', text: 'A desconcentração administrativa ocorre quando:', options: ['Há distribuição interna de competências dentro da mesma pessoa jurídica', 'Surge uma nova pessoa jurídica obrigatoriamente', 'O Estado entrega toda sua função a empresa estrangeira', 'A Constituição deixa de valer', 'O servidor perde todo vínculo com a Administração'], correct: 0, explanation: 'Desconcentração é distribuição interna de competências entre órgãos da mesma pessoa jurídica.' },
  { id: 'ap-q72', subjectId: 'administracao', topic: 'Organização Administrativa', text: 'Empresas públicas e sociedades de economia mista integram:', options: ['A Administração Indireta', 'O Poder Judiciário como órgãos judicantes', 'A Administração Direta como ministérios', 'A sociedade civil sem vínculo estatal', 'A administração pessoal do servidor'], correct: 0, explanation: 'Empresas públicas e sociedades de economia mista são entidades da Administração Indireta, com personalidade jurídica de direito privado.' },
  { id: 'ap-q73', subjectId: 'administracao', topic: 'Licitações', text: 'O julgamento objetivo na licitação significa que:', options: ['As propostas devem ser avaliadas conforme critérios previamente definidos no edital', 'O agente pode escolher pela amizade', 'O edital pode ser ignorado', 'A proposta vencedora é sempre a primeira entregue', 'Não há necessidade de critérios'], correct: 0, explanation: 'O julgamento objetivo impede subjetivismo e exige aplicação dos critérios definidos no edital.' },
  { id: 'ap-q74', subjectId: 'administracao', topic: 'Licitações', text: 'A competitividade em licitações busca:', options: ['Ampliar a disputa entre interessados aptos, evitando restrições indevidas', 'Impedir a participação de fornecedores', 'Garantir contratação sem comparação', 'Escolher sempre o fornecedor mais próximo', 'Favorecer pessoa previamente definida'], correct: 0, explanation: 'A competitividade favorece a busca da melhor proposta e evita restrições injustificadas à participação.' },
  { id: 'ap-q75', subjectId: 'administracao', topic: 'Licitações', text: 'A fase preparatória da contratação pública é importante porque:', options: ['Planeja a contratação, define necessidade, critérios e estimativas', 'Substitui toda fiscalização posterior', 'Dispensa justificativas', 'Elimina o interesse público', 'Permite contratação sem processo'], correct: 0, explanation: 'A fase preparatória organiza a necessidade pública, estudos, estimativas, critérios e planejamento da contratação.' },
  { id: 'ap-q76', subjectId: 'administracao', topic: 'Servidores Públicos', text: 'O dever de assiduidade do servidor público está relacionado:', options: ['À presença regular e cumprimento da jornada de trabalho', 'Ao direito de faltar sem justificativa', 'À dispensa de controle de frequência', 'Ao uso privado do cargo', 'À ausência de responsabilidade funcional'], correct: 0, explanation: 'Assiduidade significa comparecimento regular ao serviço e cumprimento dos deveres de presença e jornada.' },
  { id: 'ap-q77', subjectId: 'administracao', topic: 'Servidores Públicos', text: 'O dever de urbanidade exige que o servidor:', options: ['Trate o público e os colegas com respeito e cordialidade', 'Atenda com grosseria quando estiver ocupado', 'Ignore usuários do serviço público', 'Favoreça apenas conhecidos', 'Recuse atendimento sem justificativa'], correct: 0, explanation: 'Urbanidade envolve respeito, cortesia, educação e tratamento adequado ao público e aos demais servidores.' },
  { id: 'ap-q78', subjectId: 'administracao', topic: 'Controle da Administração Pública', text: 'O controle externo da Administração Pública pode ser exercido, entre outros, pelo:', options: ['Poder Legislativo com auxílio dos Tribunais de Contas', 'Somente pelo próprio servidor fiscalizado', 'Apenas por empresas contratadas', 'Exclusivamente por redes sociais', 'Apenas por particulares sem previsão legal'], correct: 0, explanation: 'O controle externo é exercido pelo Legislativo com auxílio dos Tribunais de Contas, conforme o modelo constitucional.' },
  { id: 'ap-q79', subjectId: 'administracao', topic: 'Controle da Administração Pública', text: 'A autotutela administrativa permite que a Administração:', options: ['Anule seus atos ilegais e revogue atos válidos por conveniência e oportunidade', 'Ignore seus próprios erros', 'Revogue decisões judiciais definitivas', 'Crie leis sem competência', 'Elimine direitos sem processo'], correct: 0, explanation: 'Pela autotutela, a Administração pode rever seus próprios atos, anulando os ilegais e revogando os inconvenientes ou inoportunos.' },
  { id: 'ap-q80', subjectId: 'administracao', topic: 'Constituição do Estado de SP', text: 'No estudo da Constituição do Estado de São Paulo, é correto afirmar que ela deve:', options: ['Respeitar a Constituição Federal e organizar o Estado dentro dos limites constitucionais', 'Ficar acima da Constituição Federal', 'Eliminar direitos fundamentais previstos nacionalmente', 'Autorizar atos administrativos sem princípios', 'Dispensar o controle da Administração'], correct: 0, explanation: 'A Constituição Estadual organiza o estado, mas deve respeitar a Constituição Federal e seus princípios.' },


  { id: 'ap-q81', subjectId: 'administracao', topic: 'Princípios da Administração Pública', text: 'A supremacia do interesse público indica que:', options: ['O interesse coletivo pode prevalecer sobre interesses individuais, nos limites da lei', 'O agente público pode agir sem lei', 'O interesse privado sempre prevalece sobre o público', 'A Administração pode ignorar direitos fundamentais', 'O servidor decide conforme sua preferência pessoal'], correct: 0, explanation: 'A supremacia do interesse público orienta a atuação administrativa, mas não autoriza arbitrariedade nem desrespeito à lei e aos direitos fundamentais.' },
  { id: 'ap-q82', subjectId: 'administracao', topic: 'Princípios da Administração Pública', text: 'A indisponibilidade do interesse público significa que:', options: ['O agente público não é dono do interesse público e deve administrá-lo conforme a lei', 'O servidor pode renunciar livremente a direitos da coletividade', 'A Administração atua como proprietária privada dos bens públicos', 'O interesse público pode ser usado para vantagem pessoal', 'A lei não limita a Administração'], correct: 0, explanation: 'O interesse público pertence à coletividade; por isso, o agente deve geri-lo dentro da legalidade, sem dispor dele como se fosse particular.' },
  { id: 'ap-q83', subjectId: 'administracao', topic: 'Atos Administrativos', text: 'A presunção de legitimidade dos atos administrativos significa que eles:', options: ['São considerados válidos até prova em contrário', 'Nunca podem ser questionados', 'São sempre ilegais', 'Dispensam controle judicial em qualquer caso', 'Não produzem efeitos jurídicos'], correct: 0, explanation: 'Os atos administrativos presumem-se legítimos e verdadeiros até prova em contrário, mas podem ser questionados e controlados.' },
  { id: 'ap-q84', subjectId: 'administracao', topic: 'Atos Administrativos', text: 'A imperatividade do ato administrativo permite que a Administração:', options: ['Imponha obrigações ao particular, quando a lei autorizar', 'Atue sempre sem base legal', 'Ignore contraditório em qualquer processo', 'Crie crimes por ato administrativo', 'Elimine qualquer controle externo'], correct: 0, explanation: 'Imperatividade é a possibilidade de impor obrigações unilateralmente, desde que haja fundamento legal.' },
  { id: 'ap-q85', subjectId: 'administracao', topic: 'Atos Administrativos', text: 'A autoexecutoriedade, quando presente, permite que a Administração:', options: ['Execute diretamente certas decisões administrativas, nos limites legais', 'Desobedeça sempre ao Poder Judiciário', 'Dispense toda motivação', 'Crie tributos sem lei', 'Aplique pena criminal definitiva'], correct: 0, explanation: 'A autoexecutoriedade permite execução direta de alguns atos administrativos, quando prevista em lei ou em situações urgentes, respeitados os limites legais.' },
  { id: 'ap-q86', subjectId: 'administracao', topic: 'Poderes Administrativos', text: 'O excesso de poder ocorre quando o agente público:', options: ['Vai além da competência que a lei lhe atribui', 'Age exatamente dentro de sua competência', 'Cumpre a finalidade pública prevista', 'Motiva corretamente o ato', 'Observa proporcionalidade e legalidade'], correct: 0, explanation: 'Excesso de poder é forma de abuso em que o agente extrapola os limites de sua competência legal.' },
  { id: 'ap-q87', subjectId: 'administracao', topic: 'Poderes Administrativos', text: 'O desvio de finalidade ocorre quando o agente público:', options: ['Pratica ato visando finalidade diversa da prevista em lei', 'Age para atender ao interesse público correto', 'Cumpre exatamente o edital', 'Aplica a lei com finalidade legítima', 'Atua dentro dos limites do cargo e da finalidade pública'], correct: 0, explanation: 'Desvio de finalidade ocorre quando o ato é praticado com objetivo diferente do interesse público ou da finalidade legal.' },
  { id: 'ap-q88', subjectId: 'administracao', topic: 'Organização Administrativa', text: 'Órgão público é uma unidade de atuação que:', options: ['Integra uma pessoa jurídica e não possui personalidade jurídica própria', 'Sempre possui personalidade jurídica privada', 'É necessariamente uma empresa pública', 'Atua fora da Administração', 'Não pode receber competências'], correct: 0, explanation: 'Órgãos públicos são centros de competência sem personalidade jurídica própria, integrantes de pessoas jurídicas públicas.' },
  { id: 'ap-q89', subjectId: 'administracao', topic: 'Organização Administrativa', text: 'A delegação administrativa consiste em:', options: ['Transferir temporariamente o exercício de determinada competência, quando permitido', 'Criar nova Constituição estadual', 'Eliminar a responsabilidade do delegante em qualquer caso', 'Transformar órgão em pessoa jurídica', 'Extinguir o controle administrativo'], correct: 0, explanation: 'Delegação é a transferência do exercício de competência para outro agente ou órgão, quando juridicamente possível.' },
  { id: 'ap-q90', subjectId: 'administracao', topic: 'Licitações', text: 'O planejamento da contratação pública ajuda a evitar:', options: ['Desperdício, contratações inadequadas e falta de justificativa', 'Transparência e controle', 'Competição entre fornecedores', 'Definição clara do objeto', 'Pesquisa de preços'], correct: 0, explanation: 'Planejamento adequado reduz desperdícios, melhora a definição do objeto e fortalece a eficiência e o controle da contratação.' },
  { id: 'ap-q91', subjectId: 'administracao', topic: 'Licitações', text: 'Na contratação pública, a pesquisa de preços é importante para:', options: ['Estimar valor compatível com o mercado', 'Escolher fornecedor por amizade', 'Dispensar justificativa', 'Ignorar economicidade', 'Impedir controle dos gastos'], correct: 0, explanation: 'A pesquisa de preços auxilia a estimativa do valor da contratação e evita sobrepreço ou gasto inadequado.' },
  { id: 'ap-q92', subjectId: 'administracao', topic: 'Licitações', text: 'O edital de licitação deve apresentar regras claras porque:', options: ['Orienta os interessados e vincula o procedimento', 'Serve apenas como propaganda sem efeito', 'Pode ser descumprido livremente', 'Dispensa critérios de julgamento', 'Impede a transparência'], correct: 0, explanation: 'O edital define regras, objeto, critérios e condições, vinculando Administração e participantes.' },
  { id: 'ap-q93', subjectId: 'administracao', topic: 'Servidores Públicos', text: 'A investidura em cargo público efetivo depende, em regra:', options: ['De aprovação prévia em concurso público', 'De escolha pessoal sem critérios', 'De indicação informal de particular', 'De contrato verbal sem registro', 'De pagamento ao órgão público'], correct: 0, explanation: 'A Constituição estabelece que a investidura em cargo público efetivo depende de aprovação em concurso público, ressalvadas exceções constitucionais.' },
  { id: 'ap-q94', subjectId: 'administracao', topic: 'Servidores Públicos', text: 'O estágio probatório é um período destinado a avaliar:', options: ['A aptidão e capacidade do servidor para o cargo', 'A preferência política do servidor', 'A vida privada sem relação funcional', 'A popularidade nas redes sociais', 'A possibilidade de ignorar deveres'], correct: 0, explanation: 'O estágio probatório avalia requisitos funcionais como assiduidade, disciplina, capacidade, responsabilidade e desempenho.' },
  { id: 'ap-q95', subjectId: 'administracao', topic: 'Controle da Administração Pública', text: 'A prestação de contas é importante porque:', options: ['Permite verificar o uso regular dos recursos públicos', 'Impede a transparência', 'Elimina o controle social', 'Substitui a legalidade', 'Autoriza gasto sem registro'], correct: 0, explanation: 'Prestação de contas permite fiscalização, transparência e responsabilização sobre a aplicação dos recursos públicos.' },
  { id: 'ap-q96', subjectId: 'administracao', topic: 'Controle da Administração Pública', text: 'O controle social da Administração Pública é exercido:', options: ['Pela sociedade, por meio de participação, fiscalização e acompanhamento das ações públicas', 'Apenas por empresas estrangeiras', 'Somente por servidores aposentados', 'Exclusivamente por quem ocupa cargo de chefia', 'Sem qualquer relação com cidadania'], correct: 0, explanation: 'Controle social é a participação da sociedade na fiscalização e acompanhamento da Administração Pública.' },
  { id: 'ap-q97', subjectId: 'administracao', topic: 'Improbidade Administrativa', text: 'O enriquecimento ilícito de agente público, relacionado ao exercício da função, é exemplo de:', options: ['Conduta de improbidade administrativa', 'Exercício regular e obrigatório do cargo', 'Atividade privada sem interesse público', 'Ato sempre permitido', 'Princípio da eficiência'], correct: 0, explanation: 'O enriquecimento ilícito ligado à função pública é uma das condutas associadas à improbidade administrativa.' },
  { id: 'ap-q98', subjectId: 'administracao', topic: 'Responsabilidade Fiscal', text: 'A transparência na gestão fiscal envolve:', options: ['Divulgação de informações sobre planejamento, orçamento, execução e contas públicas', 'Ocultação de gastos públicos', 'Endividamento sem controle', 'Proibição de fiscalização', 'Ausência de relatórios e demonstrativos'], correct: 0, explanation: 'A responsabilidade fiscal envolve planejamento, controle, equilíbrio e transparência na gestão das contas públicas.' },
  { id: 'ap-q99', subjectId: 'administracao', topic: 'Serviço Público', text: 'O princípio da continuidade do serviço público indica que:', options: ['Serviços essenciais devem ser prestados de forma regular, sem interrupções indevidas', 'Todo serviço público deve parar sem justificativa', 'A Administração pode abandonar o usuário', 'A prestação do serviço é sempre facultativa', 'Não existe dever de regularidade'], correct: 0, explanation: 'A continuidade busca garantir prestação regular dos serviços públicos, especialmente os essenciais.' },
  { id: 'ap-q100', subjectId: 'administracao', topic: 'Constituição do Estado de SP', text: 'Em prova, ao comparar Constituição Estadual e Constituição Federal, deve-se lembrar que:', options: ['A Constituição Estadual deve respeitar os princípios e limites da Constituição Federal', 'A Constituição Estadual sempre prevalece sobre a Federal', 'O estado pode eliminar direitos fundamentais nacionais', 'A Constituição Federal não se aplica aos estados', 'A Administração estadual atua sem legalidade'], correct: 0, explanation: 'A Constituição Estadual organiza o estado, mas deve estar em harmonia com a Constituição Federal e não pode contrariá-la.' },

];
